// 성취기준 엔티티 온톨로지 데이터 (문장 단위, 분해 없음)
// 859개 엔티티 / 5262개 계열성 링크

export const ENTITIES = [{"id": 0, "code": "[2국01-01]", "text": "중요한 내용이나 일이 일어난 순서를 고려하며 듣고 말한다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "듣기·말하기", "verb": "행위", "textLen": 33, "hasExp": false}, {"id": 1, "code": "[2국01-02]", "text": "바르고 고운 말로 서로의 감정을 나누며 듣고 말한다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "듣기·말하기", "verb": "행위", "textLen": 30, "hasExp": true, "explanation": "이 성취기준은 대화를 나눌 때 자신의 감정을 적절하게 표현함으로써 타인과의 관계를 형성하고 유지하며 발전시키는 능력을 기르기 위해 설정하였다 . 기쁨, 슬픔, 사랑, 미움 등 다양한 감정과 관련된 표현 알기 , 감정을 표현하는 과정에서 바르고 고운 말을 사용하기 , 상대의 감정을 이해하고 수용하기 등을 학습한다 ."}, {"id": 2, "code": "[2국01-03]", "text": "상대의 말을 집중하여 듣고 말차례를 지키며 대화한다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "듣기·말하기", "verb": "행위", "textLen": 30, "hasExp": true, "explanation": "이 성취기준은 구어 의사소통의 상호 교섭성을 인식하는 출발점으로 , 대화 상 황에서 상대의 말에 집중하여 그 내용을 이해하고 순서를 교대하며 구어 의사소통에 참여하는 기본 능력을 기르기 위해 설정하였다 . 상대의 말을 집중하여 듣기 , 다음 말할 사람을 선택하여 다음 말할 사람을 선택하여 부르거나 , 고갯짓 , 시선, 억양 등의 말차례 교환 신호 를 활용하여 다음 사람이 말차례를 알아차릴 수 있도록 하기 , 말차례 교환 신호를 확인하여 자신의 말차례 지키기 등을 학습한다 ."}, {"id": 3, "code": "[2국01-04]", "text": "자신의 경험이나 생각을 바른 자세로 발표한다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "듣기·말하기", "verb": "행위", "textLen": 26, "hasExp": true, "explanation": "이 성취기준은 교실에서 자신의 경험이나 생각을 바른 자세로 표현하고 학습 에 참여할 수 있는 기본 능력을 기르기 위해 설정하였다 . 자신의 경험이나 생각을 동료 학 습자들 앞에서 간단히 말하기 , 자신의 경험이나 배경지식을 바탕으로 말하기 , 수업 시간에 바른 자세로 서서 말하기 , 듣는 사람을 바라보며 말하기 , 적절한 크기의 소리로 말하기 등 을 학습한다 ."}, {"id": 4, "code": "[2국01-05]", "text": "듣기와 말하기에 관심과 흥미를 가진다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "듣기·말하기", "verb": "태도", "textLen": 22, "hasExp": true, "explanation": "이 성취기준은 삶에서 듣기 ⋅말하기의 즐거움을 느끼고 듣기 ⋅말하기의 중요 성을 인식하도록 하기 위해 설정하였다 . 듣기⋅말하기가 다양한 생각과 감정을 나누며 의 사소통하기 위한 기본적인 도구임을 인식하기 , 듣기⋅말하기의 역할과 중요성을 직접 경험 해 보기 , 다양한 놀이를 통해 듣기 ⋅말하기에 흥미 가지기 등을 학습한다 . 국어과 교육과정 14"}, {"id": 5, "code": "[2국02-01]", "text": "글자, 단어, 문장, 짧은 글을 정확하게 소리 내어 읽는다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "읽기", "verb": "기타", "textLen": 34, "hasExp": false}, {"id": 6, "code": "[2국02-02]", "text": "의미가 잘 드러나도록 문장과 짧은 글을 알맞게 띄어 읽는다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "읽기", "verb": "기타", "textLen": 34, "hasExp": true, "explanation": "이 성취기준은 글을 의미 단위에 알맞게 띄어 읽으며 글의 의미를 파악하는 능력을 기르기 위해 설정하였다 . 글을 읽으면서 의미 단위를 인식하고 이에 맞게 띄어 읽는 것은 글의 의미를 정확하게 파악하고 읽기 유창성을 높이는 데 중요한 요소이다 . 글의 의미를 이해하기 위해 의미 단위에 따른 어구나 어절 단위 등으로 띄어 읽기 , 주어부와 서술어부 등을 단위로 하여 띄어 읽기 , 문장 부호에 따라 문장 단위를 인식하면서 띄어 읽기 , 쉬는 지점, 쉼의 길이에 유의하며 띄어 읽기 등을 학습한다 . 공통 교육과정 15"}, {"id": 7, "code": "[2국02-03]", "text": "글을 읽고 중심 내용을 확인한다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "읽기", "verb": "행위", "textLen": 19, "hasExp": false}, {"id": 8, "code": "[2국02-04]", "text": "인물의 마음이나 생각을 짐작하고 이를 자신과 비교하며 글을 읽는다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "읽기", "verb": "기타", "textLen": 38, "hasExp": true, "explanation": "이 성취기준은 글에 등장하는 인물의 마음과 생각을 짐작하는 능력과 타인에 대한 공감 능력을 기르기 위해 설정하였다 . 인물의 마음이나 생각을 짐작하는 것은 글의 내 용에 대한 이해와 더불어 실제 주변 인물에 대한 이해를 높이는 데 도움이 된다 . 인물의 처 지나 상황을 파악하기 , 자신의 경험에 비추어 인물의 마음이나 생각 짐작하기 , 감정을 드러 내는 다양한 어휘를 활용하여 인물의 마음이나 생각을 표현하기 , 인물의 마음이나 생각과 관련된 자신의 경험이나 생각을 떠올리며 비교하기 등을 학습한다 ."}, {"id": 9, "code": "[2국02-05]", "text": "읽기에 흥미를 가지고 즐겨 읽는 태도를 지닌다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "읽기", "verb": "기타", "textLen": 27, "hasExp": true, "explanation": ") 과 연계할 수 있다 . 그리고 일상의 경험을 글 과 그림으로 표현해 보는 활동은 쓰기 영역에서 자신의 생각이나 느낌을 문장으로 표현해 보는 활동 ("}, {"id": 10, "code": "[2국03-01]", "text": "글자와 단어를 바르게 쓴다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "쓰기", "verb": "기타", "textLen": 16, "hasExp": false}, {"id": 11, "code": "[2국03-02]", "text": "쓰기에 흥미를 가지며 자신의 생각이나 느낌을 문장으로 표현한다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "쓰기", "verb": "행위", "textLen": 36, "hasExp": true, "explanation": "), 문학 영역에서 작품 속 내용을 시 , 노래, 이야기 , 그림 등으로 표 현해 보는 활동 ("}, {"id": 12, "code": "[2국03-03]", "text": "주변 소재에 대해 소개하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "쓰기", "verb": "기타", "textLen": 22, "hasExp": false}, {"id": 13, "code": "[2국03-04]", "text": "겪은 일을 표현하는 글을 자유롭게 쓰고 , 쓴 글을 함께 읽고 생각이나 느낌을 나눈다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "쓰기", "verb": "기타", "textLen": 49, "hasExp": true, "explanation": "이 성취기준은 자신이 겪은 일을 내용이나 형식에 제한 없이 자유롭게 표현하 고, 그 과정과 결과를 독자와 공유하는 데에 필요한 능력과 태도를 기르기 위해 설정하였"}, {"id": 14, "code": "[2국04-01]", "text": "한글 자모의 이름과 소릿값을 알고 정확하게 발음하고 쓴다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "문법", "verb": "기타", "textLen": 33, "hasExp": false}, {"id": 15, "code": "[2국04-02]", "text": "소리와 표기가 다를 수 있음을 알고 단어를 바르게 읽고 쓴다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "문법", "verb": "기타", "textLen": 35, "hasExp": false}, {"id": 16, "code": "[2국04-03]", "text": "문장과 문장 부호를 알맞게 쓰고 한글에 호기심을 가진다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "문법", "verb": "태도", "textLen": 32, "hasExp": true, "explanation": "이 성취기준은 문장으로 의사소통하기 위해 필요한 기초적인 문식성을 기르고 , 글 자, 단어, 문장을 주의 깊게 관찰하고 탐구하는 자세를 기르기 위해 설정하였다 . 자신의 생각을 문장으로 쓰는 것은 의사소통 능력의 핵심으로서 , 특히 한글 학습 초기에는 음성 언어와는 다른 문자 언어의 특성을 이해하는 것이 중요하다 . 문장 부호의 이름과 쓰임 , 평서문 ⋅의문문 ⋅감탄 문 등 다양한 종류의 문장 쓰기와 그에 따른 문장 부호 사용하기를 다루되 , 문장 부호 사용의 필요성을 깨닫고 문장을 비롯하여 문장을 이루는 글자 , 단어에도 호기심을 갖도록 한다 ."}, {"id": 17, "code": "[2국05-01]", "text": "말놀이 , 낭송 등을 통해 말의 재미와 즐거움을 느낀다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "문학", "verb": "기타", "textLen": 32, "hasExp": true, "explanation": "이 성취기준은 흥미로운 말놀이와 분위기를 살린 낭송을 통해 언어 활동의 재 미와 즐거움을 느끼며 언어적 감수성을 기르게 하기 위해 설정하였다 . 일상에서 쉽게 접할 수 있는 작품은 물론 일상적 대화 등을 통해 언어의 놀이적 성격을 인지하도록 하고 , 의성 어와 의태어 , 규칙적으로 반복되는 소리 , 언어유희 , 재치 있는 문답 , 수수께끼 , 끝말잇기 등 에서 말놀이의 재미와 가치를 느끼게 한다 . 또한 작품의 느낌과 분위기를 살려 낭송해 보면서 목소리 크기나 말의 속도 , 어조 등을 달리함에 따라 다양한 느낌을 전달할 수 있음을 알고 문학을 즐겨 향유하도록 한다 ."}, {"id": 18, "code": "[2국05-02]", "text": "작품을 듣거나 읽으면서 느끼거나 생각한 점을 말한다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "문학", "verb": "행위", "textLen": 30, "hasExp": true, "explanation": "이 성취기준은 학습자들이 작품에 대해 느끼거나 생각한 점을 다른 이들과 나 누는 과정에서 문학에 대해 더욱 흥미를 느끼고 , 주체적으로 작품을 수용하는 능력을 기르 게 하기 위해 설정하였다 . 학습자의 발달과 정서적 측면을 고려하여 시 , 노래, 이야기 등 다양한 갈래의 작품을 제시하고 , 학습자가 이들 작품을 대상으로 자신의 생각이나 느낌을 표현할 수 있도록 한다 . 이 과정에서 학습자로 하여금 작품에 대한 다른 학습자들의 말을 경청하게 하고 , 사람마다 작품을 다르게 받아들일 수 있다는 점을 이해하게 한다 ."}, {"id": 19, "code": "[2국05-03]", "text": ") 과 연계할 수 있다 . [초등학교 3∼4학년] (1) 듣기⋅말하기", "subject": "국어", "gradeGroup": "초1~2", "area": "문학", "verb": "능력", "textLen": 38, "hasExp": true, "explanation": "작품 속 인물의 모습 , 행동, 마음을 상상하여 시 , 노래, 이야기 , 그림 등으로 표현한다 ."}, {"id": 20, "code": "[2국05-04]", "text": "시나 노래 , 이야기에 흥미를 가진다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "문학", "verb": "태도", "textLen": 22, "hasExp": false}, {"id": 21, "code": "[2국06-01]", "text": "일상의 다양한 매체와 매체 자료에 흥미와 관심을 가진다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "매체", "verb": "태도", "textLen": 32, "hasExp": true, "explanation": "이 성취기준은 매체와 관련된 일상 경험을 나눔으로써 매체와 매체 자료에 대 한 흥미와 관심을 가지고 매체의 가치와 필요성을 자연스럽게 인식하도록 하기 위해 설정하였다 . 매체란 소통을 매개하는 도구 , 기술, 환경으로 , 책, TV, 스마트폰 , 컴퓨터 , 태블릿 , 인터넷 등이 이에 속하며 , 매체 자료에는 그림책 , 만화, 뉴스, 광고, 웹툰, 애니메이션 , 영화 등이 있다 . 이 성취기준에서는 학습자가 친숙한 매체와 매체 자료를 토대로 일상의 경험을 매체와 연결 지어 이야기하여 매체와 매체 자료의 개념과 쓰임을 이해하고 다양한 매체와 매체 자료에 흥미와 관심을 갖도록 한다 ."}, {"id": 22, "code": "[2국06-02]", "text": "일상의 경험과 생각을 글과 그림으로 표현한다 .", "subject": "국어", "gradeGroup": "초1~2", "area": "매체", "verb": "행위", "textLen": 26, "hasExp": true, "explanation": "이 성취기준은 글과 그림으로 자신의 생각과 느낌을 표현하는 즐거움을 경험 하도록 하기 위해 설정하였다 . 글, 그림(또는 사진 , 이모티콘 등 )을 활용하여 자신 , 친구, 가족, 학교, 교실 등 친숙한 주제에 대해 표현하거나 그림일기를 작성해 보는 활동을 통해 자신의 경험과 생각을 다양한 방식으로 표현해 보는 데 중점을 둔다 ."}, {"id": 23, "code": "[4국01-01]", "text": "중요한 내용과 주제를 파악하며 듣고 그 내용을 요약한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "듣기·말하기", "verb": "행위", "textLen": 32, "hasExp": false}, {"id": 24, "code": "[4국01-02]", "text": "원인과 결과의 관계를 고려하여 내용을 예측하며 듣고 말한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "듣기·말하기", "verb": "행위", "textLen": 34, "hasExp": false}, {"id": 25, "code": "[4국01-03]", "text": "상황에 적절한 준언어 ⋅비언어적 표현을 활용하여 듣고 말한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "듣기·말하기", "verb": "행위", "textLen": 35, "hasExp": true, "explanation": "이 성취기준은 구어 의사소통 상황에서 억양 , 어조, 속도 등의 준언어적 표현 과 표정 , 시선, 몸동작 , 자세 등의 비언어적 표현을 활용하여 의미를 효과적으로 전달하고 이해할 수 있는 능력을 기르기 위해 설정하였다 . 다양한 상황에 알맞은 준언어 ⋅비언어적 표현의 중요성 이해하기 , 준언어 ⋅비언어적 표현의 의미와 효과 파악하기 , 준언어 ⋅비언 어적 표현의 적절성 점검하기 , 상황에 적절한 준언어 ⋅비언어적 표현 활용하기 등을 학습 한다."}, {"id": 26, "code": "[4국01-04]", "text": "상황과 상대의 입장을 이해하고 예의를 지키며 대화한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "듣기·말하기", "verb": "행위", "textLen": 31, "hasExp": false}, {"id": 27, "code": "[4국01-05]", "text": "목적과 주제에 알맞게 자료를 정리하여 자신감 있게 발표한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "듣기·말하기", "verb": "행위", "textLen": 34, "hasExp": true, "explanation": ") 과도 연계 하여 발표 자료의 준비 , 제작, 발표에 이르는 일련의 과정을 지도할 수도 있다 . •인터넷 접속 경험이 적고 자료 탐색 활동에 어려움을 겪는 학습자가 있는 경우 , 보다 구체 적인 안내를 통해 이들이 학습에서 소외되지 않도록 지도한다 . •매체 소통 윤리와 관련된 활동을 지도할 때는 규범의 당위성만을 강조하기보다는 매체 소 통에 참여하는 구성원으로서 지켜야 할 예절 , 배려, 준법정신 등의 태도를 강조하고 바람직 한 매체 소통 문화 형성에 기여하는 사회 구성원으로서의 소양을 기를 수 있도록 한다 . 국어과 교육과정 30[초등학교 5∼6학년] (1) 듣기⋅말하기"}, {"id": 28, "code": "[4국01-06]", "text": "주제에 적절한 의견과 이유를 제시하고 서로의 생각을 교환하며 토의한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "듣기·말하기", "verb": "행위", "textLen": 40, "hasExp": true, "explanation": "이 성취기준은 문제를 합리적으로 해결하기 위한 기초 능력으로서 토의 능력 을 기르기 위해 설정하였다 . 주제에 적절한 의견을 이유와 함께 제시하기 , 상대의 의견을 구체적으로 파악하거나 의견과 이유의 적절성을 점검하기 위해 서로 묻고 답하기 , 다른 사 람의 생각 존중하기 등을 학습한다 . 공통 교육과정 21"}, {"id": 29, "code": "[4국02-01]", "text": "글의 의미를 파악하며 유창하게 글을 읽는다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "읽기", "verb": "기타", "textLen": 25, "hasExp": true, "explanation": "이 성취기준은 글의 의미를 효과적으로 표현하는 방법을 사용하여 유창하게 글을 읽는 능력을 기르기 위해 설정하였다 . 글의 유형에 따라 글의 분위기 , 장면, 인물의 특성 등을 파악하고 이를 고려하되 , 어조, 억양, 속도, 강세 등의 표현 요소를 활용하여 글 을 읽으면서 글의 의미를 효과적으로 표현하기 등을 학습한다 ."}, {"id": 30, "code": "[4국02-02]", "text": "문단과 글에서 중심 생각을 파악하고 내용을 간추린다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "읽기", "verb": "기타", "textLen": 30, "hasExp": false}, {"id": 31, "code": "[4국02-03]", "text": "질문을 활용하여 글을 예측하며 읽고 자신의 읽기 과정을 점검한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "읽기", "verb": "행위", "textLen": 37, "hasExp": true, "explanation": "이 성취기준은 글을 읽으며 글에 대한 질문을 만들고 이에 대한 답을 예측하 면서 글을 읽는 추론적 읽기 능력을 기르기 위해 설정하였다 . 읽기 전이나 읽기 중에 이루 어지는 질문을 통해 자신의 배경지식이나 경험을 글과 관련짓기 , 배경지식이나 경험을 활 성화하여 글의 의미 추론하기 , 제목이나 글의 차례 , 사진이나 그림 등의 자료를 통해 글의 의미 추론하기 , 질문을 통해 단어의 의미 , 이어질 내용이나 사건의 전후를 예측하기 , 질문을 통해 글을 이해한 정도를 점검하거나 읽기 과정에서 겪는 어려움을 점검하기 등을 학습한다 ."}, {"id": 32, "code": "[4국02-04]", "text": "글에 나타난 사실과 의견을 구분하고 필자와 자신의 의견을 비교한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "읽기", "verb": "행위", "textLen": 38, "hasExp": true, "explanation": "이 성취기준은 글에 나타난 사실과 의견을 구별하고 필자와 자신의 의견을 비 교하면서 필자의 의견을 일방적으로 수용하지 않고 글을 비판적으로 읽는 능력을 기르기 위해 설정하였다 . 글을 읽고 필자의 의견과 객관적 사실을 구별하기 , 필자의 의견과 자신의 의견을 비교하기 , 필자의 의견에 대한 타당성을 평가하기 , 동일한 주제나 상황에 대한 서로 다른 의견 비교하기 등을 학습한다 ."}, {"id": 33, "code": "[4국02-05]", "text": "글이나 자료의 출처가 믿을 만한지 판단한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "읽기", "verb": "행위", "textLen": 25, "hasExp": true, "explanation": "이 성취기준은 도서관이나 인터넷 등을 통해 글이나 자료를 찾아 읽을 때 출 처의 신뢰성을 평가하며 읽고 믿을 만한 글이나 자료를 선별하는 능력을 기르기 위해 설정하였다 . 글이나 자료의 출처 확인 방법이나 필요성 이해하기 , 다양한 매체를 활용하여 글이 나 자료 탐색하기 , 글이나 자료의 정보 출처 파악하기 , 정보 출처의 유형이나 정보의 최신 성 확인하기 , 권위나 공신력 등을 고려한 신뢰성 평가하기 , 여러 정보를 비교하며 내용의 신뢰성 평가하기 등을 학습한다 . 공통 교육과정 23"}, {"id": 34, "code": "[4국02-06]", "text": "바람직한 읽기 습관을 형성하고 읽기에 대한 자신감을 기른다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "읽기", "verb": "태도", "textLen": 34, "hasExp": false}, {"id": 35, "code": "[4국03-01]", "text": "중심 문장과 뒷받침 문장을 갖추어 문단을 쓰고 , 문장과 문단을 중심으로 고쳐 쓴다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "쓰기", "verb": "기타", "textLen": 48, "hasExp": true, "explanation": "이 성취기준은 문단을 짜임새 있게 쓰는 능력을 길러 글을 쓰는 과정에서 이를 적용할 수 있도록 하기 위해 설정하였다 . 문단의 개념 , 문단의 기능과 역할 , 중심 문장과 뒷받침 문장의 관계 , 중심 문장과 뒷받침 문장을 쓰는 방법 , 중심 문장과 뒷받침 문장을 갖 추어 문단을 쓰는 방법 , 문장과 문단을 중심으로 글을 고쳐 쓰는 방법 등을 학습한다 ."}, {"id": 36, "code": "[4국03-02]", "text": "절차와 결과가 드러나게 정확한 표현으로 보고하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "쓰기", "verb": "기타", "textLen": 34, "hasExp": true, "explanation": "이 성취기준은 교과 학습의 기초가 되는 보고하는 글을 쓰는 능력을 기르기 위해 설정하였다 . 보고하는 글의 개념 , 보고하는 글에 들어가야 할 내용 요소 , 절차와 결과 가 드러나게 글의 내용을 조직하는 방법 , 절차와 결과를 정확하게 표현해야 하는 이유 , 정 확한 표현으로 보고하는 글 쓰기 등을 학습한다 ."}, {"id": 37, "code": "[4국03-03]", "text": "대상에 대한 자신의 의견과 그렇게 생각한 이유가 드러나게 글을 쓴다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "쓰기", "verb": "기타", "textLen": 39, "hasExp": true, "explanation": ") 에 대해 학습한 내용을 활용하여 , 의견을 제시할 때 고려해야 할 점에 유의하면서 작품에 대한 자신의 의견을 명확 하게 전달할 수 있도록 한다 . •자신의 경험을 문학으로 표현하는 활동을 할 때 , 작품으로 쓸 만한 특별한 일이나 경험이 없 다고 어려움을 호소하는 학습자의 경우 , 관심을 가지고 주위를 둘러보며 익숙했던 것들을 새로운 시각으로 관찰하는 등 작고 쉬운 일에서부터 경험의 폭을 넓힐 수 있게 독려한다 . 또 한 이러한 태도를 지속적으로 유지하며 문학 표현에 적극성을 가질 수 있게 지도한다 . •어떤 대상이나 상태를 다른 것에 빗대어 나타내는 비유적 표현을 지도할 때는 비유를 쓰지 않았을 때와 비유를 사용했을 때의 차이와 효과를 생각해 보게 함으로써 비유의 특성을 자연스럽게 이해할 수 있게 하는 데에 중점을 둔다 ."}, {"id": 38, "code": "[4국03-04]", "text": "목적과 주제를 고려하여 독자에게 마음을 전하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "쓰기", "verb": "기타", "textLen": 33, "hasExp": false}, {"id": 39, "code": "[4국03-05]", "text": "자신의 쓰기 과정을 점검하며 쓰기에 자신감을 갖는다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "쓰기", "verb": "태도", "textLen": 30, "hasExp": false}, {"id": 40, "code": "[4국04-01]", "text": "단어와 단어 간의 의미 관계를 파악한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문법", "verb": "행위", "textLen": 23, "hasExp": false}, {"id": 41, "code": "[4국04-02]", "text": "단어를 분류하고 국어사전을 활용하여 능동적인 국어 활동을 한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문법", "verb": "기타", "textLen": 36, "hasExp": true, "explanation": "이 성취기준은 단어에 대한 기본적인 이해를 바탕으로 국어사전에서 단어를 찾고 국어사전에 수록된 정보를 활용하여 능동적인 국어생활을 할 수 있는 능력을 기르기 위해 설정하였다 . 명사, 동사, 형용사에 대한 기본적인 이해를 바탕으로 하되 , 상황에 따라 다양하게 해석되는 단어의 의미를 국어사전에서 찾을 수 있도록 동형이의어와 다의어가 국어사전에 수 록된 방식을 이해하고 , 동사와 형용사의 기본형과 활용형을 구분할 수 있도록 한다 . 또한 국어 사전을 통해 단어의 표기 , 발음, 품사, 의미, 용례 등 다양한 정보를 확인할 수 있음을 이해 하고, 단어의 정확한 발음과 표기를 국어사전에서 찾아 어법에 맞는 국어생활을 할 수 있도록 한다."}, {"id": 42, "code": "[4국04-03]", "text": "기본적인 문장의 짜임을 이해하고 적절하게 사용한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문법", "verb": "행위", "textLen": 29, "hasExp": false}, {"id": 43, "code": "[4국04-04]", "text": "글과 담화에 쓰인 높임 표현과 지시 ⋅접속 표현을 이해하고 상황에 맞게 표현한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문법", "verb": "행위", "textLen": 46, "hasExp": true, "explanation": "이 성취기준은 높임 표현과 지시 ⋅접속 표현이 상황 맥락에 맞는 언어 표현을 선 택하거나 글이나 담화를 유기적으로 구성하는 데 필요한 지식임을 이해하고 , 글이나 담화에서 높임 표현과 지시 ⋅접속 표현을 적절히 사용할 수 있는 능력을 기르기 위해 설정하였다 . 높임 표현의 기능과 적절한 사용 방식 , 앞에 나온 말을 가리키는 지시 표현 및 문장과 문장 등을 연 결하는 다양한 접속 표현의 기능과 이러한 표현들의 적절한 사용 방식을 학습한다 ."}, {"id": 44, "code": "[4국04-05]", "text": "언어가 의사소통과 관계 형성의 수단임을 이해하고 국어를 소중히 여기는 태도를 지닌다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문법", "verb": "기타", "textLen": 48, "hasExp": false}, {"id": 45, "code": "[4국05-01]", "text": "인물과 이야기의 흐름을 중심으로 작품을 감상한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문학", "verb": "행위", "textLen": 28, "hasExp": true, "explanation": "이 성취기준은 문학 작품 속 인물의 특성과 서사의 기본 구조를 파악하며 작 품을 이해하는 능력을 기르게 하기 위해 설정하였다 . 이야기를 읽을 때 인물의 성격과 역할을 파악하고 , 이를 고려하여 시간적 순서나 인과관계를 생각하며 이야기의 흐름을 파악하는 활동에 중점을 둔다 . 나아가 작품 속 다양한 인물의 특성을 고려하면서 이어질 이야기를 상 상하여 표현해 봄으로써 작품을 능동적으로 이해하고 감상하게 한다 ."}, {"id": 46, "code": "[4국05-02]", "text": "자신의 경험을 바탕으로 작품 속 세계와 현실 세계를 비교하여 작품을 감상한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문학", "verb": "행위", "textLen": 44, "hasExp": true, "explanation": "이 성취기준은 작품 속의 세계가 현실 세계를 반영한 것이지만 , 허구적 세계로서 현실 세계와 구별된다는 점을 인식하며 작품을 감상할 수 있게 하기 위해 설정하였다 . 작품 속의 인물 ⋅정서⋅상황⋅배경⋅분위기 ⋅사건 등을 이해할 때 학습자 자신의 경험을 바탕 국어과 교육과정 28으로 경험과 상상 , 사실과 허구를 비교하며 생각하게 하고 , 허구적으로 표현한 부분에 대한 의견을 나누며 작품을 감상하도록 한다 ."}, {"id": 47, "code": "[4국05-03]", "text": "작품을 듣거나 읽고 마음에 드는 작품을 소개한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문학", "verb": "행위", "textLen": 28, "hasExp": false}, {"id": 48, "code": "[4국05-04]", "text": "감각적 표현에 유의하여 작품을 감상하고 , 감각적 표현을 활용하여 자신의 생각이나 감정을 표현한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문학", "verb": "행위", "textLen": 56, "hasExp": true, "explanation": "이 성취기준은 문학 표현 방식의 효과와 기능을 이해하며 작품을 감상하고 , 자 신의 생각이나 느낌을 다양한 방법으로 나타내어 다른 이들과 나누게 하기 위해 설정하였다 . 학습자로 하여금 감각적 표현을 통해 작품 속에 형상화된 대상을 생동감 있게 체험하면 서 문학의 즐거움을 느끼게 하는 데 중점을 둔다 . 또한 자신의 생각과 감정을 효과적으로 전달할 수 있는 감각적 표현을 활용하여 말을 하거나 글을 써 보고 감각적 표현을 사용하였을 때와 그렇지 않을 때의 차이를 비교하게 한다 ."}, {"id": 49, "code": "[4국05-05]", "text": "재미나 감동을 느끼며 작품을 즐겨 감상하는 태도를 지닌다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "문학", "verb": "기타", "textLen": 33, "hasExp": false}, {"id": 50, "code": "[4국06-01]", "text": "인터넷에서 학습에 필요한 다양한 자료를 탐색하고 목적에 맞게 자료를 선택한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "매체", "verb": "행위", "textLen": 44, "hasExp": true, "explanation": "이 성취기준은 다양한 교과 학습 맥락에서 인터넷에 접속하여 다양한 자료에 효과적으로 접근하고 유용한 정보를 선택하여 목적에 맞게 활용할 때 필요한 기초 능력을 기르기 위해 설정하였다 . 교사의 안내에 따라 디지털 매체를 통해 지정된 인터넷 공간에 접 공통 교육과정 29속하기 , 다양한 자료 훑어보기 , 자료의 내용 파악하기 , 유용한 자료 선택하기 등을 수행하 고, 이를 통해 인터넷 접속 방법 , 비선형적 자료의 탐색 방법 , 목적에 맞는 정보 선택 방법 등을 체계적으로 학습한다 ."}, {"id": 51, "code": "[4국06-02]", "text": "매체를 활용하여 간단한 발표 자료를 만든다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "매체", "verb": "기타", "textLen": 25, "hasExp": false}, {"id": 52, "code": "[4국06-03]", "text": "매체 소통 윤리를 고려하여 매체 자료를 활용하고 공유한다 .", "subject": "국어", "gradeGroup": "초3~4", "area": "매체", "verb": "행위", "textLen": 33, "hasExp": true, "explanation": "이 성취기준은 매체 기반의 소통에서 지켜야 할 기본적인 윤리를 이해하고 이를 고려하며 매체 자료를 활용하거나 공유할 수 있는 능력을 기르기 위해 설정하였다 . 다양한 매체 자료를 활용하거나 공유하는 과정에서 저작권과 초상권 침해 , 개인 정보 유출 등의 문제가 발 생할 수 있음을 이해한다 . 다양한 사례를 통해 매체 이용자로서 소통 윤리를 지키려는 태도를 기르고 , 매체 자료를 안전하고 올바르게 활용하고 공유할 수 있는 방법 등을 학습한다 ."}, {"id": 53, "code": "[6국01-01]", "text": "대화에서 생략된 내용을 추론하며 듣는다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "듣기·말하기", "verb": "기타", "textLen": 23, "hasExp": false}, {"id": 54, "code": "[6국01-02]", "text": "주장을 파악하고 이유나 근거가 타당한지 평가하며 듣는다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "듣기·말하기", "verb": "기타", "textLen": 32, "hasExp": false}, {"id": 55, "code": "[6국01-03]", "text": "주제와 관련하여 궁금한 내용을 질문하며 적극적으로 듣고 말한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "듣기·말하기", "verb": "행위", "textLen": 36, "hasExp": true, "explanation": "이 성취기준은 교과 학습 상황을 비롯한 다양한 상황에서 주제와 관련하여 적 극적으로 질문하며 구어 의사소통에 참여하는 능력을 기르기 위해 설정하였다 . 들은 내용 을 확인하거나 명료하게 이해하기 위한 질문 , 생략된 내용을 추론하기 위한 질문 , 상대의 의도를 파악하기 위한 질문 , 다른 사람의 생각과 자신의 생각을 연결하기 위한 질문 , 자료 에서 제시되지 않은 대안이나 더 많은 정보를 찾기 위한 질문 등 다양한 목적으로 질문 생 성하기 , 분명한 표현으로 질문하기 , 예절을 지켜 질문하기 등을 학습한다 ."}, {"id": 56, "code": "[6국01-04]", "text": "면담의 절차를 이해하고 상대와 매체를 고려하여 면담한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "듣기·말하기", "verb": "행위", "textLen": 32, "hasExp": true, "explanation": "이 성취기준은 일련의 절차에 따라 면담을 경험해 봄으로써 정보 수집 등의 목적을 가진 구어 의사소통을 효과적이고 체계적으로 수행하는 능력을 기르기 위해 설정하 였다. 면담 준비 ⋅진행⋅결과 정리 등 면담의 절차 이해하기 , 면담의 목적 ⋅대상⋅주제 등 설정하기 , 사전 정보 수집하기 , 면담 대상 섭외하기 , 목적⋅대상⋅주제에 알맞은 질문 준비 하기, 녹음기나 기록용 노트 등 면담에 필요한 매체 준비하기 , 준비한 질문을 바탕으로 면 담하기 , 면담 결과를 발표하거나 글로 써서 보고하기 등을 학습한다 . 면담 상대를 배려하여 사전에 약속 시간 정하기 , 녹음 여부에 대해 동의 구하기 , 민감하거나 불편한 질문은 아닌 지 점검하기 , 종료 후 감사 표현하기 등 면담 과정에서 지켜야 할 예절도 학습한다 ."}, {"id": 57, "code": "[6국01-05]", "text": ") 과 연 계 가능하다 . 학습자들은", "subject": "국어", "gradeGroup": "초5~6", "area": "듣기·말하기", "verb": "기타", "textLen": 20, "hasExp": true, "explanation": "의 학습 상황에 적용해 볼 수 있다 . •정보 검색 활동에서 초등학생에게 교육적으로 적합하지 않은 선정적인 글이나 이미지 등의 검색 결과가 포함될 수 있다 . 교사는 이를 고려하여 학습자들이 안전한 인터넷 공간에서 검 색 활동을 실행할 수 있게 하며 , 이러한 고려에도 불구하고 부적절한 자료가 검색되었을 때 는 교사에게 즉시 말할 수 있도록 사전에 안내한다 . •복합양식 매체 자료의 제작은 쓰기 및 문법 영역의 성취기준과 연계하여 지도할 수 있다 . 쓰 기 영역에서는 문자를 중심으로 독자와 매체를 고려하여 글을 생산하는 과정 ("}, {"id": 58, "code": "[6국01-06]", "text": "토의에 협력적으로 참여하며 서로의 의견을 비교하고 조정한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "듣기·말하기", "verb": "행위", "textLen": 34, "hasExp": false}, {"id": 59, "code": "[6국01-07]", "text": "절차와 규칙을 지키고 타당한 이유와 근거를 제시하며 토론한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "듣기·말하기", "verb": "행위", "textLen": 35, "hasExp": true, "explanation": "이 성취기준은 민주적 의사소통 능력으로서 토론 능력을 기르기 위해 설정하 였다."}, {"id": 60, "code": "[6국02-01]", "text": "글의 구조를 고려하며 주제나 주장을 파악하고 글 내용을 요약한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "읽기", "verb": "행위", "textLen": 37, "hasExp": true, "explanation": "이 성취기준은 글의 구조를 고려하며 글의 중심 내용을 파악하고 자신의 언어로 요약하는 능력을 기르기 위해 설정하였다 . 요약하기의 일반 원리를 이해하기 , 글의 구조를 시각화한 도해 조직자를 활용하여 글의 구조와 내용 파악하기 , 주제나 주장을 파악하기 , 글의 중심 내용을 자신의 언어로 재구성하여 요약하기 등을 학습한다 ."}, {"id": 61, "code": "[6국02-02]", "text": "글에서 생략된 내용이나 함축된 표현을 문맥을 고려하여 추론한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "읽기", "verb": "행위", "textLen": 36, "hasExp": true, "explanation": "이 성취기준은 글의 문맥을 고려하여 글에 표면적으로 드러나지 않은 내용을 추론하며 읽는 능력을 기르기 위해 설정하였다 . 중요 단어나 문장 , 문단 등의 수준에서 의 미 추론하기 , 글의 전체적인 흐름을 고려할 때 글에서 빠진 세부 내용이나 이어질 내용 추 론하기 , 학습자의 배경지식을 이용하여 함축적 표현이 암시하거나 내포하는 의미 추측하기 등을 학습한다 ."}, {"id": 62, "code": "[6국02-03]", "text": "글이나 자료를 읽고 내용의 타당성과 표현의 적절성을 평가한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "읽기", "verb": "행위", "textLen": 35, "hasExp": false}, {"id": 63, "code": "[6국02-04]", "text": "문제 상황과 관련된 다양한 관점의 글을 읽고 이를 문제 해결에 활용한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "읽기", "verb": "행위", "textLen": 41, "hasExp": true, "explanation": "이 성취기준은 학습자가 직면한 문제를 해결하기 위해 다양한 관점의 글을 찾아 읽고 문제 해결에 필요한 지식이나 정보를 구성하는 창의적 읽기 능력을 기르기 위해 설정하였다 . 문제 상황과 관련한 읽기 목적 명료화하기 , 문제 상황 해결에 도움을 줄 수 있는 다양한 관점의 글 선정하기 , 다양한 관점의 글을 읽고 내용의 타당성과 유용성 평가하기 , 문제 해결을 위한 자신만의 창의적인 해결 방안 마련하기 등을 학습한다 ."}, {"id": 64, "code": "[6국02-05]", "text": "긍정적인 읽기 동기를 형성하고 적극적으로 읽기에 참여하는 태도를 기른다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "읽기", "verb": "태도", "textLen": 41, "hasExp": false}, {"id": 65, "code": "[6국03-01]", "text": "알맞은 내용을 선정하여 대상의 특성이 나타나게 설명하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "쓰기", "verb": "기타", "textLen": 38, "hasExp": true, "explanation": "이 성취기준은 설명하는 글을 쓰는 데에 필요한 능력을 기르기 위해 설정하였다 . 설명하고자 하는 대상의 특성을 드러낼 수 있는 내용을 선정하는 방법 , 개념 정의 , 부연 상술 , 예시, 열거, 인용, 비교와 대조 등을 활용하여 독자가 대상의 특성을 이해하기 쉽게 내용을 구성하고 표현하는 방법 , 설명 대상과 설명 방법의 관련성 등을 학습한다 . 설명 대상은 인문 , 사회, 과학, 예술, 체육 등 교과 내용에서 선정한다 ."}, {"id": 66, "code": "[6국03-02]", "text": "적절한 근거를 사용하고 인용의 출처를 밝히며 주장하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "쓰기", "verb": "기타", "textLen": 37, "hasExp": true, "explanation": "이 성취기준은 주장하는 글을 쓰는 데에 필요한 능력과 쓰기 윤리를 준수하며 글을 쓰는 태도를 기르기 위해 설정하였다 . 주장하는 글 쓰기의 중요성과 특성 , 주장과 이유 및 근거의 개념과 관계 , 주장하는 글에 적절한 근거가 필요한 까닭 , 역사적 사실 , 실험 및 조사 결과 , 통계 수치 , 전문가의 견해 등을 활용하여 근거 생성하기 , 이유와 근거를 활용하여 주장하는 글 쓰기 , 인용의 출처를 밝혀야 하는 이유와 기본적인 인용 방법 등을 학습한다 ."}, {"id": 67, "code": "[6국03-03]", "text": "체험한 일에 대한 감상을 나타내는 글을 쓴다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "쓰기", "verb": "기타", "textLen": 26, "hasExp": false}, {"id": 68, "code": "[6국03-04]", "text": "독자와 매체를 고려하여 내용을 생성하고 표현하며 글을 쓴다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "쓰기", "verb": "기타", "textLen": 34, "hasExp": true, "explanation": ") 에 초점을 맞춘다면 , 매체 영역에서는 문자와 더불어 그림 , 사진, 이미지 , 소리 등의 다양한 표현 양식을 통한 소통에 초점을 맞춘다 . 각 양식의 표현 효과를 이해하고 적용하는 과정은 문법 영역에서 음성 언어 및 문자 언어의 특성을 이해하고 다양한 매체 자료에서 표현 효과를 평가하는 활동 ("}, {"id": 69, "code": "[6국03-05]", "text": "쓰기 과정을 점검 ⋅조정하며 글을 쓰고 , 글 전체를 대상으로 통일성 있게 고쳐 쓴다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "쓰기", "verb": "기타", "textLen": 49, "hasExp": true, "explanation": "이 성취기준은 필자가 자신의 쓰기 과정을 점검 ⋅조정하고 그 결과를 바탕으 로 글을 고쳐 쓰는 능력을 기르기 위해 설정하였다 . 글쓰기에서 통일성의 개념과 중요성 , 쓰기 과정에 대한 점검과 조정의 필요성 , 쓰기 과정의 회귀적 특성 , 글에 대한 독자의 반응을 생각하며 고쳐쓰기 , 글의 주제와 목적 , 예상 독자 등을 고려하여 글의 통일성 점검하기 등을 학습한다 . 공통 교육과정 35"}, {"id": 70, "code": "[6국03-06]", "text": "쓰기에 적극적으로 참여하며 자신의 글을 독자와 공유하는 태도를 지닌다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "쓰기", "verb": "기타", "textLen": 40, "hasExp": false}, {"id": 71, "code": "[6국04-01]", "text": "음성 언어 및 문자 언어의 특성을 이해하고 다양한 매체 자료에서 표현 효과를 평가한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문법", "verb": "행위", "textLen": 49, "hasExp": true, "explanation": ") 과 유기적으로 연계될 수 있다 . 국어과 교육과정 42[중학교 1∼3학년] (1) 듣기⋅말하기"}, {"id": 72, "code": "[6국04-02]", "text": "표준어와 방언의 기능을 파악하고 언어 공동체와 국어생활과의 관계를 이해한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문법", "verb": "행위", "textLen": 43, "hasExp": true, "explanation": "이 성취기준은 국어 화자의 의사소통에서 표준어와 방언이 담당하는 기능이 다르다는 점을 알고 , 자신이 속한 언어 공동체 특유의 한국어 변이형들로 인해 자신의 국어 생활이 상황에 따라 다양하게 실현됨을 이해하도록 하기 위해 설정하였다 . 방언의 형성과 존재 양상을 파악함으로써 지역적 요인에 따라 자연스럽게 한국어에 변이가 일어남을 이해 하도록 하고 , 이러한 다양성을 아우르는 언어 공동체 규준인 표준어의 개념과 필요성을 함 께 다루도록 한다 . 또한 의사소통의 공적 ⋅사적 상황에 따라 , 상대방과의 거리감 조절 등 화자의 의도에 따라 표준어와 방언을 선택함으로써 다양한 의사소통 기능이 실현된다는 점 을 확인할 수 있도록 한다 . 공통 교육과정 37"}, {"id": 73, "code": "[6국04-03]", "text": "고유어와 관용 표현의 쓰임과 가치를 이해하고 상황에 맞게 표현한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문법", "verb": "행위", "textLen": 38, "hasExp": true, "explanation": "이 성취기준은 고유어와 관용 표현의 쓰임과 가치를 이해하고 국어문화에 대한 관심과 우리말을 소중히 여기는 태도를 고양하기 위해 설정하였다 . 한자어 , 외래어와 함께 국어 어휘의 일부를 이루는 고유어의 특성과 가치 , 고유어에 다양하게 발달해 있는 관용 표 현의 특성과 쓰임에 대한 이해에 중점을 두되 , 상황과 표현 의도에 따라 어휘를 적절하게 사용하고 외래어의 오 ⋅남용 방지 등 국어 순화의 필요성을 자각하며 실천할 수 있도록 한다 ."}, {"id": 74, "code": "[6국04-04]", "text": "문장 성분을 이해하고 호응 관계가 올바른 문장을 구성한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문법", "verb": "행위", "textLen": 33, "hasExp": true, "explanation": "이 성취기준은 문장을 구성하는 성분들 사이의 호응 관계가 올바르고 자연스 러운 문장을 구성하는 데 필요한 능력을 기르기 위해 설정하였다 . 문장에서 주어 , 목적어 , 서술어의 역할 , 성분 간의 호응 관계 (주어와 서술어의 호응 , 목적어와 서술어의 호응 )에 대 해 학습하고 , 이전 학년군의 높임 표현 및 동일 학년군의 시간 표현 성취기준과 연계하여 높임이나 시제의 일치를 함께 학습할 수 있다 ."}, {"id": 75, "code": "[6국04-05]", "text": "글과 담화에 쓰인 시간 표현을 이해하고 상황에 맞게 표현한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문법", "verb": "행위", "textLen": 35, "hasExp": true, "explanation": "이 성취기준은 효과적인 의사소통을 위해 상황 맥락에 맞게 시간 표현을 사용 하는 것의 중요성을 알고 시간을 표현할 때 사용되는 언어 형식을 이해하고 활용하는 능력 을 기르기 위해 설정하였다 . ‘-았-/-었-, -는-/-ㄴ-, -겠-, -(으)ㄹ 것이 -’나 시간 부사 등 글이나 담화에서 과거 , 현재, 미래를 표현하는 언어 형식 및 방법을 학습하고 , 다양한 상황 맥락에서 시간 표현을 사용한 후 그 적절성을 평가해 보도록 한다 ."}, {"id": 76, "code": "[6국04-06]", "text": "글과 담화에 쓰인 단어 및 문장 , 띄어쓰기를 민감하게 살펴 바르게 고치는 태도를 지닌다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문법", "verb": "기타", "textLen": 51, "hasExp": false}, {"id": 77, "code": "[6국05-01]", "text": "작가의 의도를 생각하며 작품을 읽는다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문학", "verb": "기타", "textLen": 22, "hasExp": true, "explanation": "이 성취기준은 작품을 만든 이에 대해 호기심을 가지고 작가라는 존재를 고려 하면서 작품을 수용하는 능력을 기르게 하기 위해 설정하였다 . 작가가 작품을 쓰게 된 계기나 상황을 생각하고 , 작가의 취지와 의도를 헤아리면서 작품을 더 깊고 넓게 이해할 수 있게 한다. 또한 작가에 대한 관심을 바탕으로 작가의 다른 작품들도 찾아 읽는 태도를 가지며 능동적인 문학 향유자로 성장할 수 있게 한다 . 아울러 다양한 상상의 세계를 펼쳐 보이는 창의성을 가진 인간에게 관심을 가짐으로써 학습자도 그러한 창의성을 가진 인간으로 성장하는 계기가 될 수 있게 한다 . 다만 작품의 의미는 작가의 의도에 한정되는 것이 아니며 , 다양한 독자들의 해석이 더해져서 계속 생성되어 가는 것이라는 점을 함께 생각하며 문학 소통에 적극적으로 참여할 수 있게 한다 ."}, {"id": 78, "code": "[6국05-02]", "text": "비유적 표현의 효과에 유의하여 작품을 감상한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문학", "verb": "행위", "textLen": 27, "hasExp": false}, {"id": 79, "code": "[6국05-03]", "text": "소설이나 극을 읽고 인물 , 사건, 배경을 파악한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문학", "verb": "행위", "textLen": 30, "hasExp": true, "explanation": "이 성취기준은 작품을 이루는 주요 요소를 중심으로 작품을 분석하고 이해하 는 능력을 기르게 하기 위해 설정하였다 . 작품 속 인물 , 사건, 배경을 파악하고 , 각 요소의 기능 및 요소 간 관계를 이해하도록 한다 . 예를 들어 인물의 성격과 사건의 전개 과정 간의 관계, 인물의 성격이 사건 전개 과정에 끼치는 영향 , 사건의 전개 과정과 배경과의 관련 , 배경의 변화에 따른 사건 전개 과정의 변화 등을 파악하여 작품을 깊이 있게 감상한다 . 나 아가 이러한 요소의 역할이나 관계가 모든 작품에서 동일한 양상으로 나타나는 것이 아니며 , 작품에 따라 특정 요소가 두드러지게 부각되기도 하고 요소 간의 관계가 독특하게 형성 되기도 한다는 점을 생각하며 작품을 수용하게 한다 ."}, {"id": 80, "code": "[6국05-04]", "text": "인상적인 부분을 중심으로 작품에 대한 의견을 나눈다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문학", "verb": "기타", "textLen": 30, "hasExp": true, "explanation": "이 성취기준은 학습자가 작품에 대한 자신의 생각을 적극적으로 표현하고 , 이 를 타인과 나눔으로써 보다 주체적인 문학 수용 능력을 기르게 하기 위해 설정하였다 . 이를 위해 인상적인 장면을 중심으로 작품에 대한 의견을 나누되 , 인상적이라고 생각하는 이유 공통 교육과정 39나 근거를 작품과 연결 지어 설명하도록 한다 . 또한 상대방의 수용 경험에도 귀를 기울여 작품에 대한 해석이 다양한 관점에서 이루어질 수 있음을 알고 문학 소통에 즐겁게 참여하도록 한다 ."}, {"id": 81, "code": "[6국05-05]", "text": "자신의 경험을 시 , 소설, 극, 수필 등 적절한 갈래로 표현한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문학", "verb": "행위", "textLen": 38, "hasExp": true, "explanation": ") 에서 간단히 다루고 , ‘공통국어 1’을 거쳐 선택 과목 ‘문학’([12문학01-02]) 에서 종합적으로 다루게 되는 , 문학 영역의 대 표적인 반복 ⋅심화 학습 내용 중 하나이다 . ‘공통국어 1’에서는 서정 , 서사, 극, 교술 갈래별 로 나타나는 특성이 작품의 주제를 효과적으로 전달하거나 작품에서 아름다움을 느끼게 하는 데에 어떻게 작용하는지 살피면서 작품을 수용하도록 한다 . •생태 소양을 함양하는 데에 필요한 생명 존중 의식이나 생태 감수성을 담은 작품 , 생태적 관점에서 새롭게 해석할 수 있는 작품 등을 통해 지속가능한 발전을 자신의 일로 생각하는 주체적 태도를 기를 수 있게 지도한다 . •작품 구성 요소의 유기적 관계와 맥락에 유의하며 작품을 생산하는 활동에 대해 평가할 때 는 최종 결과물에 대해서만 평가하지 말고 , 학습자들이 어떤 의도를 가지고 작품을 생산하 였는지 설명하는 말이나 글을 덧붙이게 할 필요가 있다 ."}, {"id": 82, "code": "[6국05-06]", "text": "작품을 읽고 자신의 삶과 연관 지어 성찰하는 태도를 지닌다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "문학", "verb": "기타", "textLen": 34, "hasExp": true, "explanation": "이 성취기준은 작품을 읽고 성찰하는 과정을 통해 자신을 돌아보는 것은 물론 자신이 속한 공동체의 삶에 대해서도 생각하게 하기 위해 설정하였다 . 학습자가 작품을 적 극적으로 수용하여 작품에 담긴 가치를 내면화하는 가운데 자신의 삶의 모습을 되돌아보게 한다 . 또한 공동체의 다양한 문제를 다룬 작품을 읽을 때에도 먼저 자신의 삶을 돌아보고 , 함께 살아가는 삶을 위해 공동체 구성원으로서 가져야 할 바람직한 자세나 태도에 대하여 생각해 보도록 한다 ."}, {"id": 83, "code": "[6국06-01]", "text": "에서 정보를 검색하는 일반적인 원리를 학습한 후 이 를", "subject": "국어", "gradeGroup": "초5~6", "area": "매체", "verb": "기타", "textLen": 30, "hasExp": true, "explanation": "정보 검색 도구를 활용하여 자신의 목적에 맞는 매체 자료를 찾는다 ."}, {"id": 84, "code": "[6국06-02]", "text": "뉴스 및 각종 정보 매체 자료의 신뢰성을 평가한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "매체", "verb": "행위", "textLen": 29, "hasExp": true, "explanation": "이 성취기준은 뉴스 및 각종 정보 매체의 매체 자료에 대해 신뢰성 측면을 중 심으로 평가하는 능력을 기르기 위해 설정하였다 . 뉴스 및 각종 정보 매체 자료는 개인과 공동체에 미치는 영향력이 크기 때문에 매체 자료를 수용할 때는 그것이 신뢰할 만한 것인 지 평가하는 태도가 중요하다는 점을 이해하도록 한다 . 매체 자료의 신뢰성은 제작자가 얼 마나 해당 분야에 전문적이고 권위가 있는지 , 실제 취재하거나 수집한 근거 자료를 기반으 로 제작된 것인지 , 근거 자료가 얼마나 정확하고 최신의 것이며 증빙 가능한 것인지 등의 측면에서 평가할 수 있다 ."}, {"id": 85, "code": "[6국06-03]", "text": "적합한 양식과 수용자의 반응을 고려하여 복합양식 매체 자료를 제작하고 공유한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "매체", "verb": "행위", "textLen": 45, "hasExp": true, "explanation": "이 성취기준은 매체 및 매체 자료의 양식과 수용자에게 끼칠 영향을 고려하여 복합양식 자료를 제작하는 능력을 기르기 위해 설정하였다 . 의도나 주제를 드러내는 다양 한 표현 양식을 이해하고 자신의 목적 , 주제, 수용자 반응을 고려하여 이미지가 포함된 글 , 공통 교육과정 41카드 뉴스 , 발표 자료 , 동영상 등의 복합양식 매체 자료를 제작한 다음 이를 공유하여 그 효과성을 점검한다 ."}, {"id": 86, "code": "[6국06-04]", "text": "자신의 매체 이용 양상에 대해 성찰한다 .", "subject": "국어", "gradeGroup": "초5~6", "area": "매체", "verb": "행위", "textLen": 23, "hasExp": false}, {"id": 87, "code": "[9국01-01]", "text": "화자의 의도와 관점을 추론하며 듣는다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "기타", "textLen": 22, "hasExp": true, "explanation": "이 성취기준은 담화의 맥락을 고려하여 담화에서 표면적으로 드러나지 않는 숨겨진 요소를 추론하며 들음으로써 담화의 내용을 깊이 이해하는 능력을 기르기 위해 설정하였다 . 일상의 대화 상황에서 상대의 발화 의도 추론하기 , 정보 전달이나 설득 등 다양 한 목적의 담화에서 여러 가지 정보와 상황 맥락을 고려하여 화자의 숨겨진 의도와 관점 , 가치관 추론하기 등을 학습한다 ."}, {"id": 88, "code": "[9국01-02]", "text": "설득 전략을 비판적으로 분석하며 듣는다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "기타", "textLen": 23, "hasExp": false}, {"id": 89, "code": "[9국01-03]", "text": "담화 공동체에 따른 듣기 ⋅말하기 방식의 다양성을 고려하여 듣고 말한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 41, "hasExp": true, "explanation": "이 성취기준은 개인이 속해 있는 담화 공동체의 듣기 ⋅말하기 방식이 가진 다 양성을 고려하여 구어 의사소통에 참여함으로써 사회 ⋅문화적 맥락에 맞는 의사소통 능력을 기르기 위해 설정하였다 . 듣기⋅말하기 방식에 영향을 미치는 요인으로 세대 , 성, 직업, 지역, 공동체의 관심사나 이해관계 , 공동체의 언어문화와 관습 등이 있음을 이해하기 , 개인이 속한 집단이나 공동체에 따라 듣기 ⋅말하기 방식이 다양할 수 있음을 이해하기 , 듣기⋅말하기 방식의 다양성에 대한 존중이 긍정적인 관계 형성과 유지에 기여함을 이해하기 , 서로 다른 듣기⋅말하기 방식을 이해하고 존중하는 태도 형성하기 , 자신의 듣기 ⋅말하기 방식이 상황 맥락이나 자신이 속한 공동체에 적절한지를 지속적으로 점검하여 개선하기 등을 학습한다 ."}, {"id": 90, "code": "[9국01-04]", "text": "상대의 말을 경청하고 상대의 감정과 입장에 공감하는 반응을 보이며 대화한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 43, "hasExp": false}, {"id": 91, "code": "[9국01-05]", "text": "면담의 다양한 목적과 상대를 고려하여 질문을 점검하고 효과적으로 면담한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "이 성취기준은 효과적으로 면담을 수행함으로써 목적과 상대를 고려하는 의사 소통 능력을 기르기 위해 설정하였다 . 말하기나 글쓰기를 위한 자료 수집 , 의사 결정 , 상담, 선발 등 다양한 면담 목적과 상대를 고려하여 질문 마련하기 , 구조화 면담 또는 반구조화 공통 교육과정 43면담 등 면담 유형에 적절한 면담 수행 계획 세우기 , 면담 대상자의 입장이나 반응 등에 따 라 면담 질문의 내용이나 순서 , 진행 방법 등을 조정하여 면담하기 , 면담 중에 추가 질문하 기, 면담 후 면담 계획이나 목적에 따라 면담이 원만하게 진행되었는지를 점검하기 , 질문의 의도와 답변자의 의도를 고려하여 면담 내용을 정리하기 등을 학습한다 ."}, {"id": 92, "code": "[9국01-06]", "text": "다양한 자료를 재구성하여 내용을 체계적으로 조직하고 청중이 이해하기 쉽게 발표한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "이 성취기준은 말할 내용을 체계적으로 조직하여 청중이 이해하기 쉽게 발표 하는 능력을 함양하기 위해 설정하였다 . 다양한 자료를 청자가 이해하기 쉬운 방향으로 재 구성하기 , 발표 내용을 도입부 ⋅전개부 ⋅정리부로 나누어 체계적으로 구성하기 , 발표 목적 이나 대상의 특성에 적절한 설명 방법 활용하기 , 청중이 이해하기 쉽게 발표하기 , 발표 준 비와 실행 과정을 되돌아보고 수행의 적절성 점검하기 등을 학습한다 ."}, {"id": 93, "code": "[9국01-07]", "text": "토의에서 다양한 의견을 교환하여 대안을 마련하고 문제를 해결한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 37, "hasExp": false}, {"id": 94, "code": "[9국01-08]", "text": "토론에서 반론을 고려하여 타당한 논증을 구성하고 논리적으로 반박한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 39, "hasExp": true, "explanation": "이 성취기준은 합리적이고 민주적인 의사 결정을 위한 토론 능력을 기르기 위 해 설정하였다 . 토론 논제에 대한 찬성과 반대 입장별로 각 입장을 뒷받침하는 이유와 근거 마련하기 , 상대방이 제기할 수 있는 반론을 고려하여 논증 구성하기 , 주장⋅이유⋅근거⋅ 반론에 대한 고려 등 논증 구성 요소들이 타당한지 비판적으로 분석하여 반박하기 , 논증의 논리적 전개 과정에서 논리적 허점이나 오류가 없는지 분석하여 반박하기 등을 학습한다 ."}, {"id": 95, "code": "[9국01-09]", "text": "서로의 감정이나 바라는 바를 진솔하게 표현하면서 갈등을 조정한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 37, "hasExp": true, "explanation": "이 성취기준은 갈등을 조정할 수 있는 대화 방법을 배움으로써 상대방과의 관 계를 원만하게 유지할 수 있는 능력을 기르기 위해 설정하였다 . 자신의 생각과 감정을 진솔 하게 표현하는 것이 왜 중요한지 이해하기 , 자신과 상대의 생각과 감정 , 욕구 등을 정확히 파악하기 , 어떠한 차이로 인해 갈등이 발생하게 되었는지 분석하기 , 사건에 대한 주관적 해 석을 배제하고 객관적으로 전달하기 , 상황이나 사건에 대한 자신의 감정과 욕구를 진솔하 게 표현하기 , 자신이 상대에게 바라는 것이 무엇인지 구체적으로 요청하기 방법을 활용하 여 갈등 조정하기 , 갈등을 악화시킬 수 있는 표현 경계하기 , 상대의 의견과 감정을 존중하 기 등을 학습한다 ."}, {"id": 96, "code": "[9국01-10]", "text": "언어폭력의 문제점을 성찰하고 , 서로를 존중하는 표현을 사용하여 말한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 41, "hasExp": false}, {"id": 97, "code": "[9국01-11]", "text": "듣기⋅말하기 과정을 점검하고 듣기 ⋅말하기의 어려움을 효과적으로 조정한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "듣기·말하기", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "이 성취기준은 듣기 ⋅말하기 전 ⋅중⋅후 과정을 점검하고 구어 의사소통 과정 에서 발생하는 다양한 어려움을 효과적으로 조정하는 상위 인지 능력을 기르기 위해 설정 하였다 . 듣기⋅말하기 활동 후에 자신의 듣기 ⋅말하기 과정이 적절했는지 성찰하기 , 듣기⋅ 말하기 과정에서 부딪히는 어려움 분석하기 , 향후의 듣기 ⋅말하기를 효과적으로 수행하기 위해 조정해야 할 점을 찾아 개선 계획 세워보기 , 말하기 불안을 느끼는 상황에서 이를 완 화할 수 있는 방법을 연습하고 적용하기 등을 학습한다 ."}, {"id": 98, "code": "[9국02-01]", "text": "읽기는 사회 ⋅문화적 맥락에서 의미를 구성하는 과정임을 이해하며 사회적 독서에 참여 하고 사회적 독서 문화 형성에 기여한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "읽기", "verb": "행위", "textLen": 70, "hasExp": true, "explanation": "이 성취기준은 읽기가 다양한 사회 ⋅문화적 맥락에 속한 공동체 구성원들이 상호 작용하며 의미를 구성하는 과정임을 이해하고 사회적 독서 문화 형성에 기여하도록 하기 위해 설정하였다 . 독자는 자신이 처한 상황이나 사회 ⋅문화, 역사적 배경에 따라 의미 를 형성해 간다 . 또한 공동체 구성원들이 구성한 의미를 협력적으로 소통함에 따라 타인의 삶에 대한 이해나 공동체가 지향해야 할 가치를 발견할 수 있다 . 사회⋅문화적으로 가치 있는 주제의 글을 선정하여 읽기 , 사회⋅문화적 맥락을 고려하여 필자의 의도 파악하기 , 독 서 토론을 통해 구성원 간의 다양한 의미 교환하기 , 사회⋅문화적 맥락에서 새로운 의미 국어과 교육과정 46발견하기 , 사회적 독서 문화 형성하기 등을 학습한다 ."}, {"id": 99, "code": "[9국02-02]", "text": "읽기 목적과 글의 구조를 고려하며 글을 효과적으로 요약한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "읽기", "verb": "행위", "textLen": 34, "hasExp": false}, {"id": 100, "code": "[9국02-03]", "text": "독자의 배경지식과 글에 나타난 정보 등을 활용하여 글에 드러나지 않은 의도나 관점을 추론하며 읽는다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "읽기", "verb": "기타", "textLen": 57, "hasExp": false}, {"id": 101, "code": "[9국02-04]", "text": ") 과 연계 가 능하다 . 공통 교육과정 59 3. 교수 ⋅학습 및 평가", "subject": "국어", "gradeGroup": "중1~3", "area": "읽기", "verb": "기타", "textLen": 40, "hasExp": true, "explanation": "복합양식으로 구성된 글이나 자료의 내용 타당성과 신뢰성 , 표 현 방 법 의 적 절 성 을 평 가 하며 읽는다 ."}, {"id": 102, "code": "[9국02-05]", "text": "글에 사용된 다양한 설명 방법과 논증 방법을 파악하고 , 그 타당성을 평가하며 읽는다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "읽기", "verb": "기타", "textLen": 49, "hasExp": false}, {"id": 103, "code": "[9국02-06]", "text": "동일한 화제를 다룬 여러 글이나 자료를 주제 통합적으로 읽는다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "읽기", "verb": "기타", "textLen": 36, "hasExp": true, "explanation": "이 성취기준은 동일한 화제를 다룬 여러 글이나 자료를 비판적으로 읽고 자신 의 관점에 따라 의미를 재구성할 수 있는 주제 통합적 읽기 능력을 기르기 위해 설정하였"}, {"id": 104, "code": "[9국02-07]", "text": ") 와 연계하여 지도할 수 있다 . 공통 교육과정 57(6) 매체", "subject": "국어", "gradeGroup": "중1~3", "area": "읽기", "verb": "능력", "textLen": 36, "hasExp": true, "explanation": "진로나 관심 분야에 대한 다양한 책이나 자료를 스스로 찾아 읽는다 ."}, {"id": 105, "code": "[9국02-08]", "text": "자신의 독서 상황과 수준에 맞는 글을 선정하고 읽기 과정을 점검 ⋅조정하며 읽는다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "읽기", "verb": "기타", "textLen": 47, "hasExp": false}, {"id": 106, "code": "[9국03-01]", "text": "대상의 특성에 적합한 설명 방법을 활용하여 글을 쓴다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "기타", "textLen": 31, "hasExp": true, "explanation": "이 성취기준은 대상의 특성에 적합한 설명 방법을 활용하여 독자가 이해하기 쉬운 글을 쓰는 데에 필요한 능력을 기르기 위해 설정하였다 . 대상과 관련한 독자의 배경지식 및 관심 고려하기 , 정의, 인과, 분석, 분류 등 다양한 설명 방법을 익히고 전달하고자 하는 정보의 특성을 고려하여 설명 방법 활용하기 , 대상의 특성을 효과적으로 전달하기 위한 글의 구조 및 표현 방법 이해하기 등을 학습한다 ."}, {"id": 107, "code": "[9국03-02]", "text": "복수의 자료를 활용하여 다양한 형식으로 정보를 전달하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "기타", "textLen": 38, "hasExp": true, "explanation": "이 성취기준은 둘 이상의 자료를 활용하여 다양한 형식으로 보고서나 설명문 을 쓰는 데에 필요한 능력을 기르기 위해 설정하였다 . 객관적인 정보의 공유와 소통을 위해 다양한 정보를 담고 있는 복수의 자료 활용하기 , 정보를 전달하는 글의 내용을 생성하는 과정 에서 책 , 신문, 인터넷 등 다양한 매체에서 정보 수집하기 , 수집한 정보의 중요도 분석하기 , 수집한 정보 통합하기 , 쓰기 윤리를 지키며 자료 활용하기 , 문자 언어와 함께 도표 , 그림, 사진 등을 활용하여 정보를 전달하기 등을 학습한다 ."}, {"id": 108, "code": "[9국03-03]", "text": "주장을 뒷받침할 수 있는 타당한 근거를 들고 적절한 표현을 사용하여 주장하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "기타", "textLen": 50, "hasExp": false}, {"id": 109, "code": "[9국03-04]", "text": "의견 차이가 있는 사안에 대해 자료를 수집하고 사회 ⋅문화적 맥락을 고려하며 주장하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "기타", "textLen": 55, "hasExp": true, "explanation": "이 성취기준은 의견 차이가 있는 사안이 발생한 상황을 이해하고 쟁점을 분석 하여 자신의 주장을 제시하는 글을 쓰는 데에 필요한 능력을 기르기 위해 설정하였다 . 의견 차이가 있는 사안 찾기 , 쟁점을 분석하고 쟁점에 대한 다양한 의견과 자료를 수집하기 , 쟁 점에 대한 자신의 관점을 수립하여 주장을 논리적으로 전개하기 , 자신의 주장이 사회 ⋅문 화적 맥락 내에서 수용될 수 있도록 제시하기 등을 학습한다 . 국어과 교육과정 50"}, {"id": 110, "code": "[9국03-05]", "text": "자신의 삶과 경험을 바탕으로 정서를 진솔하게 표현하는 글을 쓴다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "기타", "textLen": 37, "hasExp": false}, {"id": 111, "code": "[9국03-06]", "text": "다양한 표현을 활용하여 자신의 생각과 느낌이 드러나는 글을 쓰고 독자와 공유한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "행위", "textLen": 46, "hasExp": false}, {"id": 112, "code": "[9국03-07]", "text": "복합양식 자료를 활용하여 내용을 생성하고 글의 유형을 고려하여 내용을 조직하며 글을 쓴다.", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "기타", "textLen": 50, "hasExp": true, "explanation": "이 성취기준은 글을 쓸 때 복합양식 자료를 활용하여 내용을 생성하고 글의 유형을 고려하여 내용을 조직하는 능력을 기르기 위해 설정하였다 . 문자, 소리, 그림, 사진, 동영상 등이 결합된 복합양식 자료의 특징 및 유형 이해하기 , 복합양식 자료를 활용하여 내 용 생성하기 , 글의 유형을 고려하여 내용 조직하기 등을 학습한다 ."}, {"id": 113, "code": "[9국03-08]", "text": "쓰기 과정과 전략을 점검 ⋅조정하며 글을 쓰고 , 독자를 고려하여 글을 고쳐 쓴다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "기타", "textLen": 47, "hasExp": true, "explanation": "이 성취기준은 쓰기 과정과 전략을 점검 ⋅조정하며 글을 쓰고 독자를 고려하여 글을 고쳐 쓰는 데에 필요한 능력을 기르기 위해 설정하였다 . 독자를 고려하여 글을 고쳐 쓰는 것은 글의 내용 차원 , 조직 차원 , 표현 차원에서 두루 이루어질 필요가 있다 . 쓰기 과정과 전략을 점검 ⋅조정하기 , 독자의 지식 , 기대나 요구 , 태도를 분석하기 , 독자 분석의 결과를 반영하여 글을 고쳐쓰기 등을 학습한다 ."}, {"id": 114, "code": "[9국03-09]", "text": "언어 공동체의 구성원인 필자로서 자신에 대해 성찰하며 , 윤리적 소통 문화를 형성하는 데에 기여한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "쓰기", "verb": "행위", "textLen": 57, "hasExp": true, "explanation": "이 성취기준은 필자가 자신과 자신의 쓰기 과정 및 결과를 성찰하여 언어 공 동체의 구성원으로 성장하는 데에 필요한 능력과 태도를 기르기 위해 설정하였다 . 필자로서 자기 자신이 어떤 사람인지 필자 정체성 성찰하기 , 언어 공동체의 개념 이해하기 , 윤리적 소통 문화의 특성과 필요성 이해하기 , 책임감 있게 글을 쓰는 태도 기르기 등을 학습한다 ."}, {"id": 115, "code": "[9국04-01]", "text": "국어의 음운 체계와 문자 체계를 이해하고 국어생활에 활용한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문법", "verb": "행위", "textLen": 35, "hasExp": true, "explanation": "이 성취기준은 국어의 음운 체계와 문자 체계를 종합적으로 탐구함으로써 , 말 소리와 문자의 관련성을 체계적으로 이해하도록 하기 위해 설정하였다 . 말소리와 음운의 관계, 음운 체계에 대한 이해를 바탕으로 발음 및 표기를 정확하게 할 수 있도록 한다 . 이와 관련지어 훈민정음 창제 정신과 원리를 중심으로 국어의 문자 체계를 탐구하고 , 디지털 ⋅ 정보화 시대에 한글이 지니는 가치 및 발전 방향을 다각도로 탐색하도록 한다 ."}, {"id": 116, "code": "[9국04-02]", "text": "단어의 짜임을 분석하여 새말 형성의 원리를 이해한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문법", "verb": "행위", "textLen": 30, "hasExp": false}, {"id": 117, "code": "[9국04-03]", "text": "품사의 종류와 특성을 이해하고 국어 자료를 분석한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문법", "verb": "행위", "textLen": 30, "hasExp": true, "explanation": "이 성취기준은 품사의 종류와 특성을 이해하고 이를 바탕으로 다양한 국어 자 료를 분석할 수 있는 능력을 기르기 위해 설정하였다 . 품사 분류를 통해 우리말에 대한 이 해의 폭을 넓힘은 물론 품사의 특성을 고려해 정확하고 적절하게 단어를 사용할 수 있도록 한다 . 또한, 문장을 단어별로 나누어 문장 안에서의 쓰임을 분석하거나 , 글이나 담화에 쓰 인 단어의 정확성 ⋅적절성을 평가하거나 , 단어 부류의 빈도나 분포에 따라 글이나 담화의 특성을 간략히 기술하는 등 , 품사 지식을 활용해 국어 자료의 특성을 간단히 분석해 봄으로 써 품사가 국어 탐구를 위한 기초적이고 유용한 도구임을 이해하도록 한다 ."}, {"id": 118, "code": "[9국04-04]", "text": "문장의 짜임을 이해하고 표현 효과를 고려하여 문장을 구성한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문법", "verb": "행위", "textLen": 35, "hasExp": false}, {"id": 119, "code": "[9국04-05]", "text": "피동 표현과 인용 표현의 의도와 효과를 분석하고 상황에 맞게 활용한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문법", "verb": "행위", "textLen": 40, "hasExp": true, "explanation": "이 성취기준은 피동 표현과 인용 표현을 활용해 의도를 정확하고 적절하게 표 현하고 , 그 효과를 분석하는 능력을 기르기 위해 설정하였다 . 피동 표현과 인용 표현의 형 식적 특성과 기능 , 표현 효과를 학습하는 데 중점을 둔다 . 피동 표현과 인용 표현의 사용을 표현 의도와 관련지어 이해하고 , 그 효과를 분석하여 실제 국어생활에서 상황 맥락에 맞게 적절하게 활용할 수 있도록 한다 . 공통 교육과정 53"}, {"id": 120, "code": "[9국04-06]", "text": "한글 맞춤법의 기본 원리와 내용을 이해하고 국어생활에 적용한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문법", "verb": "행위", "textLen": 36, "hasExp": true, "explanation": "이 성취기준은 한글 맞춤법의 기본 원리를 이해하여 정확하고 교양 있는 국어 생활을 영위하도록 하기 위해 설정하였다 . ‘공통국어 2’의 한글 맞춤법 관련 성취기준에서 내용이 심화 ⋅연계됨을 고려하여 , ‘소리대로 적되 어법에 맞도록 함을 원칙으로 한다 .’라는 한글 맞춤법 총칙을 중심으로 한글 맞춤법의 기본 원리를 탐구하는 데 중점을 두고 , 음운 변동에 대한 지식을 필요로 하는 한글 맞춤법 조항 등은 다루지 않는다 ."}, {"id": 121, "code": "[9국04-07]", "text": "세대⋅분야⋅매체에 따른 어휘의 양상과 쓰임을 분석하고 다양한 집단과 사회의 언어에 관용적 태도를 지닌다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문법", "verb": "기타", "textLen": 59, "hasExp": true, "explanation": "이 성취기준은 세대 ⋅분야⋅매체에 따라 어휘가 변이되고 팽창하는 양상을 다 양한 국어 자료를 바탕으로 탐구하고 , 이를 바탕으로 다양한 집단과 사회의 언어에 대해 관 용적 태도를 지니도록 하기 위해 설정하였다 . 어휘는 언어 사용의 구체적인 맥락과 세대 , 분야, 매체 등의 요인에 따라 다양한 양상으로 나타난다 . 청소년어 , 노인어 , 전문어 , 인터넷 언어, 새말 등을 대상으로 어휘의 특성과 쓰임 , 변이와 생성 과정에 대한 탐구를 통해 , 이 들 어휘를 중심으로 한 언어 실천이 상황 맥락 및 사회 ･문화적 맥락을 고려한 사회적 행위 임을 이해하고 다양한 집단과 사회의 언어에 대해 관용적 태도를 견지할 수 있도록 한다 ."}, {"id": 122, "code": "[9국04-08]", "text": "자신과 주변의 다양한 국어 실천 양상을 비판적으로 분석하여 언어와 자아 및 세계 사이의 관계를 인식한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문법", "verb": "행위", "textLen": 59, "hasExp": true, "explanation": "이 성취기준은 다양한 국어 자료에 대한 분석과 성찰을 통해 언어의 본질과 힘을 인식하고 , 언어 주체로서 능동적인 국어생활을 영위하도록 하기 위해 설정하였다 . 욕 설이나 부정적 표현 및 말투 등이 개인의 정체성 형성에 미치는 영향을 분석하고 , 의도를 제대로 전달하지 못하는 표현 , 편견 및 고정 관념을 유발하거나 사실을 왜곡하는 표현 , 갈 등을 조장하거나 강화하는 표현 , 규범과 관습에 적절하지 않은 표현 등이 개인 간 관계 형 성 및 언어 공동체에 미치는 영향을 성찰하고 비판하여 , 언어가 자아 및 세계를 구성하는 핵심 자원임을 이해하도록 한다 ."}, {"id": 123, "code": "[9국05-01]", "text": "운율, 비유, 상징의 특성과 효과에 유의하며 작품을 감상하고 창작한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "행위", "textLen": 40, "hasExp": false}, {"id": 124, "code": "[9국05-02]", "text": "갈등의 진행과 해결 과정을 파악하며 작품을 감상한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "행위", "textLen": 30, "hasExp": false}, {"id": 125, "code": "[9국05-03]", "text": "인간의 성장을 다룬 작품을 읽으며 문학의 가치를 내면화한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "행위", "textLen": 34, "hasExp": false}, {"id": 126, "code": "[9국05-04]", "text": "보는 이나 말하는 이의 특성과 효과를 파악하며 작품을 감상한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "행위", "textLen": 36, "hasExp": true, "explanation": "이 성취기준은 시의 화자 또는 소설의 시점 및 서술자에 주목하여 작품을 깊이 있게 감상하는 능력을 기르게 하기 위해 설정하였다 . 문학 작품에서 누가 보는가 , 누가 말 하는가에 따라 전달하는 내용이나 작품의 분위기가 크게 달라진다 . 보는 이나 말하는 이가 누구인지 , 어떤 특성을 가지고 있는지를 파악하고 , 보는 이나 말하는 이의 특성이 작품 전 체의 주제나 분위기에 어떤 효과를 미치는가에 주목하며 작품을 감상하도록 한다 . 공통 교육과정 55"}, {"id": 127, "code": "[9국05-05]", "text": "작품에 반영된 사회 ⋅문화적 상황을 이해하며 작품을 감상한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "행위", "textLen": 35, "hasExp": false}, {"id": 128, "code": "[9국05-06]", "text": "자신의 경험을 개성적인 발상과 표현으로 형상화한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "행위", "textLen": 29, "hasExp": true, "explanation": ") 과 연계하여 지도할 수도 있다 . 카메라의 거리와 각도 , 자막 등 시각적 요소와 배경 음악이나 효과음 등 청각적 요소의 특성을 이해하고 , 내용에 맞게 장면을 구성하며 , 주제와 목적에 맞게 편집하여 영상 매체 자료를 제작하도록 한다 . •매체 소통 태도에 대한 학습에서 , 소통 참여자는 자신의 생각을 표현하고 존중받을 권리가 있다는 점 , 디지털 텍스트의 항존성 (디지털 발자국 ), 디지털 공간에서 매체 자료가 청중에게 미치는 영향 등을 고려해야 함을 이해하도록 한다 . 또한 매체 자료를 공유한 이후에도 수용 자의 반응을 살펴 자신의 매체 자료 제작 및 공유 과정을 성찰하도록 한다 . •매체 자료의 공정성을 평가하는 활동은 읽기 영역에서 복합양식으로 구성된 글이나 자료의 내용 타당성과 신뢰성 , 표현 방법의 적절성을 평가하며 읽는 활동 ("}, {"id": 129, "code": "[9국05-07]", "text": "연관성이 있는 다른 작품들과의 관계를 파악하며 작품을 감상한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "행위", "textLen": 36, "hasExp": true, "explanation": "이 성취기준은 작품들 간의 관계에 주목하며 작품을 감상할 수 있게 하기 위 해 설정하였다 . 다른 문학 작품들과의 관계 속에서 작품을 다각도로 살핀다면 독자는 작품 에 대해 더 다양하고 깊이 있는 감상이 가능해진다 . 통시적 ⋅공시적으로 유사한 주제나 형 식을 가진 작품들 , 서로 영향을 주고받은 작품들을 찾아보고 , 작품 간의 공통점 및 차이점 , 상호 간의 연관 관계를 파악하며 작품을 감상하도록 한다 . 또한 학습자가 스스로 여러 작품 간의 관계를 찾아 새로운 의미 연관성의 맥락을 만들어 볼 수 있도록 한다 ."}, {"id": 130, "code": "[9국05-08]", "text": "근거를 바탕으로 작품을 해석하고 , 다른 해석들과 비교하여 자신의 해석을 평가한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "이 성취기준은 주체적인 관점에서 작품을 해석하며 평가할 수 있는 능력을 기 르게 하기 위해 설정하였다 . 작품을 해석할 때는 작품 속의 내용적 ⋅형식적 근거나 작품 밖의 맥락적 근거 등을 토대로 하여 작품을 해석하는 것이 필요하다 . 작품 해석은 독자의 지식, 경험, 가치관 등을 바탕으로 이루어지는 과정이기 때문에 독자에 따라 얼마든지 달라 질 수 있다 . 다만 이때 작품을 잘못 이해하는 오독을 범하지 않으려면 작품 안과 밖의 여러 근거를 바탕으로 작품을 해석해야 한다 . 적절한 근거를 들어 작품을 해석하고 , 이를 다른 사람들의 해석과 비교하면서 자기 해석의 적절성을 검토하도록 한다 ."}, {"id": 131, "code": "[9국05-09]", "text": "문학을 통해 타자를 이해하고 공동체의 문제에 참여하는 태도를 지닌다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "문학", "verb": "기타", "textLen": 39, "hasExp": true, "explanation": "이 성취기준은 내가 아닌 다른 사람들 , 그리고 다른 존재들을 이해하고 , 그들 에 공감하는 능력을 기르며 , 그들과 어떻게 함께 살아갈 것인가를 공동체의 관점에서 고려 하고, 공동체의 현안에 참여하는 태도를 가지게 하기 위해 설정하였다 . 타자를 이해하는 능 력은 평화로운 공존과 협력적 연대를 위한 핵심적 요인이다 . 작품 속 인물들의 생각과 마음 을 이해하고 다양한 삶을 간접적으로 체험하도록 함으로써 타자에 대한 이해와 공감의 폭 을 넓힐 수 있도록 한다 . 또한 가정 , 학교, 이웃 사회 , 생태환경 등 다양한 공동체의 문제와 그 해결 과정을 담은 작품을 읽고 , 학습자가 속한 공동체의 문제에 대한 인식 능력과 실천 적 참여 능력을 함양하도록 한다 ."}, {"id": 132, "code": "[9국06-01]", "text": "대중매체와 개인 인터넷 방송의 특성과 영향력을 비교한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "매체", "verb": "행위", "textLen": 32, "hasExp": false}, {"id": 133, "code": "[9국06-02]", "text": "소통 맥락과 수용자 참여 양상을 고려하여 상호 작용적 매체를 분석한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "매체", "verb": "행위", "textLen": 40, "hasExp": true, "explanation": "이 성취기준은 상호 작용적 매체의 특성을 이해하고 상황 맥락과 사회 ⋅문화 적 맥락에 맞게 소통하는 능력을 기르기 위해 설정하였다 . 예를 들어 사회 관계망 서비스 (SNS) 는 생각 , 의견, 관점 등을 비교적 자유롭게 공유할 수 있는 개방적인 공간이며 , 학교 나 학급의 누리집은 공적인 정보를 공유하는 데 초점을 둔 공간이다 . 이처럼 소통 목적 , 소 통 공간의 특성에 따라 참여자들이 소통하는 방식이 어떻게 달라지는지 다양한 각도에서 분석해 보고 자신의 소통 방식의 적절성에 대해서도 점검해 보도록 한다 ."}, {"id": 134, "code": "[9국06-03]", "text": "복합양식성을 고려하여 영상 매체 자료를 제작하고 공유한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "매체", "verb": "행위", "textLen": 33, "hasExp": false}, {"id": 135, "code": "[9국06-04]", "text": "매체 소통에서의 권리와 책임을 이해하고 , 수용자의 반응을 고려하며 매체 자료의 제작 과정을 성찰한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "매체", "verb": "행위", "textLen": 58, "hasExp": false}, {"id": 136, "code": "[9국06-05]", "text": "매체 자료의 재현 방식을 이해하고 광고나 홍보물을 분석한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "매체", "verb": "행위", "textLen": 34, "hasExp": true, "explanation": "이 성취기준은 매체 텍스트가 현실을 재현하는 방식을 이해하는 능력을 기르 기 위해 설정하였다 . 매체 자료는 제작자의 의도와 관점이 반영된 재현물이라는 것에 대한 이해를 바탕으로 다양한 광고나 홍보물을 살펴보며 사건 , 쟁점, 인물 등을 표현하기 위해 어떤 문구나 이미지가 선택되거나 배제되었는지를 탐구하고 , 사회상이나 특정 집단에 대해 어떤 고정 관념이 반영되어 있는지 분석하도록 한다 ."}, {"id": 137, "code": "[9국06-06]", "text": "사회⋅문화적 맥락을 고려하여 매체 자료의 공정성을 평가한다 .", "subject": "국어", "gradeGroup": "중1~3", "area": "매체", "verb": "행위", "textLen": 34, "hasExp": true, "explanation": "이 성취기준은 매체 자료를 공정성의 측면에서 비판적으로 이해하는 능력을 기르기 위해 설정하였다 . 타당하고 신뢰성 있는 정보라 하더라도 그것이 의도에 따라 과도 하게 반복 , 과장, 축소되어 전달되는 경우에는 공정한 매체 자료라고 보기 어렵다 . 특정 사 건이나 쟁점을 다루는 매체 자료를 비교하고 , 그 매체 자료가 제작된 사회 ⋅문화적 맥락이 어떠한지 파악한다 . 그리고 매체 자료가 특정 제품이나 업체를 홍보하고 있지는 않은지 , 다 양한 주장을 전달하지 않고 특정 입장을 지닌 주장을 전달하면서 한쪽으로 치우쳐 있지는 않은지 , 피상적인 사실 전달에 그쳐 특정한 쟁점이나 사건에 대한 진실을 간과하거나 호도 하고 있지는 않은지 등을 점검한다 ."}, {"id": 138, "code": "[4도01-01]", "text": "자신의 감정을 소중히 여기며 존중하는 태도를 바탕으로 내가 누구인가를 탐구한다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "자신과의 관계", "verb": "행위", "textLen": 45, "hasExp": false}, {"id": 139, "code": "[4도01-02]", "text": "정직의 의미를 알고 모범적인 사례를 탐색하여 바르게 행동하려는 태도를 기른다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "자신과의 관계", "verb": "태도", "textLen": 44, "hasExp": false}, {"id": 140, "code": "[4도01-03]", "text": "성실한 생활의 모범 사례를 탐색하고 시간 관리를 위한 생활을 계획하여 지속적인 자기 성장을 모색한다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "자신과의 관계", "verb": "행위", "textLen": 57, "hasExp": false}, {"id": 141, "code": "[4도01-04]", "text": "다른 사람의 관점을 수용할 수 있는지를 도덕적으로 검토하고 도덕규범을 내면화하여 도덕적으로 행동할 수 있는 자세를 기른다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "자신과의 관계", "verb": "태도", "textLen": 69, "hasExp": false}, {"id": 142, "code": "[4도02-01]", "text": "효, 우애의 의미와 필요성을 명료하게 이해하고 가족의 행복을 위해 할 수 있는 일을 탐색 하여 실천 계획을 세운다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "타인과의 관계", "verb": "기타", "textLen": 65, "hasExp": false}, {"id": 143, "code": "[4도02-02]", "text": "친구 사이의 배려에 대한 올바른 이해를 바탕으로 일상생활에서 배려에 기반한 도덕적 관계를 맺을 수 있는 방안을 탐색한다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "타인과의 관계", "verb": "행위", "textLen": 68, "hasExp": false}, {"id": 144, "code": "[4도02-03]", "text": "공감의 태도가 필요한 이유를 이해하고 도덕적 상상력을 바탕으로 대상과 상황에 따라 감정을 나누는 방법을 탐구하여 실천한다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "타인과의 관계", "verb": "행위", "textLen": 69, "hasExp": false}, {"id": 145, "code": "[4도03-01]", "text": "불공정의 사례를 탐구하고 , 일상생활에서 공정의 가치를 추구하는 활동을 통해 실천 의지를 함양한다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "사회·공동체와의 관계", "verb": "행위", "textLen": 56, "hasExp": true, "explanation": "이 성취기준의 취지는 학생이 자신의 삶에서 공정이라는 가치에 관해 성찰하는 기회를 갖도록 하여 공정한 사회로 발전해가는 토대를 마련하려는 것이다 . 학생이 공정과 불공정의 사례를 스스로 탐구하고 일상에서 공정을 실제로 추구하는 활동을 실천함으로써 공정의 가치를 생활화할 수 있도록 한다 ."}, {"id": 146, "code": "[4도03-02]", "text": "디지털 사회에서 발생하는 다양한 문제를 살펴보고 , 해결 방안을 탐구하여 정보통신 윤리에 대한 민감성을 기른다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "사회·공동체와의 관계", "verb": "태도", "textLen": 63, "hasExp": false}, {"id": 147, "code": "[4도03-03]", "text": "통일의 필요성을 이해하고 , 통일 감수성을 길러 바람직한 통일의 방향을 모색한다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "사회·공동체와의 관계", "verb": "행위", "textLen": 46, "hasExp": false}, {"id": 148, "code": "[4도04-01]", "text": "생명 경시 사례를 조사하고 문제 해결 방법을 탐구함으로써 생명의 소중함을 이해한다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "자연·초월과의 관계", "verb": "행위", "textLen": 47, "hasExp": false}, {"id": 149, "code": "[4도04-02]", "text": "인간과 자연이 함께 살아야 하는 이유를 이해하고 공생을 위한 구체적인 실천 계획을 세우며 생태 감수성을 기른다 .", "subject": "도덕", "gradeGroup": "초3~4", "area": "자연·초월과의 관계", "verb": "태도", "textLen": 63, "hasExp": true, "explanation": "이 성취기준의 취지는 학생이 일상에서 자연스럽게 생태 감수성과 생태전환적 사고에 따라 실천하도록 하기 위한 것이다 . 생태전환과 관련된 도덕적 쟁점을 마주할 때 단순히 생태 체험에만 그치지 않고 , 인간중심 사고에서 벗어나 자연과의 공존을 위한 생각 과 행동의 변화까지 모색한다 ."}, {"id": 150, "code": "[6도01-01]", "text": "자주적인 삶에 대한 이해를 바탕으로 자신의 생활계획을 세우고 실천하여 주체적인 삶의 태도를 기른다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "자신과의 관계", "verb": "태도", "textLen": 56, "hasExp": false}, {"id": 151, "code": "[6도01-02]", "text": "생활 습관에 대한 성찰을 통해 자기 생활을 점검하고 올바른 계획을 세워 이를 실천한다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "자신과의 관계", "verb": "행위", "textLen": 49, "hasExp": true, "explanation": "이 성취기준의 취지는 자신의 행동에 대한 문제점을 확인하고 재정립하도록 하여 반성하는 태도를 기르기 위한 것이다 . 학생이 스스로 자기 행동의 문제를 인식하고 개선하려 노력함으로써 바른 도덕 생활의 토대를 마련하도록 한다 ."}, {"id": 152, "code": "[6도01-03]", "text": "자기가 하고 싶은 일을 선택할 때 도덕적 고려의 필요성을 알고 자신의 특기와 적성을 탐색하여 진로계획을 수립한다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "자신과의 관계", "verb": "행위", "textLen": 64, "hasExp": false}, {"id": 153, "code": "[6도02-01]", "text": "봉사의 의미와 중요성을 이해하고 , 타인이 처한 상황과 환경에 대한 주의 깊은 관심을 바탕으로 봉사를 실천한다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "타인과의 관계", "verb": "행위", "textLen": 63, "hasExp": true, "explanation": "이 성취기준의 취지는 봉사의 의미와 중요성을 지식적으로만 이해하는 것에 그치지 않고 타인의 환경에 대한 관심을 바탕으로 생활 속에서 자연스럽게 봉사를 실천할 수 있는 역량을 함양하기 위한 것이다 . 타인을 위한 봉사 경험을 통해 학생에게 진정한 이 타심과 봉사 의지를 다지고 고양할 기회를 제공하도록 한다 ."}, {"id": 154, "code": "[6도02-02]", "text": "편견이 발생하는 이유를 탐색하여 해결 방안을 살펴보고 , 다양성 존중을 바탕으로 다른 사람과 올바른 관계를 맺기 위한 실천 방안을 탐구한다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "타인과의 관계", "verb": "행위", "textLen": 79, "hasExp": false}, {"id": 155, "code": "[6도02-03]", "text": "인간과 인공지능 로봇 간의 다양한 관계를 파악하고 도덕에 기반을 둔 관계 형성의 필요 성을 탐구한다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "타인과의 관계", "verb": "행위", "textLen": 57, "hasExp": false}, {"id": 156, "code": "[6도03-01]", "text": "인권과 관련된 다양한 사례를 살펴보고 인권에 관한 감수성을 길러 이를 실천하려는 의지를 함양한다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "사회·공동체와의 관계", "verb": "행위", "textLen": 55, "hasExp": false}, {"id": 157, "code": "[6도03-02]", "text": "정의에 관한 관심을 토대로 공동체 규칙의 중요성을 살펴보고 직접 공정한 규칙을 고안 하며 기초적인 시민의식을 기른다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "사회·공동체와의 관계", "verb": "태도", "textLen": 66, "hasExp": false}, {"id": 158, "code": "[6도03-03]", "text": "통일과정과 통일 이후 사회의 여러 가지 상황을 예상하고 바람직한 통일과정과 통일 국가의 사회상을 제시한다", "subject": "도덕", "gradeGroup": "초5~6", "area": "사회·공동체와의 관계", "verb": "행위", "textLen": 58, "hasExp": false}, {"id": 159, "code": "[6도03-04]", "text": "다른 나라 사람들이 처한 여러 가지 상황을 종합적으로 이해하고 해결 방안을 탐구하며 인류애를 기른다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "사회·공동체와의 관계", "verb": "태도", "textLen": 57, "hasExp": false}, {"id": 160, "code": "[6도04-01]", "text": "지구의 환경 위기 상황을 이해하고 , 이를 극복하기 위한 다양한 방안을 찾아 자신의 일 상에서 실천하고자 노력한다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "자연·초월과의 관계", "verb": "행위", "textLen": 65, "hasExp": false}, {"id": 161, "code": "[6도04-02]", "text": "지속가능한 삶의 의미를 탐구하고 미래 세대에 대한 책임을 강화하여 자연의 다양성을 존중하고 생산성을 유지할 수 있는 미래를 위한 실천 방안을 찾는다 .", "subject": "도덕", "gradeGroup": "초5~6", "area": "자연·초월과의 관계", "verb": "기타", "textLen": 84, "hasExp": false}, {"id": 162, "code": "[9도01-01]", "text": "자신의 삶과 가치관에 대한 성찰을 통해 자아를 올바로 이해하고 , 삶에서 도덕이 필요한 이유에 근거하여 도덕적인 삶에 대한 의지를 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자신과의 관계", "verb": "태도", "textLen": 78, "hasExp": false}, {"id": 163, "code": "[9도01-02]", "text": "일상에서 발생하는 부도덕한 행동의 여러 원인을 분석하고 , 도덕적 인격이 갖추어야 할 특성들을 파악하여 이를 내면화하는 의지를 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자신과의 관계", "verb": "태도", "textLen": 76, "hasExp": true, "explanation": "이 성취기준의 취지는 일상의 부도덕한 행동들이 옳고 그름을 분별하지 못하는 무지뿐만 아니라 자기정당화 기제를 포함한 도덕 심리학적 원인에서 비롯될 수 있음을 파악하고 , 이러한 부도덕한 행동의 원인을 극복한 훌륭한 인격자의 도덕적 특성들을 탐구함 으로써 도덕적 인격이 갖춰야 할 도덕성의 구성요소를 내면화하는 의지를 기르는 것이다 . "}, {"id": 164, "code": "[9도01-03]", "text": "행복에 관한 심리적 , 사회적 , 윤리적 접근 등을 통해 행복의 의미를 종합적으로 파악하고 , 삶의 목적과 행복의 관계를 정립할 수 있다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자신과의 관계", "verb": "능력", "textLen": 78, "hasExp": false}, {"id": 165, "code": "[9도01-04]", "text": "옳고 그름을 분별할 수 있는 도덕적 기준을 탐구하고 , 도덕적 상상력을 바탕으로 일상의 도덕 문제들에 도덕적 추론을 적용할 수 있다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자신과의 관계", "verb": "능력", "textLen": 75, "hasExp": true, "explanation": "이 성취기준의 취지는 동양과 서양의 주요한 규범윤리 이론들을 탐구하고 , 일 상의 도덕적 문제 상황에서 상대방의 감정에 공감하면서 다양한 대안을 탐색하는 도덕적 상상력과 도덕원리와 법칙에 근거하여 도덕 판단을 도출하는 도덕적 추론능력을 기르는 것이다 . "}, {"id": 166, "code": "[9도01-05]", "text": "삶의 유한함에 관한 성찰을 통해 생명의 소중함과 의미 있는 삶의 중요성을 인식하고 , 자신의 미래 모습을 상상하며 삶을 계획하고 이를 실천하는 의지를 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자신과의 관계", "verb": "태도", "textLen": 89, "hasExp": false}, {"id": 167, "code": "[9도01-06]", "text": "내면에 대한 성찰을 통해 심리적 고통과 불안 , 우울감 등의 원인을 찾고 , 마음의 평온을 얻을 수 있는 방안들을 다각적으로 모색하여 실천할 수 있다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자신과의 관계", "verb": "능력", "textLen": 85, "hasExp": true, "explanation": "이 성취기준의 취지는 학생들이 경험하는 정신적 혼란과 심리적 스트레스의 다양한 원인을 파악하고 , 이를 극복하는 데 도움이 되는 방법들을 익힘으로써 자기 관리 및 조절 능력과 회복탄력성을 기르고 진정한 마음의 평화를 얻는 것이다 . "}, {"id": 168, "code": "[9도01-07]", "text": "삶에서 직업이 갖는 의미와 가치를 파악하며 , 사례 탐구를 통해 직업적 양심과 직업윤리의 필요성을 정당화할 수 있다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자신과의 관계", "verb": "능력", "textLen": 66, "hasExp": true, "explanation": "이 성취기준의 취지는 학생들이 직업의 가치를 개인적 , 사회적 측면에서 탐색 하고, 직업적 양심과 직업윤리의 중요성을 파악함으로써 자신이 희망하는 진로와 직업 세 계의 직업윤리를 구성하는 것이다 . 도덕과 교육과정 16"}, {"id": 169, "code": "[9도02-01]", "text": "정서적 , 배려적 공동체로서 가정의 특성과 도덕적 기능을 파악하고 , 가정에서 발생하는 갈등을 공감적인 소통과 민주적인 과정을 통해 해소하는 의지를 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "타인과의 관계", "verb": "태도", "textLen": 88, "hasExp": false}, {"id": 170, "code": "[9도02-02]", "text": "친구의 의미와 가치를 삶의 맥락 속에서 탐구하고 , 서로를 인격적으로 존중하는 친구 관 계를 상상하며 이를 실현하는 의지를 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "타인과의 관계", "verb": "태도", "textLen": 74, "hasExp": false}, {"id": 171, "code": "[9도02-03]", "text": "가상공간과 현실 세계에 대한 비교 ⋅분석을 바탕으로 가상공간에서 발생하는 도덕 문제들의 원인과 해결 방안을 제안하고 , 타인을 존중하며 가상공간을 활용하는 태도를 함양한다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "타인과의 관계", "verb": "행위", "textLen": 97, "hasExp": true, "explanation": "이 성취기준의 취지는 학생들이 삶에서 접하는 다양한 유형의 가상공간이 지니는 특성들을 현실 세계와 비교하여 분석하고 , 이를 바탕으로 가상공간에서 일어나는 도덕적 문제의 원인과 해결 방안을 탐구하도록 하는 것이다 . 이를 통해 일상화된 가상공간을 올바로 활용할 수 있는 디지털 문해력의 함양을 지향하는 것이다 . 공통 교육과정 17"}, {"id": 172, "code": "[9도02-04]", "text": "인간을 관계적 존재로 해석할 수 있는 이유에 근거하여 타인과의 관계에서 필요한 가치 ⋅ 덕목을 탐구하고 , 타인의 생각과 감정에 공감하는 태도를 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "타인과의 관계", "verb": "태도", "textLen": 86, "hasExp": true, "explanation": "이 성취기준의 취지는 학생들이 인간을 관계적 존재로 보는 동양과 서양의 윤 리적 관점에 근거하여 자신이 맺고 있는 다양한 관계에서 필요한 도덕적 가치와 덕목들을 탐구하고 , 그러한 가치와 덕목들에 근거하여 자신의 삶을 성찰하도록 하는 것이다 . 이를 통 해 타인의 생각과 감정을 공유하며 협력할 수 있는 공감 능력의 함양을 지향하는 것이다 ."}, {"id": 173, "code": "[9도02-05]", "text": "다양한 갈등 상황을 평화적으로 해결할 수 있는 방안을 모색하고 , 폭력의 유형과 원인 , 결과에 대한 분석을 바탕으로 일상의 폭력 상황에 대한 대처 능력을 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "타인과의 관계", "verb": "태도", "textLen": 92, "hasExp": false}, {"id": 174, "code": "[9도02-06]", "text": "청소년기의 바람직한 성윤리를 탐구하여 내면화하고 , 사회⋅문화적 차원에서 성의 의미를 파악하여 성에 대한 편견의 문제점을 분석하고 이를 바로잡는 의지를 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "타인과의 관계", "verb": "태도", "textLen": 90, "hasExp": false}, {"id": 175, "code": "[9도03-01]", "text": "인권을 존중해야 하는 도덕적 이유를 정당화하고 , 인권 침해 사례에 대한 탐구를 통해 그 원인과 해결 방안을 도출함으로써 인권 감수성을 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "사회·공동체와의 관계", "verb": "태도", "textLen": 81, "hasExp": false}, {"id": 176, "code": "[9도03-02]", "text": "외집단에 대한 편견을 비판적으로 분석하고 , 타문화 ⋅타종교 ⋅타인종을 존중해야 하는 이유에 근거하여 차이와 다양성에 대한 열린 마음을 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "사회·공동체와의 관계", "verb": "태도", "textLen": 81, "hasExp": true, "explanation": "이 성취기준의 취지는 학생들이 다양한 사례를 통해 외집단에 대한 편견을 분 석함으로써 암묵적인 내집단 편향을 비판적으로 인식하고 , 우리 사회가 다문화사회로 진입 하고 있다는 점을 바탕으로 다문화 가족 , 이주 노동자 , 난민 등과 관련하여 우리 사회가 직 면한 문제들을 탐구함으로써 타인종 , 타문화 , 타종교를 인정하고 존중하며 그들을 환대하 는 태도를 기르는 것이다 . "}, {"id": 177, "code": "[9도03-03]", "text": "북한에 대한 이해를 바탕으로 분단의 문제점을 분석하고 , 도덕적 가치에 기초하여 통일의 의미를 재구성함으로써 바람직한 남북관계 및 통일의 방향을 제안할 수 있다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "사회·공동체와의 관계", "verb": "능력", "textLen": 91, "hasExp": false}, {"id": 178, "code": "[9도03-04]", "text": "정의로운 사회를 상상해보고 , 이를 실현할 수 있는 정의의 원칙과 제도에 대한 다양한 의견들을 민주적인 방식으로 종합할 수 있다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "사회·공동체와의 관계", "verb": "능력", "textLen": 73, "hasExp": false}, {"id": 179, "code": "[9도03-05]", "text": "국가와 시민 사이에서 발생하는 윤리적 쟁점들을 탐구하고 , 국가와 시민 사이의 바람직한 관계에 기초하여 국가와 시민의 역할을 재구성할 수 있다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "사회·공동체와의 관계", "verb": "능력", "textLen": 81, "hasExp": false}, {"id": 180, "code": "[9도03-06]", "text": "인류의 고통에 공감하며 지구적 차원의 다양한 도덕 문제들을 탐구하고 , 해결 방안을 모색 하여 실천하는 자세를 갖는다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "사회·공동체와의 관계", "verb": "태도", "textLen": 67, "hasExp": false}, {"id": 181, "code": "[9도03-07]", "text": "현대 과학기술과 관련된 윤리적 쟁점의 분석을 통해 과학기술의 유용성과 한계를 인식하고 , 과학기술의 바람직한 활용에 관한 관심과 책임 의식을 기른다 . 도덕과 교육과정 18", "subject": "도덕", "gradeGroup": "중1~3", "area": "사회·공동체와의 관계", "verb": "태도", "textLen": 96, "hasExp": true, "explanation": "이 성취기준의 취지는 학생들이 인공지능 , 유전자 변형 , 생명공학을 활용한 인 간 향상 , 빅데이터 등 현대 과학기술의 발전으로 인해 새롭게 등장하는 윤리적 쟁점을 예 측하고 , 이에 대한 해결책을 찾는 탐구와 토론을 수행함으로써 과학기술의 윤리적 사용을 위해 갖추어야 할 바람직한 태도와 윤리적 책임감을 함양하는 것이다 ."}, {"id": 182, "code": "[9도04-01]", "text": "인간 이외의 생명체를 도덕적으로 고려해야 하는 이유를 정당화하고 , 생명을 가진 존재 들이 겪는 고통에 공감하며 생명을 소중히 여기는 태도를 기른다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자연·초월과의 관계", "verb": "태도", "textLen": 84, "hasExp": true, "explanation": "이 성취기준의 취지는 학생들이 가정에서 동물을 돌보거나 식물을 가꾸어 본 경험을 바탕으로 인간 이외의 생명체를 그 자체로 존중해야 하는 도덕적 이유를 추론해보고 , 공통 교육과정 19인간 이외의 생명체들이 겪는 고통과 위험에 민감하게 반응하며 생명을 소중히 여기는 태 도를 기르는 것이다 ."}, {"id": 183, "code": "[9도04-02]", "text": "자연에 대한 동양과 서양의 주요 입장들을 토대로 인간과 자연의 바람직한 관계를 도출 하고, 환경 위기에 대한 윤리적 책임을 구체화하여 실천할 수 있다 .", "subject": "도덕", "gradeGroup": "중1~3", "area": "자연·초월과의 관계", "verb": "능력", "textLen": 85, "hasExp": false}, {"id": 184, "code": "[4사01-01]", "text": "은 학생들의 생활이 이루어지는 주변 여러 장소에서의 경험과 느낌을 글, 그림, 심상지도 등의 다양한 방식으로 표현하고 , 이를 통해 사람마다 장소감의 차이가 나타날 수 있음을 이해하도록 설정한 것이다 . 장소감이란 장소에 대한 인지, 감정, 태도, 행동을 포괄 하는 것으로 개인이나 집단이 장소에 부여하는 의미나 관심을 뜻한다 . 장소 경험을 공유하 는 과정에서 장소감의 차이를 이해하고 서로 존중하며 , 주변의 장소를 알아가면서 이에 대 한 관심을 심화시키는 데 초점을 맞춘다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "지리 인식", "verb": "기타", "textLen": 269, "hasExp": false}, {"id": 185, "code": "[4사01-02]", "text": "는 학생들이 생활하는 데 편익을 제공하는 주요 장소 및 시설이나 기관을 살펴 보고, 우리가 사는 곳을 더 살기 좋은 곳으로 만드는 방안을 찾아보도록 설정한 것이다 . 특 히, 우리가 사는 곳의 놀이⋅여가, 안전, 교육⋅문화, 건강⋅의료 등과 관련 있는 장소를 조사하여 좋은 점, 불편한 점 등을 확인하고 , 학생들의 관점에서 살기 좋은 곳의 조건을 생 각하면서 우리가 사는 곳에 관심을 가지도록 하는 데 중점을 둔다.", "subject": "사회", "gradeGroup": "초3~4", "area": "지리 인식", "verb": "기타", "textLen": 233, "hasExp": false}, {"id": 186, "code": "[4사02-01]", "text": "일상 속에서 시간의 흐름을 경험할 수 있는 사례를 살펴보고 , 이를 바탕으로 역사의 시간 개념을 이해한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "자연환경과 인간 생활", "verb": "행위", "textLen": 60, "hasExp": true, "explanation": "은 시간을 표현하는 용어, 사건의 시간적 위치, 과거와 현재의 거리감 등을 통해 역사의 시간 개념을 이해하고 시간 감각을 키우는 데 중점을 둔다."}, {"id": 187, "code": "[4사02-02]", "text": "오래된 물건이나 자료들을 주변에서 찾아보고 , 이를 통해 과거의 모습을 살펴볼 수 있음을 이해한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "자연환경과 인간 생활", "verb": "행위", "textLen": 56, "hasExp": true, "explanation": "는 오래된 물건과 자료가 과거를 알려주는 증거임을 이해하고 , 이를 통해 역사가 증거를 바탕으로 구성된다는 것을 파악하는 데 중점을 둔다. •나와 가족, 학교 등에서 일어난 중요한 일을 조사하여 시간의 흐름에 따라 배열하고 옛 기록 이나 일기에서 시간 표현 용어를 찾아보는 등의 활동으로 역사의 시간 개념을 익힌다."}, {"id": 188, "code": "[4사02-03]", "text": "지역의 변화상을 보여주는 역사 자료를 분석하여 지역 사람들의 달라진 생활 모습을 파 악한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "자연환경과 인간 생활", "verb": "행위", "textLen": 52, "hasExp": true, "explanation": "은 지역 사람들의 달라진 생활 모습을 탐구하며 역사의 변화와 지속을 이해하 도록 설정한 것이다 . 지역의 유래와 관련된 이야기 , 지역의 변화를 알려주는 사진이나 영상 등 역사 자료를 활용하여 (변형되어 , 혹은 그대로) 이어져 내려온 것, 사라진 것을 찾아 지역 사람들의 생활이 어떻게 달라졌는지 살펴본다 . 공통 교육과정 21"}, {"id": 189, "code": "[4사03-01]", "text": "최근 사회 변화의 양상과 특징을 파악하고 , 그로 인해 나타난 생활모습의 변화를 탐색한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "인문환경과 인간 생활", "verb": "행위", "textLen": 51, "hasExp": true, "explanation": "은 사례를 통해 저출산 , 고령화 , 지능정보화 등 최근 사회 변화가 가져온 현상 과 특징을 파악하고 , 그로 인해 우리의 생활 모습이 어떻게 변화되는지 분석하도록 설정한 것이다 . 이를 통하여 사회 변화에 대응할 수 있는 역량을 기르는 데 초점을 맞추도록 한다."}, {"id": 190, "code": "[4사03-02]", "text": "우리 사회에 다양한 문화가 확산되면서 나타나는 긍정적 효과와 문제를 분석하고 , 나와 다른 사람이나 집단의 문화를 존중하는 태도를 기른다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "인문환경과 인간 생활", "verb": "태도", "textLen": 78, "hasExp": true, "explanation": "는 외국인 이주민의 증가, 1인 가구와 비혼, 반려동물 양육 등 다양한 문화가 확산⋅공유되면서 나타나는 긍정적 효과와 사회문제를 사례 또는 통계 자료를 통해 파악하 도록 설정한 것이다 . 이를 바탕으로 나와 다른 사람들의 삶의 방식이나 문화를 존중하는 태 도를 함양하는 데 초점을 맞춘다 . 사회과 교육과정 22"}, {"id": 191, "code": "[4사04-01]", "text": "옛날 풍습에 대해 알아보고 , 오늘날과 비교하여 변화상을 파악한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "지속가능한 세계", "verb": "행위", "textLen": 38, "hasExp": true, "explanation": "은 옛날의 다양한 풍습을 살펴보며 당시 사람들의 생활을 이해하고 , 오늘날과 비교하여 변화상을 파악하도록 설정한 것이다 . 놀이, 세시 풍속 등 여러 풍습을 통해 변화 상을 알아보고 풍습 속에 담긴 옛날 사람들의 생활과 생각을 이해한다 ."}, {"id": 192, "code": "[4사04-02]", "text": "옛날부터 오늘날까지 교통의 변화에 따른 이동과 생활 모습의 변화를 이해한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "지속가능한 세계", "verb": "행위", "textLen": 43, "hasExp": true, "explanation": "는 교통로 및 교통수단의 변화와 달라진 사람들의 생활 모습과의 관계를 이해 하도록 설정한 것이다. 시대에 따른 교통의 변화가 사람과 물자의 이동 및 생활 전반에 어떤 변화를 일으켰는지 살펴본다 . 그리고 교통 발달에 따른 생활공간의 확대를 고려하여 변화를 설명한다 ."}, {"id": 193, "code": "[4사04-03]", "text": "옛날부터 오늘날까지 통신수단의 변화에 따른 정보 교류와 의사소통 방식의 변화를 설명 한다.", "subject": "사회", "gradeGroup": "초3~4", "area": "지속가능한 세계", "verb": "기타", "textLen": 50, "hasExp": true, "explanation": "은 시대에 따른 통신수단의 변화 과정을 파악하고 이를 통해 달라진 사람들의 생활 모습을 파악하도록 설정한 것이다."}, {"id": 194, "code": "[4사05-01]", "text": "우리 지역을 표현한 다양한 종류의 지도를 찾아보고 , 지도의 요소를 이해한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "정치", "verb": "행위", "textLen": 44, "hasExp": true, "explanation": "은 우리 지역을 표현한 다양한 종류의 지도를 탐색하고 , 우리 지역의 지도를 활 용하여 방위, 기호와 범례, 축척, 높낮이 표현 방식 등 지도 제작에 필요한 요소를 파악하 도록 설정한 것이다 . 여기서는 지도의 요소를 이해하여 일상생활에서 지도를 활용하는 데 초점을 맞춘다 ."}, {"id": 195, "code": "[4사05-02]", "text": "에서의 우리 지역은 행정구역상 시⋅군⋅구 단위의 범위를 의미 한다.", "subject": "사회", "gradeGroup": "초3~4", "area": "정치", "verb": "기타", "textLen": 37, "hasExp": true, "explanation": "에서 우리 지역의 위치를 파악할 때는 시⋅도 단위의 행정구역 범위에서 위치를 찾아보고 , 우리 지역과 연접한 지역(시⋅군⋅구)도 확인할 수 있다. 또한 전국 시⋅ 도 단위의 행정구역을 파악함으로써"}, {"id": 196, "code": "[4사07-02]", "text": "생산과 소비 활동을 파악하고 , 인적⋅물적 교류의 사례를 통해 각 지역 및 사람들이 상호 의존 관계를 맺고 있음을 탐색한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "사회·문화", "verb": "행위", "textLen": 70, "hasExp": true, "explanation": "는 생산과 소비의 개념을 이해하고 , 한 지역의 생산과 소비 활동이 다른 지역과 상호의존 관계에 있음을 이해하도록 설정한 것이다 . 여기서는 지역에서 이루어지는 생산과 소비 활동의 사례를 통하여 한 지역의 경제활동이 다른 지역과 상호 의존 관계에 있다는 사실을 파악하는 데 초점을 맞춘다 ."}, {"id": 197, "code": "[4사07-01]", "text": "자원의 희소성으로 인해 경제활동에서 선택의 문제가 발생함을 이해하고 , 경제활동에서 합 리적 선택의 방법을 탐색한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "사회·문화", "verb": "행위", "textLen": 66, "hasExp": true, "explanation": "은 자원의 희소성 개념을 이해하고 , 이를 바탕으로 경제활동에서 합리적 선택의 방법을 파악하도록 설정한 것이다 . 여기서는 경제활동에서 선택의 문제가 발생하는 이유와 합리적 선택의 중요성을 이해하는 데 초점을 맞춘다 ."}, {"id": 198, "code": "[4사06-01]", "text": "지역의 문화유산을 통해 문화유산의 의미와 유형을 알아보고 , 문화유산의 가치를 탐색한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "경제", "verb": "행위", "textLen": 50, "hasExp": true, "explanation": "은 문화유산에 관한 기본 지식 및 가치를 지역의 문화유산을 통해 이해하도록 설정한 것이다 . 지역 문화유산을 통해 문화유산의 의미와 유형을 알아보고 , 이를 토대로 옛 날 사람들의 생활 모습을 추론하며 과거와 현재를 이어주는 귀중한 자료로서 문화유산의 가치를 파악한다 ."}, {"id": 199, "code": "[4사06-02]", "text": "지역의 박물관 , 기념관 , 유적지 등을 체험하고 지역의 역사를 이해한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "경제", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "는 지역에 있는 박물관, 기념관, 유적지 등을 방문하여 지역의 역사를 이해하기 위해 설정한 것이다 . 박물관 , 기념관 , 유적지 등을 온오프라인으로 방문하여 학생이 주도적 으로 지역의 역사에 관한 지식을 습득하고 해석하며 표현한다 . 그리고 지역의 역사를 보존 하고 실천하는 태도를 기른다 ."}, {"id": 200, "code": "[4사08-01]", "text": "학교 자치 사례를 통하여 민주주의의 의미를 이해하고 , 학교생활에서 민주주의를 실천하는 능력을 기른다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "역사", "verb": "태도", "textLen": 58, "hasExp": true, "explanation": "은 학교 자치 사례를 통해 민주주의의 의미를 이해하고 , 이를 바탕으로 학교생 활에서 학교 자치를 실천할 수 있도록 설정한 것이다 . 여기서는 학생이 학교 자치를 통해 민주주의를 실천하고 참여할 수 있는 능력을 기르는 데 초점을 맞춘다 ."}, {"id": 201, "code": "[4사08-02]", "text": "지역에서 이루어지는 민주주의 사례를 통해 주민 자치와 주민 참여의 중요성을 파악하고 , 지역사회의 문제 해결에 참여하는 태도를 기른다 . 사회과 교육과정 26", "subject": "사회", "gradeGroup": "초3~4", "area": "역사", "verb": "태도", "textLen": 88, "hasExp": true, "explanation": "는 민주주의의 의미에 기초하여 마을이나 지역에서 이루어지는 주민 자치와 참 여의 중요성을 파악하도록 설정한 것이다 . 여기서는 마을이나 지역사회에서 이루어지는 민 주주의의 사례를 통해 주민 자치와 주민 참여의 중요성을 이해하고 지역사회의 문제 해결에 관심을 갖고 참여하는 태도를 기르는 것에 초점을 맞춘다 ."}, {"id": 202, "code": "[4사09-01]", "text": "생활 주변에서 찾을 수 있는 여러 가지 문제를 파악하고 , 그 문제를 합리적으로 해결하는 능력을 기른다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "정치", "verb": "태도", "textLen": 59, "hasExp": true, "explanation": "은 각 지역에서 발생하는 문제를 민주적 방식으로 해결하는 과정과 방법을 습 득하도록 설정한 것이다 . 지리적 문제, 환경 문제, 사회적 문제, 역사적 문제 등 다양한 문 제를 찾아서 토론을 통해 합리적으로 해결하는 방법과 능력을 배우는 데 초점을 맞춘다 ."}, {"id": 203, "code": "[4사09-02]", "text": "지역의 자연환경 , 역사, 문화, 생산물 등을 알리려는 지역사회의 노력을 알고 관심을 갖는다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "정치", "verb": "태도", "textLen": 53, "hasExp": true, "explanation": "는 지역의 자연환경 , 역사, 문화, 생산물 등을 알리기 위한 여러 활동을 조사하 면서 지역을 이해하도록 설정한 것이다. 여기서는 지역의 자연환경 , 역사, 문화, 생산물 등을 살펴보고 , 지역에 관심을 가지며 , 지역사회에 참여하는 태도를 기르는 데 주안점을 둔다. 공통 교육과정 27"}, {"id": 204, "code": "[4사10-01]", "text": "여러 지역의 자연환경과 인문환경의 특징을 살펴보고 , 환경의 이용과 개발에 따른 변화를 탐구한다 .", "subject": "사회", "gradeGroup": "초3~4", "area": "지리 인식", "verb": "행위", "textLen": 55, "hasExp": true, "explanation": "은 우리 지역과 다른 자연환경 및 인문환경이 나타나는 곳을 살펴보고 , 환경의 이용과 개발로 변화한 모습을 탐구하도록 설정한 것이다 . 여기서는 다양한 환경 특성을 파 악하고 , 개발로 인해 나타난 긍정적 , 부정적 변화 모습을 균형 잡힌 관점으로 파악하는 데 중점을 둔다."}, {"id": 205, "code": "[4사10-02]", "text": "사례에서 도시의 인구, 교통, 산업 등의 특징을 탐구하고 , 도시에서의 삶의 모습을 이해 한다.", "subject": "사회", "gradeGroup": "초3~4", "area": "지리 인식", "verb": "기타", "textLen": 53, "hasExp": true, "explanation": "는 우리나라 여러 도시의 특징을 탐구하면서 도시에서 나타나는 삶의 모습을 종합적으로 이해하도록 설정한 것이다. 사례에서 도시의 경관, 인구, 교통, 산업, 생활방식의 특징을 이해하고 도시 생활의 좋은 점과 문제들을 파악하는 데 중점을 둔다. 사회과 교육과정 28"}, {"id": 206, "code": "[6사01-01]", "text": "우리나라 산지, 하천, 해안 지형의 위치를 확인하고 지형의 분포 특징을 탐구한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "지리 인식", "verb": "행위", "textLen": 46, "hasExp": true, "explanation": "은 우리나라 주요 산지, 하천, 해안 지형의 위치를 지도에서 확인하고 그 분포 특징을 파악하도록 설정한 것이다. 이를 바탕으로 국토 환경에 대한 기초적인 지식을 기르는 데 중점을 둔다."}, {"id": 207, "code": "[6사01-02]", "text": "독도의 지리적 특성과 독도에 대한 역사 기록을 바탕으로 영토로서 독도의 중요성을 이해 한다.", "subject": "사회", "gradeGroup": "초5~6", "area": "지리 인식", "verb": "기타", "textLen": 51, "hasExp": true, "explanation": "는 독도의 위치, 지형, 기후, 동식물 등의 지리적 특성을 파악하고 독도에 대한 역사 기록을 탐구하여 영토 주권 의식을 기르도록 설정한 것이다 . 이를 바탕으로 영토로서 독도의 가치를 인식하고 위상을 확인하는 데 주안점을 둔다."}, {"id": 208, "code": "[6사02-01]", "text": "우리나라의 계절별 기후 특징을 자료에서 탐구하고 , 기후변화로 인한 자연재해의 심각성을 이해한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "자연환경과 인간 생활", "verb": "행위", "textLen": 55, "hasExp": true, "explanation": "은 기후 그래프를 비롯해 디지털 영상 자료와 지도, 통계 자료, 사진 등 다양한 시각 자료를 활용하여 우리나라의 계절별 기후 특징을 기온, 강수, 바람의 측면에서 탐구하 도록 설정한 것이다 . 또한 기후변화로 자연재해가 심화하고 있음을 파악하고 기후 행동 등 에 참여하는 태도를 갖는 데 주안점을 둔다."}, {"id": 209, "code": "[6사02-02]", "text": "우리나라의 지역별 인구 분포의 특징을 알아보고 , 이에 따른 문제점과 해결 방안을 탐색 한다.", "subject": "사회", "gradeGroup": "초5~6", "area": "자연환경과 인간 생활", "verb": "기타", "textLen": 52, "hasExp": true, "explanation": "는 우리나라의 인구 분포 특징을 수도권 인구 집중과 관련한 자료를 중심으로 탐구하면서 인구 집중의 원인, 문제, 그리고 이를 해결하려는 노력을 알아보도록 설정한 것 이다. 이를 통해 인구 분포의 불균형과 인구 문제의 심각성을 이해하여 국토 균형 발전의 중요성을 인식하고 해결 방안을 탐색하는 데 주안점을 둔다. 사회과 교육과정 30"}, {"id": 210, "code": "[6사03-01]", "text": "일상 사례에서 법의 의미와 역할을 이해하고 , 헌법에 규정된 인권이 일상생활에서 구현 되는 사례를 조사하여 인권 친화적 태도를 기른다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "인문환경과 인간 생활", "verb": "태도", "textLen": 76, "hasExp": true, "explanation": "은 우리 생활에 영향을 미치는 법의 의미와 역할을 일상 사례를 통해 이해하고 , 헌법에 규정된 인권을 보장하는 다양한 사례를 조사하도록 설정한 것이다 . 이를 통해 준법 태도와 인권 의식을 기르는 데 초점을 맞춘다 ."}, {"id": 211, "code": "[6사03-02]", "text": "일상생활에서 인권이 침해되는 사례를 찾아 그 해결 방안을 탐색하고 , 인권을 보호하는 활동에 참여한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "인문환경과 인간 생활", "verb": "행위", "textLen": 58, "hasExp": true, "explanation": "는 일상생활에서 발생하는 인권 침해 문제의 해결 방안을 제시할 수 있는 능력을 기르도록 설정한 것이다 . 인권 문제 해결과 관련된 토론 및 문제 해결의 과정을 통해 인권 보호 활동에 참여하는 능력과 태도를 함양하는 데 중점을 둔다. 공통 교육과정 31"}, {"id": 212, "code": "[6사04-01]", "text": "선사 시대와 고조선의 유적과 유물을 활용하여 당시 사람들의 생활을 추론한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "지속가능한 세계", "verb": "행위", "textLen": 43, "hasExp": true, "explanation": "은 선사 시대와 고조선의 유적과 유물을 활용하여 당시 사람들의 생활 모습을 추론하도록 설정한 것이다 . 당시 사람들의 생활을 추론하는 데 적절한 유적과 유물 등을 선정하여 탐구 과정을 경험하도록 한다."}, {"id": 213, "code": "[6사04-02]", "text": "역사 기록이나 유적과 유물에 나타난 고대 사람들의 생각과 생활을 추론한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "지속가능한 세계", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "는 고대의 역사 기록이나 유적과 유물을 활용하여 당시 사람들의 생각이나 생활 모습을 추론하기 위해 설정한 것이다 . 삼국사기 , 삼국유사  등 역사 기록이나 삼국⋅ 가야⋅통일신라 ⋅발해 사람들의 생각과 생활 모습이 드러난 유적과 유물을 탐구하여 고대 사회의 여러 면모를 알아본다 ."}, {"id": 214, "code": "[6사04-03]", "text": "다양한 역사 자료를 활용하여 고려 시대 사회 모습과 사람들의 생활을 추론한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "지속가능한 세계", "verb": "행위", "textLen": 44, "hasExp": true, "explanation": "은 유적과 유물, 역사 기록 등 여러 자료를 활용하여 고려 시대 사회 모습과 사람 들의 생활을 탐구하도록 설정한 것이다 . 종교, 성별, 신분, 교류 등과 관련된 내용 중에서 고려 시대 사회 모습과 사람들의 생활을 보여주는 주제를 선택하여 살펴본다 . 사회과 교육과정 32"}, {"id": 215, "code": "[6사05-01]", "text": "조선 시대 사람들의 생각과 생활에 유교 문화가 미친 영향을 파악한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "정치", "verb": "행위", "textLen": 39, "hasExp": true, "explanation": "은 조선 전기부터 조선 후기까지 유교 문화가 조선 사회에 미친 영향을 파악하는 데 중점을 둔다. •유교 문화, 조선 후기 사회⋅문화적 변화 및 개항기 근대 문물 수용 과정과 관련 있는 내용 중에서 당시 사람들의 생각과 생활을 보여주는 주제를 선택하여 살펴본다 . •조선 후기 사회⋅문화적 변화와 근대 문물의 수용 과정에서 사람들의 생각과 생활이 변화 되었음을 다양한 자료를 통해 파악한다 . •유교 문화가 조선 시대 사람들의 생각과 생활에 미친 영향과 조선 후기 사회⋅문화적 변화 및 근대 문물 수용 과정에서 달라진 생활 모습을 설명할 수 있는지 평가한다 . 공통 교육과정 33(6) 식민 통치와 저항, 전쟁이 바꾼 사회와 생활"}, {"id": 216, "code": "[6사05-02]", "text": "조선 후기 사회⋅문화적 변화와 개항기 근대 문물 수용 과정에서 달라진 사람들의 생활을 이해한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "정치", "verb": "행위", "textLen": 54, "hasExp": true, "explanation": "는 조선 후기 사회⋅문화적 변화 양상과 개항 이후 근대 문물 수용으로 달라진 생활 모습을 이해하도록 설정한 것이다 . 조선 후기 새로운 문화 주체로 등장한 사람들의 활동을 살펴보고 개항 이후 근대 문물의 수용, 변형 등을 파악한다 ."}, {"id": 217, "code": "[6사06-01]", "text": "일제의 식민 통치와 이에 대한 저항이 사회와 생활에 미친 영향을 이해한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "경제", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "은 일제 식민 통치와 국권 회복을 위한 저항으로 달라진 사회와 식민 통치하에 사람들의 생활 모습을 알아보도록 설정한 것이다 . 3⋅1 운동 등 일제에 대한 저항을 알아 보고, 이로 인해 달라진 사회 변화와 사람들의 생활을 사례를 중심으로 살펴본다 ."}, {"id": 218, "code": "[6사06-02]", "text": "8⋅15 광복과 6⋅25 전쟁이 사회와 생활에 미친 영향을 파악한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "경제", "verb": "행위", "textLen": 39, "hasExp": true, "explanation": "는 8⋅15 광복과 6⋅25 전쟁이 사회와 사람들의 생활에 가져온 변화를 살펴 보도록 설정한 것이다. 8⋅15 광복과 6⋅25 전쟁을 알아보고 , 성별, 연령, 계층 등 사람들 의 생활과 사회 전반에 미친 영향을 구체적 사례로 파악한 후 오늘날까지 영향을 미치고 있음을 이해한다 ."}, {"id": 219, "code": "[6사07-01]", "text": "분단으로 나타난 문제점과 분단과 관련된 장소를 평화의 장소로 만들려는 노력 등을 알아 보고, 평화 통일을 위해 우리가 할 수 있는 일을 탐색한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "사회·문화", "verb": "행위", "textLen": 82, "hasExp": true, "explanation": "은 분단으로 나타난 문제점과 평화 통일을 위한 과제를 탐색하도록 설정한 것 이다. 분단이 사회와 사람들의 생활에 미친 영향을 알아보고 , 분단과 관련된 장소를 평화의 사회과 교육과정 34장소로 만들려는 사람들의 노력을 살펴본다 . 그리고 평화 통일의 필요성을 인식하고 이를 위해 우리가 할 수 있는 일을 탐색한다 ."}, {"id": 220, "code": "[6사07-02]", "text": "민주화와 산업화로 인해 달라진 생활 문화를 사례를 들어 이해한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "사회·문화", "verb": "행위", "textLen": 37, "hasExp": true, "explanation": "는 민주화 , 산업화가 사람들의 생활과 어떤 관계가 있는지 알아보도록 설정한 것이다 . 사회적인 강압이나 통제에서 벗어나기 위해 노력한 다양한 분야 사람들의 모습과 산업화로 달라진 사람들의 생활을 여러 사례를 중심으로 이해한다 ."}, {"id": 221, "code": "[6사08-01]", "text": "민주주의에서 선거의 의미와 역할을 파악하고 , 시민의 주권 행사를 위해 선거에 참여하 는 태도를 기른다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "역사", "verb": "태도", "textLen": 59, "hasExp": true, "explanation": "은 민주주의에서 시민의 주권 행사의 한 방법으로써 선거의 역할과 중요성을 파악하도록 설정한 것이다 . 이를 바탕으로 선거에 주체적으로 참여하는 태도를 형성하는 데 중점을 둔다."}, {"id": 222, "code": "[6사08-02]", "text": "민주 국가에서 국회, 행정부, 법원이 하는 일에 대해 이해하고 , 각 국가기관의 권력을 분립 하는 이유를 탐색한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "역사", "verb": "행위", "textLen": 65, "hasExp": true, "explanation": "는 우리나라 민주주의에서 국회, 행정부 , 법원이 하는 일을 이해하도록 설정한 것이다 . 이를 바탕으로 시민의 자유와 권리 보장 측면에서 권력 분립의 이유를 파악하는 데 중점을 둔다."}, {"id": 223, "code": "[6사08-03]", "text": "민주주의에서 미디어의 의미와 역할을 이해하고 , 여러 가지 미디어의 내용을 비판적으로 분석하여 올바르게 이용하는 태도를 기른다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "역사", "verb": "태도", "textLen": 72, "hasExp": true, "explanation": "은 민주주의에서 신문, 방송, 사회 관계망 서비스(SNS) 같은 미디어가 하는 역 할을 파악하고 , 미디어가 제공한 거짓 또는 왜곡된 정보와 내용 등을 찾아 비판적으로 분석 공통 교육과정 35하고 평가하도록 설정한 것이다 . 이런 비판적 분석을 통해 미디어를 올바르게 이용하는 능 력을 함양하는 데 초점을 맞춘다 ."}, {"id": 224, "code": "[6사09-01]", "text": "세계를 표현하는 다양한 공간 자료의 특징을 이해하고 , 지구본과 세계지도에서 위치를 표현하는 방법을 익힌다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "정치", "verb": "기타", "textLen": 61, "hasExp": true, "explanation": "은 지구본, 세계지도뿐만 아니라 디지털 공간 영상 정보 등 다양한 공간 자료의 특성을 이해하고 이를 활용하여 세계에 대한 기초적인 지리 정보를 획득하려고 설정한 것이다. 여기서는 경⋅위도의 의미를 이해하고 , 이를 활용하여 위치를 표현하는 방법을 익히도록 한다."}, {"id": 225, "code": "[6사09-02]", "text": "세계 주요 대륙과 대양을 파악하고 , 우리나라 및 세계 여러 국가의 위치와 영토의 특징을 이해한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "정치", "verb": "행위", "textLen": 56, "hasExp": true, "explanation": "는 위치가 갖는 중요성을 인식하여 지구본과 세계지도에서 세계의 대륙 및 대 양의 위치를 파악하도록 설정한 것이다 . 세계 여러 국가의 위치와 영토의 형상 등 기초적인 지리 정보를 획득하는 데 주안점을 둔다. 사회과 교육과정 36"}, {"id": 226, "code": "[6사10-02]", "text": "세계의 다양한 기후를 알아보고 기후 환경과 인간생활 간의 관계를 탐구한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "경제", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "는 기온 및 강수량을 나타낸 기후 그래프 , 지도, 사진 자료 등을 활용하여 세계 주요 기후의 분포를 파악하도록 설정한 것이다. 여기서는 기후와 인간 생활을 관련지어 이해 하는 데 중점을 둔다. 공통 교육과정 37"}, {"id": 227, "code": "[6사10-01]", "text": "세계의 여러 지역의 지형 경관을 살펴보고 , 이를 통해 다양한 삶의 모습을 이해한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "경제", "verb": "행위", "textLen": 48, "hasExp": true, "explanation": "은 세계적으로 유명한 산지, 하천, 해안 지역 등의 경관 특징과 그곳에서 살아 가는 사람들의 생활 모습에서 세계 여러 지역의 다양성을 이해하도록 설정한 것이다 . 여기 서는 우리와 다른 지역의 생활 모습에 관심을 갖는 데 주안점을 둔다."}, {"id": 228, "code": "[6사11-01]", "text": "시장경제에서 가계와 기업의 역할을 이해하고 , 근로자의 권리와 기업의 자유 및 사회적 책임을 탐색한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "사회·문화", "verb": "행위", "textLen": 58, "hasExp": true, "explanation": "은 시장경제의 특징에 대한 이해를 바탕으로 가계와 기업의 역할 및 상호 의존 관계를 파악하고 , 근로자의 권리와 기업의 자유로운 경제활동 및 사회적 책임을 탐색하도 록 설정한 것이다 . 이를 바탕으로 근로자의 권리를 보호하고 기업이 자유로운 경제활동과 이윤을 추구하면서 사회적 책임을 이행하는 것의 중요성을 인식하는 데 초점을 맞춘다 ."}, {"id": 229, "code": "[6사11-02]", "text": "경제성장이 우리 생활에 미치는 영향을 파악하고 , 빠른 경제성장으로 발생한 문제의 해결 방안을 탐색한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "사회·문화", "verb": "행위", "textLen": 59, "hasExp": true, "explanation": "는 우리나라의 경제성장이 우리 생활에 미친 긍정적 ⋅부정적 영향을 통계 자료를 통 해 파악 하 고 빠 른 경 제 성장 으 로 발 생 한 문 제 의 해 결 방 안 을 찾 도 록 설 정 한 것 이다. 또한, 토론을 통해 빠른 경제성장으로 발생하는 문제를 합리적으로 해결하는 방안을 찾는 데 중점을 둔다. 사회과 교육과정 38"}, {"id": 230, "code": "[6사11-03]", "text": "사례를 통해 무역의 의미를 이해하고 , 국가 간 무역이 발생하는 이유를 탐구한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "사회·문화", "verb": "행위", "textLen": 46, "hasExp": true, "explanation": "은 학생이 접할 수 있는 수입⋅수출 상품의 사례에서 무역의 의미와 중요성을 파악하고 세계 여러 나라 간 무역이 발생하는 이유를 탐구하도록 설정한 것이다 . 이를 바탕 으로 오늘날 여러 나라가 무역을 통해 경쟁 및 상호 의존 관계에 있음을 파악하는 데 중점을 둔다."}, {"id": 231, "code": "[6사12-01]", "text": "세계의 인구 분포를 파악하고 여러 국가의 인구 특징을 탐구한다 .", "subject": "사회", "gradeGroup": "초5~6", "area": "역사", "verb": "행위", "textLen": 36, "hasExp": true, "explanation": "은 세계의 인구 분포를 파악하고 , 인구수 및 인구 밀도의 특징이 두드러진 국가를 탐구하도록 설정한 것이다 . 여기서는 지구촌 시대의 세계 여러 지역에 대한 기본적인 지리 정보를 습득하는 데 초점을 맞춘다 ."}, {"id": 232, "code": "[6사12-02]", "text": "지구촌을 위협하는 다양한 문제들을 파악하고 , 지속가능한 미래를 위한 해결 방안을 탐색 한다.", "subject": "사회", "gradeGroup": "초5~6", "area": "역사", "verb": "기타", "textLen": 52, "hasExp": true, "explanation": "는 지구촌의 평화와 발전을 위협하는 문제를 파악하고 이를 해결하려는 방안을 탐색하며 , 지속가능한 지구촌을 건설하는 데 관심을 가지도록 설정한 것이다 . 세계에 대한 올바른 이해를 바탕으로 세계시민으로서 지녀야 할 관점과 태도를 함양하는 데 주안점을 둔다. 공통 교육과정 39"}, {"id": 233, "code": "[9역01-01]", "text": "역사와 역사 탐구의 의미를 파악하고 , 역사 학습의 목적을 다각도로 탐색한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지리 인식", "verb": "행위", "textLen": 44, "hasExp": true, "explanation": "역사의 의미를 ‘과거의 사실’이나 ‘기록된 과거’에 한정하지 않고, 학습자가 일상 에서 접하는 역사의 활용 사례를 포함하여 탐구하고 , 학습자의 삶의 맥락에서 역사 학습을 의미화하는 데 초점을 둔다."}, {"id": 234, "code": "[9역01-02]", "text": "다양한 자료와 사례를 통해 역사 탐구 방법을 익힌다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지리 인식", "verb": "기타", "textLen": 30, "hasExp": true, "explanation": "역사를 탐구하는 과정과 방법을 기초적 수준에서 이해하기 위해 설정하였다 . 문자, 비문자 자료 등 역사 자료의 종류와 특징을 이해하고 , 자료에 대한 분석⋅해석을 토대로 논쟁을 경험하도록 한다."}, {"id": 235, "code": "[9역02-01]", "text": "선사 문화 및 문명의 형성을 이해하고 , 각 문명의 특징을 비교한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "자연환경과 인간 생활", "verb": "행위", "textLen": 39, "hasExp": false}, {"id": 236, "code": "[9역02-02]", "text": "서아시아 ⋅지중해 세계에서 등장한 여러 정치체를 비교하고 종교 및 문화를 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "자연환경과 인간 생활", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "페르시아와 그리스 , 로마 등 다양한 정치체 (폴리스 , 제국, 왕국 등)를 통치 체 제(민주정 , 공화정 , 제정) 상의 다양성에 따라 비교하면서 각각의 특징을 파악한다 ."}, {"id": 237, "code": "[9역02-03]", "text": "중국과 인도의 정치적 변화와 종교⋅사상 성립의 관계를 이해하고 , 유라시아의 상호 교 류를 탐색한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "자연환경과 인간 생활", "verb": "행위", "textLen": 57, "hasExp": false}, {"id": 238, "code": "[9역03-01]", "text": "수⋅당 시기 동아시아 국제 질서의 특징을 이해하고 , 동아시아 문화를 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "인문환경과 인간 생활", "verb": "행위", "textLen": 45, "hasExp": false}, {"id": 239, "code": "[9역03-02]", "text": "인도, 서아시아 , 지중해에서 진행된 정치적 변동 과정과 각 종교의 특징 및 영향을 파악한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "인문환경과 인간 생활", "verb": "행위", "textLen": 53, "hasExp": true, "explanation": "유라시아 각지의 정치⋅종교적 변동을 사산 왕조 페르시아 및 굽타 왕조의 등장, 서로마 제국의 소멸과 비잔티움 제국의 발전, 이슬람 세계의 성장을 중심으로 파악한다 ."}, {"id": 240, "code": "[9역03-03]", "text": "크리스트교 세계의 정치와 종교의 상관성을 이해하고 , 이슬람 세계와 크리스트교 세계의 충돌 및 교류의 결과를 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "인문환경과 인간 생활", "verb": "행위", "textLen": 67, "hasExp": true, "explanation": "9세기 이후 서유럽 세계의 권력 세분화와 교황권의 성장을 연관 지어 이해하고 지중해 지역에서 이루어진 크리스트교 세계와 이슬람 세계 간의 충돌과 교류를 탐구한다 ."}, {"id": 241, "code": "[9역04-01]", "text": "송과 몽골 제국 시기 유라시아 ⋅인도양 교역권의 성장을 경제⋅문화 자료를 통해 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지속가능한 세계", "verb": "행위", "textLen": 50, "hasExp": false}, {"id": 242, "code": "[9역04-02]", "text": "명⋅청, 에도 막부, 무굴 제국의 정치⋅사회 변화를 비교한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지속가능한 세계", "verb": "행위", "textLen": 35, "hasExp": true, "explanation": "아시아 국가들이 고유한 방식으로 정치⋅사회적 발전을 이루었음을 파악하기 위해 설정하였다 . 명⋅청, 에도 막부, 무굴 제국의 통치 체제 정비, 산업 및 문화의 발전에 초점을 맞춘다 . 사회과 교육과정 80"}, {"id": 243, "code": "[9역04-03]", "text": "오스만 제국의 성장과 유럽 사회의 근대적 변화를 조사한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지속가능한 세계", "verb": "행위", "textLen": 33, "hasExp": true, "explanation": "서아시아에서 지중해에 걸친 오스만 제국의 성장과 통합 정책을 탐구하고 , 신항로 개척 및 세계 교역망 확립이 초래한 결과를 유럽뿐 아니라 유럽 이외 지역의 관점에서 종합 적으로 이해한다 . 또한 종교개혁 이후 등장한 재정⋅군사 국가의 특징을 파악한다 ."}, {"id": 244, "code": "[9역05-01]", "text": "시민 혁명을 국민 국가 형성과 연결하여 파악하고 , 역사적 의의와 한계를 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "정치", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "미국 혁명과 프랑스 혁명 과정에서 인권과 민주주의에 입각한 새로운 정치 체제 의 확립 시도가 이루어졌음을 이해하고 , 혁명이 아이티 등 라틴 아메리카의 여러 나라에 끼친 영향을 파악한다 . 이후 인권과 참정권의 실질적인 확대를 위해 서양 각국에서 전개된 여러 정 치적 움직임을 파악하고 , 이 과정에서 나타난 다양한 국민 국가 건설 노력을 비교한다 ."}, {"id": 245, "code": "[9역05-02]", "text": "서양의 산업화와 제국주의 정책을 이해하고 , 사회와 생태환경에 미친 영향을 분석한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "정치", "verb": "행위", "textLen": 48, "hasExp": true, "explanation": "산업화를 기술적 ⋅경제적 발전과 풍요의 관점뿐 아니라 자본주의의 등장, 국 민 국가의 형성과 맞물려 제국주의적 팽창과 침략으로 연결되는 과정으로 이해하고 , 그 영 향을 국가적 ⋅세계적 차원 및 생태환경적 관점에서 파악한다 ."}, {"id": 246, "code": "[9역05-03]", "text": "제국주의 열강의 침략에 대한 아시아의 대응 및 국민 국가 건설 노력을 이해하고 , 그 성 과와 한계를 평가한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "정치", "verb": "행위", "textLen": 63, "hasExp": true, "explanation": "청, 무굴 제국, 오스만 제국, 일본 등에서 전개된 반제국주의 운동, 국민 국가 건설 운동의 특징을 비교하는 데 주안점을 둔다. 공통 교육과정 81"}, {"id": 247, "code": "[9역06-01]", "text": "20세기 전반 세계 질서의 변화를 두 차례의 세계 대전을 중심으로 파악한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "경제", "verb": "행위", "textLen": 43, "hasExp": true, "explanation": "두 차례의 세계 대전을 파악하는 데 있어 서양 열강 간 경쟁과 대립, 러시아 혁명과 서유럽 각국의 민주주의 확대, 세계 대공황의 충격과 전체주의 (파시즘 , 나치즘 , 군 국주의 )의 등장을 중점적으로 이해하도록 한다."}, {"id": 248, "code": "[9역06-02]", "text": "세계 대전 중의 전쟁 범죄를 탐구하고 , 인권 회복과 평화 실현을 위한 노력을 조사한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "경제", "verb": "행위", "textLen": 50, "hasExp": false}, {"id": 249, "code": "[9역06-03]", "text": "아시아 ⋅아프리카 지역의 민족 운동을 이해하고 , 그 특징을 비교한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "경제", "verb": "행위", "textLen": 40, "hasExp": true, "explanation": "두 차례 세계 대전 전후의 민족 운동을 민족주의 , 사회주의의 세계적 확산과 관련하여 파악하는 데에 중점을 둔다."}, {"id": 250, "code": "[9역07-01]", "text": "냉전의 전개와 제3 세계 등장의 상관관계를 이해하고 , 냉전 이후 국제 질서의 변화를 분 석한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "사회·문화", "verb": "행위", "textLen": 55, "hasExp": false}, {"id": 251, "code": "[9역07-02]", "text": "20세기 후반 민주주의와 인권의 신장을 위한 노력에 관심을 갖는다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "사회·문화", "verb": "태도", "textLen": 38, "hasExp": true, "explanation": "20세기 후반에 전개된 반전 평화 운동, 민권 운동, 여성 운동, 환경 운동 등의 의미를 학습자 삶과의 연계성을 고려하여 파악하고 , 제기되는 과제의 해결 방안을 모색한 다."}, {"id": 252, "code": "[9역07-03]", "text": "오늘날 세계화의 양상을 조사하고 , 성과와 과제를 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "사회·문화", "verb": "행위", "textLen": 34, "hasExp": true, "explanation": "20세기 후반 사회주의 진영이 붕괴된 이후, 세계화의 확산으로 인해 나타난 변화를 고찰하기 위해 설정하였다 . 오늘날 세계화의 성과와 과제를 살피고 , 문제 해결에 동 참하는 자세를 갖는 데에 초점을 맞춘다 ."}, {"id": 253, "code": "[9역08-01]", "text": "고조선과 여러 나라의 형성 과정 및 사회 모습을 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "역사", "verb": "행위", "textLen": 33, "hasExp": true, "explanation": "고조선의 성장과 멸망을 동아시아의 국제 관계 속에서 이해한다 . 당시 사람들 의 생활 모습이 담긴 자료를 분석하면서 고조선 멸망 전후에 등장한 여러 나라의 특징을 파악하는 데 초점을 둔다."}, {"id": 254, "code": "[9역08-02]", "text": "삼국과 가야의 성장 과정을 파악한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "역사", "verb": "행위", "textLen": 21, "hasExp": false}, {"id": 255, "code": "[9역08-03]", "text": "삼국과 가야가 남긴 문화의 특징을 분석한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "역사", "verb": "행위", "textLen": 25, "hasExp": false}, {"id": 256, "code": "[9역09-01]", "text": "삼국 통일의 과정을 동아시아 국제 정세의 맥락에서 이해하고 , 통일신라와 발해 성립의 역사적 의의를 추론한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "정치", "verb": "행위", "textLen": 62, "hasExp": true, "explanation": "삼국 통일의 과정을 동아시아의 국제 정세 속에서 파악하기 위해 설정하였다 . 당시 국제 정세를 삼국 및 발해, 당과 일본뿐 아니라 거란, 말갈, 돌궐, 토번 등 다양한 세 력과의 관계 속에서 이해하며 , 통일신라와 발해 성립의 의미를 추론한다 ."}, {"id": 257, "code": "[9역09-02]", "text": "통일신라와 발해의 국가 체제 정비와 변동을 분석한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "정치", "verb": "행위", "textLen": 30, "hasExp": false}, {"id": 258, "code": "[9역09-03]", "text": "통일신라와 발해 문화의 특징을 파악한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "정치", "verb": "행위", "textLen": 23, "hasExp": true, "explanation": "통일신라와 발해의 문화가 동아시아의 다양한 문화와의 상호 작용을 통해 형 성되었음을 파악한다 . 삼국의 문화를 바탕으로 한 통일신라 문화의 특징을 동아시아 문화 의 관점에서 파악하고 , 발해의 문화는 고구려 , 당, 말갈 등의 문화가 어우러져 형성되었음 을 이해한다 . 사회과 교육과정 84"}, {"id": 259, "code": "[9역10-01]", "text": "후삼국 통일과 체제 정비 과정을 통해 고려 성립의 역사적 의미를 탐색한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "경제", "verb": "행위", "textLen": 42, "hasExp": false}, {"id": 260, "code": "[9역10-02]", "text": "고려의 정치적 변동을 파악하고 주변국과의 관계를 이해한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "경제", "verb": "행위", "textLen": 33, "hasExp": false}, {"id": 261, "code": "[9역10-03]", "text": "원 간섭기 고려 사회에 나타난 변화를 파악하고 개혁의 영향을 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "경제", "verb": "행위", "textLen": 40, "hasExp": false}, {"id": 262, "code": "[9역10-04]", "text": "고려의 문화유산과 대외 교류의 사례를 조사하여 그 특징을 파악한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "경제", "verb": "행위", "textLen": 38, "hasExp": true, "explanation": "다양한 자료를 활용하여 고려의 문화가 가진 특징을 파악하고 , 고려 시대 사람 들의 삶을 종합적으로 이해한다 . 송, 원을 비롯한 주변 세력과의 경제⋅문화적 대외 교류가 문화의 형성에 미친 영향을 파악한다 ."}, {"id": 263, "code": "[9역11-01]", "text": "조선 성립의 의의를 통치 체제의 특징을 통해 파악한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "사회·문화", "verb": "행위", "textLen": 31, "hasExp": false}, {"id": 264, "code": "[9역11-02]", "text": "사림 세력의 성장이 성리학적 질서 확산에 끼친 영향을 추론한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "사회·문화", "verb": "행위", "textLen": 36, "hasExp": false}, {"id": 265, "code": "[9역11-03]", "text": "왜란과 호란의 성격을 동아시아 국제 정세 속에서 분석한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "사회·문화", "verb": "행위", "textLen": 33, "hasExp": true, "explanation": "왜란과 호란을 동아시아 역사의 맥락 속에서 파악하도록 설정하였다 . 명⋅청 교체, 에도 막부의 성립 등과의 관련성에 초점을 맞춘다 . 공통 교육과정 85"}, {"id": 266, "code": "[9역12-01]", "text": "왜란과 호란 이후 체제 재정비의 노력과 정치 변동의 모습을 파악한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "역사", "verb": "행위", "textLen": 39, "hasExp": false}, {"id": 267, "code": "[9역12-02]", "text": "조선 후기 문화에서 나타난 변화를 분석한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "역사", "verb": "행위", "textLen": 25, "hasExp": false}, {"id": 268, "code": "[9역12-03]", "text": "조선 후기 사회적 모순에 대한 여러 세력의 대응을 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "역사", "verb": "행위", "textLen": 34, "hasExp": true, "explanation": "조선 후기 변동에 따른 사회적 모순을 살펴보고 이에 대한 여러 세력의 대응을 파악하도록 설정하였다 . 세도정치의 폐단, 삼정의 문란 등으로 인한 농민 봉기, 흥선 대원 군의 정책 등을 파악하는 데 초점을 맞춘다 ."}, {"id": 269, "code": "[9역13-01]", "text": "개항 이후 근대 국가를 건설하기 위한 노력을 파악한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지속가능한 세계", "verb": "행위", "textLen": 31, "hasExp": false}, {"id": 270, "code": "[9역13-02]", "text": "국권 피탈 이후 전개된 민족 운동을 세계사적 관점에서 이해한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지속가능한 세계", "verb": "행위", "textLen": 36, "hasExp": false}, {"id": 271, "code": "[9역13-03]", "text": "한국의 민주화 과정에서 나타난 성과와 과제를 탐구한다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지속가능한 세계", "verb": "행위", "textLen": 31, "hasExp": true, "explanation": "정치적 ⋅경제적 ⋅사회적 민주화 양상을 포함하여 다양한 주체들의 노력으로 이루어진 사회 전반의 자유민주적 기본질서 정착과정과 과제를 탐구하는 데 초점을 둔다."}, {"id": 272, "code": "[9역13-04]", "text": "지속가능한 사회를 위한 과제를 역사적 맥락에서 탐구하고 , 과제 해결에 참여하는 자세를 갖는다 .", "subject": "사회", "gradeGroup": "중1~3", "area": "지속가능한 세계", "verb": "태도", "textLen": 54, "hasExp": true, "explanation": "한국의 통일 문제를 비롯하여 현대 세계가 겪고 있는 평화와 민주주의의 위기, 생태환경 위기, 전염병의 확산 등을 자신의 문제로 인식하는 태도를 길러 주기 위해 설정하 사회과 교육과정 86였다. 현대 사회 문제의 원인과 해결 방안을 역사적 맥락에서 탐색하여 지속가능한 사회의 실현에 참여하는 태도의 함양에 초점을 둔다."}, {"id": 273, "code": "[2수01-01]", "text": "수의 필요성을 인식하면서 0과 100까지의 수 개념을 이해하고 , 수를 세고 읽고 쓸 수 있다.", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "기타", "textLen": 53, "hasExp": false}, {"id": 274, "code": "[2수01-02]", "text": "일, 십, 백, 천의 자릿값과 위치적 기수법을 이해하고 , 네 자리 이하의 수를 읽고 쓸 수 있다.", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "기타", "textLen": 55, "hasExp": false}, {"id": 275, "code": "[2수01-03]", "text": "네 자리 이하의 수의 범위에서 수의 계열을 이해하고 , 수 의 크 기 를 비 교 할 수 있 다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "기타", "textLen": 54, "hasExp": false}, {"id": 276, "code": "[2수01-04]", "text": "하나의 수를 두 수로 분해하고 두 수를 하나의 수로 합성하는 활동을 통하여 수 감각을 기른다 . 숕 두 자리 수 범위의 덧셈과 뺄셈", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "태도", "textLen": 73, "hasExp": false}, {"id": 277, "code": "[2수01-05]", "text": "덧셈과 뺄셈이 이루어지는 실생활 상황과 연결하여 덧셈과 뺄셈의 의미를 이해한다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "행위", "textLen": 45, "hasExp": false}, {"id": 278, "code": "[2수01-06]", "text": "두 자리 수의 범위에서 덧셈과 뺄셈의 계산 원리를 이해하고 그 계산을 할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "능력", "textLen": 47, "hasExp": true, "explanation": "덧셈은 두 자리 수의 범위에서 다루되, 합이 세 자리 수인 경우도 포함한다."}, {"id": 279, "code": "[2수01-07]", "text": "덧셈과 뺄셈의 관계를 이해한다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "행위", "textLen": 18, "hasExp": false}, {"id": 280, "code": "[2수01-08]", "text": "두 자리 수의 범위에서 세 수의 덧셈과 뺄셈을 할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "능력", "textLen": 34, "hasExp": false}, {"id": 281, "code": "[2수01-09]", "text": "□가 사용된 덧셈식과 뺄셈식을 만들고 , □ 의 값 을 구 할 수 있 다 . 숖 한 자리 수의 곱셈", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "기타", "textLen": 55, "hasExp": false}, {"id": 282, "code": "[2수01-10]", "text": "곱셈이 이루어지는 실생활 상황과 연결하여 곱셈의 의미를 이해한다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "행위", "textLen": 37, "hasExp": false}, {"id": 283, "code": "[2수01-11]", "text": "곱셈구구를 이해하고 , 한 자리 수의 곱셈을 할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "수와 연산", "verb": "능력", "textLen": 33, "hasExp": false}, {"id": 284, "code": "[2수02-01]", "text": "물체, 무늬, 수 등의 배열에서 규칙을 찾아 여러 가지 방법으로 표현할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "변화와 관계", "verb": "능력", "textLen": 46, "hasExp": true, "explanation": "물체, 무늬, 수 등의 배열을 관찰하여 일정하게 반복되거나 증가하는 규칙을 찾고 말, 수, 그림, 기호, 구체물, 행동 등의 다양한 방법으로 표현하게 한다. 그리고 물체, 무늬, 수의 배열에서 다음에 올 것이나 중간에 빠진 것을 추측하게 한다."}, {"id": 285, "code": "[2수02-02]", "text": "자신이 정한 규칙에 따라 물체 , 무늬, 수 등을 배열할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "변화와 관계", "verb": "능력", "textLen": 38, "hasExp": false}, {"id": 286, "code": "[2수03-01]", "text": "교실 및 생활 주변에서 여러 가지 물건을 관찰하여 직육면체 , 원기둥 , 구의 모양을 찾고 , 이를 이용하여 여러 가지 모양을 만들 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "기타", "textLen": 80, "hasExp": false}, {"id": 287, "code": "[2수03-02]", "text": "쌓기나무로 만든 입체도형의 모양에 대해서 ‘∼의 앞’, ‘∼의 오른쪽’, ‘∼의 위’, ‘2층’ 등을 사용하여 말하게 한다.", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "기타", "textLen": 69, "hasExp": true, "explanation": "쌓기나무를 이용하여 여러 가지 입체도형의 모양을 만들고 , 그 모양에 대해 위치나 방향을 이용하여 말할 수 있다 . 숕 평면도형과 그 구성 요소"}, {"id": 288, "code": "[2수03-03]", "text": "교실 및 생활 주변에서 여러 가지 물건을 관찰하여 삼각형 , 사각형 , 원의 모양을 찾고 , 이를 이용하여 여러 가지 모양을 만들 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "기타", "textLen": 79, "hasExp": false}, {"id": 289, "code": "[2수03-04]", "text": "삼각형 , 사각형 , 원을 직관적으로 이해하고 , 그 모양을 그릴 수 있다 . 수학과 교육과정 14", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "기타", "textLen": 55, "hasExp": true, "explanation": "삼각형, 사각형, 원은 예인 것과 예가 아닌 것을 분류하는 활동을 통하여 직관적으로 이해하게 한다. 본뜨기, 도형판을 이용한 활동 등을 통해 삼각형, 사각형, 원의 모양을 그리게 할 수 있다."}, {"id": 290, "code": "[2수03-10]", "text": "길이 단위 1cm와 1m를 알고 , 이를 이용하여 주변 사물의 길이를 측정할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "능력", "textLen": 49, "hasExp": true, "explanation": "길이의 표준 단위를 도입하기 전에 구체물을 직접 비교해 보거나 여러 가지 임의 단위를 사용하여 구체물의 길이를 재어보는 활동을 통해 표준 단위의 필요성을 알게 한다."}, {"id": 291, "code": "[2수03-12]", "text": "여러 가지 물건의 길이를 어림하고 , 길이에 대한 양감을 기른다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "태도", "textLen": 37, "hasExp": true, "explanation": "생활 주변의 여러 가지 물건들의 길이를 어림해 보고 자로 측정하여 확인하는 활동과 주어진 길이에 해당하는 선분을 그려 보는 활동을 통해 길이에 대한 양감을 기르게 한다."}, {"id": 292, "code": "[2수03-05]", "text": "삼각형 , 사각형에서 각각의 공통점을 찾아 말할 수 있다 . 숖 양의 비교", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "능력", "textLen": 41, "hasExp": false}, {"id": 293, "code": "[2수03-06]", "text": "구체물의 길이 , 들이, 무게, 넓이를 비교하여 각각 ‘길다, 짧다’, ‘많다, 적다’, ‘무겁다 , 가볍다 ’, ‘넓다, 좁다’ 등을 구별하여 말할 수 있다 . 숗 시각과 시간", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "능력", "textLen": 99, "hasExp": false}, {"id": 294, "code": "[2수03-07]", "text": "시계를 보고 시각을 ‘몇 시 몇 분 ’까지 읽을 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "기타", "textLen": 33, "hasExp": false}, {"id": 295, "code": "[2수03-08]", "text": "1 시간과 1분의 관계를 이해하고 , 시간을 ‘시간’, ‘분’으로 표현할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "능력", "textLen": 47, "hasExp": false}, {"id": 296, "code": "[2수03-09]", "text": "실생활 문제 상황과 연결하여 1분, 1시간, 1일, 1주일, 1개월, 1년 사이의 관계를 이해한다 . 수 길이", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "기타", "textLen": 61, "hasExp": false}, {"id": 297, "code": "[2수03-11]", "text": "1m 와 1cm의 관계를 이해하고 , 길이를 ‘몇 m 몇 cm’와 ‘몇 cm’로 표현할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "능력", "textLen": 55, "hasExp": false}, {"id": 298, "code": "[2수03-13]", "text": "실생활 문제 상황과 연결하여 길이의 덧셈과 뺄셈을 할 수 있다 . 공통 교육과정 15•입체도형과 평면도형의 모양을 다룰 때 모양의 특징을 직관적으로 파악하여 모양을 분류하 고, 분류한 모양을 지칭하기 위해 일상용어를 사용하게 할 수 있다. •입체도형과 평면도형의 모양을 이용한 모양 만들기의 주제는 학생들에게 친근한 소재인 동물, 탈 것, 건물 등으로 다양하게 제시하여 수학에 대한 흥미와 관심을 갖게 한다. •쌓기나무, 칠교판 등의 구체물을 이용한 모양 만들기를 통하여 도형에 대한 공간 감각을 기르게 한다. •양의 비교는 학생들에게 친근한 실생활 상황을 이용하고, 직관적인 비교, 직접 비교, 간접 비교 등을 상황에 따라 알맞게 다룬다. •저학년 학생들의 한글 학습 정도를 고려하여 양을 비교할 때 ‘짧다’, ‘많다’, ‘넓다’ 등과 같이 한글로 쓰게 하는 것은 지양한다.", "subject": "수학", "gradeGroup": "초1~2", "area": "도형과 측정", "verb": "능력", "textLen": 434, "hasExp": false}, {"id": 299, "code": "[2수04-01]", "text": "여러 가지 사물을 정해진 기준 또는 자신이 정한 기준으로 분류하여 개수를 세어 보고 , 기준에 따른 결과를 말할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "자료와 가능성", "verb": "능력", "textLen": 69, "hasExp": false}, {"id": 300, "code": "[2수04-02]", "text": "자료를 분류하여 표로 나타내고 , 자료를 표로 나타내면 편리한 점을 말할 수 있다 .", "subject": "수학", "gradeGroup": "초1~2", "area": "자료와 가능성", "verb": "능력", "textLen": 47, "hasExp": true, "explanation": "표를 이용하여 자료의 크기를 수로 정리하면, 자료의 크기를 나타내고 비교하 는 데 편리하다는 점을 통해 수학의 유용성을 인식하게 한다."}, {"id": 301, "code": "[2수04-03]", "text": "자료를 분류하여 ○ , ×, / 등을 이용한 그래프로 나타내고 , 자료를 그래프로 나타내면 편리한 점을 말할 수 있다 . 수학과 교육과정 16", "subject": "수학", "gradeGroup": "초1~2", "area": "자료와 가능성", "verb": "능력", "textLen": 79, "hasExp": true, "explanation": "그래프를 이용하여 자료의 크기를 시각적으로 나타내면, 자료의 크기를 한눈에 비교하는 데 편리하다는 점을 통해 수학의 유용성을 인식하게 한다."}, {"id": 302, "code": "[4수01-01]", "text": "큰 수의 필요성을 인식하면서 10000 이상의 큰 수에 대한 자릿값과 위치적 기수법을 이해하고 , 수를 읽고 쓸 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "기타", "textLen": 69, "hasExp": false}, {"id": 303, "code": "[4수01-02]", "text": "다섯 자리 이상의 수의 범위에서 수의 계열을 이해하고 , 수의 크기를 비교하며 그 방법을 설명할 수 있다 . 숕 세 자리 수의 덧셈과 뺄셈", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "능력", "textLen": 77, "hasExp": false}, {"id": 304, "code": "[4수01-03]", "text": "덧셈은 세 자리 수의 범위에서 다루되, 합이 네 자리 수인 경우도 포함한다.", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "세 자리 수의 덧셈과 뺄셈의 계산 원리를 이해하고 그 계산을 할 수 있다 . 숖 세 자리 수 범위의 곱셈"}, {"id": 305, "code": "[4수01-04]", "text": "곱하는 수가 한 자리 수 또는 두 자리 수인 곱셈의 계산 원리를 이해하고 그 계산을 할 수 있다 . 숗 세 자리 수 범위의 나눗셈", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "능력", "textLen": 72, "hasExp": true, "explanation": "곱셈은 ‘(두 자리 수) ×(한 자리 수)’, ‘(세 자리 수) ×(한 자리 수)’, ‘(두 자리 수)×(두 자리 수)’, ‘(세 자리 수) ×(두 자리 수)’를 다룬다."}, {"id": 306, "code": "[4수01-05]", "text": "나눗셈이 이루어지는 실생활 상황과 연결하여 나눗셈의 의미를 알고 , 곱셈과 나눗셈의 관계를 이해한다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "행위", "textLen": 57, "hasExp": false}, {"id": 307, "code": "[4수01-06]", "text": "나누는 수가 한 자리 수인 나눗셈의 계산 원리를 이해하고 그 계산을 할 수 있으며 , 나눗셈에서 몫과 나머지의 의미를 안다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "기타", "textLen": 70, "hasExp": true, "explanation": "나눗셈에서 ‘(두 자리 수) ÷(한 자리 수)’는 나누어떨어지는 경우와 나누어떨어 지지 않는 경우를 포함하여 몫과 나머지를 이해하게 한다."}, {"id": 308, "code": "[4수01-07]", "text": "나누는 수가 두 자리 수인 나눗셈의 계산 원리를 이해하고 그 계산을 할 수 있다 . 수 자연수의 어림셈", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "능력", "textLen": 57, "hasExp": true, "explanation": "나누는 수가 두 자리 수인 나눗셈에서는 ‘(두 자리 수) ÷(두 자리 수)’, ‘(세 자 리 수)÷(두 자리 수)’를 다룬다."}, {"id": 309, "code": "[4수01-08]", "text": "자연수의 덧셈 , 뺄셈, 곱셈, 나눗셈과 관련한 여러 가지 상황에서 어림셈을 할 수 있다 . 숙 분수", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "능력", "textLen": 56, "hasExp": false}, {"id": 310, "code": "[4수01-09]", "text": "양의 등분할을 통하여 분수의 필요성을 인식하고 , 분수를 이해하고 읽고 쓸 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "기타", "textLen": 48, "hasExp": true, "explanation": "1보다 작은 양을 나타내는 경우를 통하여 분수의 필요성이나 그 표현의 편리 함을 인식하게 할 수 있다. 양의 등분할을 통하여 분수를 도입할 때 부분과 전체를 파악하 게 하고, ‘분모’, ‘분자’를 사용한다."}, {"id": 311, "code": "[4수01-10]", "text": "단위분수 , 진분수 , 가분수 , 대분수를 알고 , 그 관계를 이해한다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "행위", "textLen": 41, "hasExp": false}, {"id": 312, "code": "[4수01-11]", "text": "분모가 같은 분수끼리 , 단위분수끼리 크기를 비교하고 그 방법을 설명할 수 있다 . 숚 소수", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "능력", "textLen": 51, "hasExp": false}, {"id": 313, "code": "[4수01-12]", "text": "분모가 10인 진분수와 연결하여 소수 한 자리 수를 이해하고 읽고 쓸 수 있다 . 수학과 교육과정 18", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "기타", "textLen": 57, "hasExp": false}, {"id": 314, "code": "[4수01-13]", "text": "자릿값의 원리를 바탕으로 소수 두 자리 수와 소수 세 자리 수를 이해하고 읽고 쓸 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "기타", "textLen": 52, "hasExp": false}, {"id": 315, "code": "[4수01-14]", "text": "소수의 크기를 비교하고 그 방법을 설명할 수 있다 . 숛 분수의 덧셈과 뺄셈", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "능력", "textLen": 42, "hasExp": false}, {"id": 316, "code": "[4수01-15]", "text": "분모가 같은 분수의 덧셈과 뺄셈의 계산 원리를 이해하고 그 계산을 할 수 있다 . 순 소수의 덧셈과 뺄셈", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "능력", "textLen": 58, "hasExp": false}, {"id": 317, "code": "[4수01-16]", "text": "소수 두 자리 수의 범위에서 소수의 덧셈과 뺄셈의 계산 원리를 이해하고 그 계산을 할 수 있다. 공통 교육과정 19•자연수의 덧셈, 뺄셈, 곱셈, 나눗셈을 하기 전에 계산 결과를 어림하기, 어림한 값을 이용하 여 계산 결과가 타당한지 확인하기, 어림셈이 필요한 실생활 상황의 문제를 해결하기 등을 다룰 수 있다. •친근한 실생활 상황을 이용하여 자연수의 덧셈, 뺄셈, 곱셈, 나눗셈에 관련된 문제를 만들어 해결하게 하고, 사칙계산의 유용성을 인식하게 한다. •실생활에서 소수를 활용한 사례를 통해 소수의 필요성을 인식하게 한다. •소수의 덧셈과 뺄셈은 계산 원리를 이해할 수 있는 수준에서 간단히 다룬다. •계산 기능을 숙달하는 것이 목적이 아닌 경우에는 계산기를 사용하게 할 수 있다. •‘수와 연산’ 영역의 문제 상황에 적합한 문제해결 전략을 지도하고, 문제해결 과정을 설명하게 하여 문제해결 역량을 기르게 한다.", "subject": "수학", "gradeGroup": "초3~4", "area": "수와 연산", "verb": "능력", "textLen": 457, "hasExp": false}, {"id": 318, "code": "[4수02-01]", "text": "다양한 변화 규칙을 찾아 설명하고 , 그 규칙을 수나 식으로 나타낼 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "변화와 관계", "verb": "기타", "textLen": 44, "hasExp": false}, {"id": 319, "code": "[4수02-02]", "text": "계산식의 배열에서 규칙을 찾고 , 계산 결과를 추측할 수 있다 . 숕 등호와 동치 관계", "subject": "수학", "gradeGroup": "초3~4", "area": "변화와 관계", "verb": "능력", "textLen": 48, "hasExp": true, "explanation": "다양한 규칙을 찾을 수 있는 계산식의 배열, 수의 성질을 탐구할 수 있는 계산 식의 배열을 다룬다."}, {"id": 320, "code": "[4수02-03]", "text": "등호를 사용하여 크기가 같은 두 양의 관계를 식으로 나타낼 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "변화와 관계", "verb": "기타", "textLen": 39, "hasExp": true, "explanation": "등호( )의 의미를 토대로 구체물, 그림 등을 사용하여 주어진 식이 옳은지 판 단하는 활동, 크기가 같은 두 양을 찾는 활동 등을 통해 동치 관계를 이해하게 한다."}, {"id": 321, "code": "[4수03-01]", "text": "직선, 선분, 반직선을 이해하고 구별할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 28, "hasExp": false}, {"id": 322, "code": "[4수03-02]", "text": "각과 직각을 이해하고 , 직각과 비교하는 활동을 통하여 예각과 둔각을 구별할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 49, "hasExp": false}, {"id": 323, "code": "[4수03-03]", "text": "직선의 수직 관계와 평행 관계를 이해한다 . 숕 평면도형의 이동", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "기타", "textLen": 35, "hasExp": false}, {"id": 324, "code": "[4수03-04]", "text": "구체물이나 평면도형의 밀기 , 뒤집기 , 돌리기 활동을 통하여 그 변화를 이해한다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "실생활에서 평면도형의 이동을 활용한 사례를 찾아서 이동에 따른 변화를 추론 하고 위치나 방향이 어떻게 변화했는지 설명하게 한다."}, {"id": 325, "code": "[4수03-05]", "text": "평면에서 점의 이동에 대해 위치와 방향을 이용하여 설명할 수 있다 . 숖 원의 구성 요소", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 49, "hasExp": true, "explanation": "평면에서 점의 이동은 격자를 따라 위, 아래, 오른쪽, 왼쪽으로 ‘∼칸’, ‘∼cm’를 이동하는 수준에서 다룬다. 한 점의 이동에 대해 위치와 방향을 설명하는 데 초점을 두고, 꼭짓점의 이동을 이용하여 평면도형의 이동을 설명하는 활동은 다루지 않는다."}, {"id": 326, "code": "[4수03-06]", "text": "원의 중심 , 반지름 , 지름을 이해하고 , 그 성질을 안다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "기타", "textLen": 35, "hasExp": false}, {"id": 327, "code": "[4수03-07]", "text": "컴퍼스를 이용하여 여러 가지 크기의 원을 그릴 수 있다 . 숗 여러 가지 삼각형", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "기타", "textLen": 44, "hasExp": true, "explanation": "컴퍼스를 사용하여 다양한 크기의 원을 그리는 방법을 원의 성질과 연결하여 이해하게 한다."}, {"id": 328, "code": "[4수03-08]", "text": "여러 가지 모양의 삼각형에 대한 분류 활동을 통하여 이등변삼각형 , 정삼각형을 이해하고 , 그 성질을 탐구하고 설명할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 72, "hasExp": false}, {"id": 329, "code": "[4수03-09]", "text": "여러 가지 모양의 삼각형에 대한 분류 활동을 통하여 직각삼각형 , 예각삼각형 , 둔각 삼각형을 이해한다 . 수 여러 가지 사각형", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "기타", "textLen": 71, "hasExp": false}, {"id": 330, "code": "[4수03-10]", "text": "여러 가지 모양의 사각형에 대한 분류 활동을 통하여 직사각형 , 정사각형 , 사다리꼴 , 평행 사변형 , 마름모를 이해하고 , 그 성질을 탐구하고 설명할 수 있다 . 공통 교육과정 21숙 다각형", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 108, "hasExp": false}, {"id": 331, "code": "[4수03-11]", "text": "다각형과 정다각형을 이해한다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "행위", "textLen": 17, "hasExp": true, "explanation": "도형판, 모양 조각 등의 교구를 이용한 구체적인 조작 활동을 통해 다각형과 정다각형을 이해하게 한다."}, {"id": 332, "code": "[4수03-12]", "text": "주어진 도형을 이용하여 여러 가지 모양을 만들거나 채우고 설명할 수 있다 . 숚 시각과 시간", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 51, "hasExp": true, "explanation": "다양한 교구와 공학 도구 등을 이용한 구체적인 활동을 통해 주어진 도형으로 여러 가지 모양을 다양하게 만들거나 채울 수 있다."}, {"id": 333, "code": "[4수03-13]", "text": "1 분과 1초의 관계를 이해하고 , 초 단위까지 시각을 읽을 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "기타", "textLen": 40, "hasExp": false}, {"id": 334, "code": "[4수03-14]", "text": "실생활 문제 상황과 연결하여 초 단위까지의 시간의 덧셈과 뺄셈을 할 수 있다 . 숛 길이", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 49, "hasExp": false}, {"id": 335, "code": "[4수03-15]", "text": "길이 단위 1mm 와 1km를 알고 , 이를 이용하여 길이를 측정하고 어림하며 수학의 유용성을 인식할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 63, "hasExp": false}, {"id": 336, "code": "[4수03-16]", "text": "1cm 와 1mm, 1km 와 1m의 관계를 이해하고 , 길이를 ‘몇 cm 몇 mm’와 ‘몇 mm’, ‘몇 km 몇 m’와 ‘몇 m’로 다양하게 표현할 수 있다 . 순 들이", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 96, "hasExp": false}, {"id": 337, "code": "[4수03-17]", "text": "들이 단위 1L와 1mL를 알고 , 이를 이용하여 들이를 측정하고 어림하며 수학의 유용성을 인식할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 61, "hasExp": false}, {"id": 338, "code": "[4수03-18]", "text": "1L 와 1mL의 관계를 이해하고 , 들이를 ‘몇 L 몇 mL’와 ‘몇 mL’로 표현할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 55, "hasExp": false}, {"id": 339, "code": "[4수03-19]", "text": "실생활 문제 상황과 연결하여 들이의 덧셈과 뺄셈을 할 수 있다 . 숝숦 무게", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 42, "hasExp": false}, {"id": 340, "code": "[4수03-20]", "text": "실생활에서 무게를 나타낼 때 사용하는 단위 1g과 1kg을 알고 , 이를 이용하여 무게를 측정하고 어림하며 수학의 유용성을 인식할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 79, "hasExp": true, "explanation": "초등학교에서는 무게와 질량의 개념을 엄밀하게 구분하지 않으며, 무게를 비교하고 측정하는 데에 g, kg의 단위를 사용하게 한다."}, {"id": 341, "code": "[4수03-21]", "text": "1kg 과 1g의 관계를 이해하고 , 무게를 ‘몇 kg 몇 g’과 ‘몇 g’으로 표현할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 55, "hasExp": false}, {"id": 342, "code": "[4수03-22]", "text": "실생활에서 무게를 나타낼 때 사용하는 단위 1t을 알고 , 1t과 1kg의 관계를 이해한다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "행위", "textLen": 52, "hasExp": false}, {"id": 343, "code": "[4수03-23]", "text": "실생활 문제 상황과 연결하여 무게의 덧셈과 뺄셈을 할 수 있다 . 숝숧 각도", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 42, "hasExp": false}, {"id": 344, "code": "[4수03-24]", "text": "각의 크기의 단위인 1도(°)를 알고 , 각도기를 이용하여 각의 크기를 측정하고 어림할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "능력", "textLen": 55, "hasExp": false}, {"id": 345, "code": "[4수03-25]", "text": "여러 가지 방법으로 삼각형과 사각형의 내각의 크기의 합을 추론하고 , 자신의 추론 과정을 설 명 할 수 있 다 . 수학과 교육과정 22", "subject": "수학", "gradeGroup": "초3~4", "area": "도형과 측정", "verb": "기타", "textLen": 75, "hasExp": false}, {"id": 346, "code": "[4수04-01]", "text": "자료를 수집하여 그림그래프나 막대그래프로 나타내고 해석할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "자료와 가능성", "verb": "능력", "textLen": 38, "hasExp": false}, {"id": 347, "code": "[4수04-02]", "text": "자료를 수집하여 꺾은선그래프로 나타내고 해석할 수 있다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "자료와 가능성", "verb": "능력", "textLen": 32, "hasExp": false}, {"id": 348, "code": "[4수04-03]", "text": "탐구 문제를 해결하기 위해 자료를 수집 , 정리하여 막대그래프나 꺾은선그래프로 나타내고 해 석 할 수 있 다 .", "subject": "수학", "gradeGroup": "초3~4", "area": "자료와 가능성", "verb": "기타", "textLen": 62, "hasExp": true, "explanation": "여러 가지 문제를 해결하기 위해 자료를 수집, 정리하고 그래프로 나타내어 해 석하는 일련의 과정을 직접 경험하게 한다. 자료의 크기를 비교할 때는 막대그래프로, 시간에 따른 변화의 경향을 알아볼 때는 꺾은선그래프로 나타내는 것이 편리함을 알고, 자료의 특성에 따라 목적에 맞는 적절한 그래프를 선택하게 한다."}, {"id": 349, "code": "[6수01-01]", "text": "덧셈, 뺄셈, 곱셈, 나눗셈의 혼합 계산에서 계산하는 순서를 알고 , 혼 합 계 산 을 할 수 있 다 . 숕 수의 범위와 올림 , 버림, 반올림", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "기타", "textLen": 80, "hasExp": false}, {"id": 350, "code": "[6수01-02]", "text": "실생활과 연결하여 이상 , 이하, 초과, 미만의 의미와 쓰임을 알고 , 이를 활용하여 수의 범위를 나타낼 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "기타", "textLen": 65, "hasExp": false}, {"id": 351, "code": "[6수01-03]", "text": "어림값을 구하기 위한 방법으로 올림 , 버림, 반올림의 의미와 필요성을 알고 , 이를 실생활에 활용함으로써 수학의 유용성을 인식할 수 있다 . 숖 약수와 배수", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 88, "hasExp": false}, {"id": 352, "code": "[6수01-04]", "text": "약수, 공약수 , 최대공약수를 이해하고 구할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 31, "hasExp": false}, {"id": 353, "code": "[6수01-05]", "text": "배수, 공배수 , 최소공배수를 이해하고 구할 수 있다 . 숗 분수의 덧셈과 뺄셈", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 44, "hasExp": false}, {"id": 354, "code": "[6수01-06]", "text": "크기가 같은 분수를 만드는 방법을 이해하고 , 분수를 약분 , 통분할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 45, "hasExp": false}, {"id": 355, "code": "[6수01-07]", "text": "분모가 다른 분수의 크기를 비교하고 그 방법을 설명할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 36, "hasExp": false}, {"id": 356, "code": "[6수01-08]", "text": "분모가 다른 분수의 덧셈과 뺄셈의 계산 원리를 탐구하고 그 계산을 할 수 있다 . 수 분수의 곱셈과 나눗셈", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 59, "hasExp": false}, {"id": 357, "code": "[6수01-09]", "text": "분수의 곱셈의 계산 원리를 탐구하고 그 계산을 할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 34, "hasExp": false}, {"id": 358, "code": "[6수01-10]", "text": "‘( 자연수 )÷(자연수 )’에서 나눗셈의 몫을 분수로 나타낼 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "기타", "textLen": 41, "hasExp": false}, {"id": 359, "code": "[6수01-11]", "text": "분수의 나눗셈의 계산 원리를 탐구하고 그 계산을 할 수 있다 . 숙 분수와 소수의 관계", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 48, "hasExp": true, "explanation": "분수의 나눗셈은 ‘(분수) ÷(자연수)’, ‘(자연수) ÷(분수)’, ‘(분수) ÷(분수)’를 다룬다."}, {"id": 360, "code": "[6수01-12]", "text": "분수와 소수의 관계를 이해하고 크기를 비교하며 그 방법을 설명할 수 있다 . 숚 소수의 곱셈과 나눗셈", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 56, "hasExp": false}, {"id": 361, "code": "[6수01-13]", "text": "소수의 곱셈의 계산 원리를 탐구하고 그 계산을 할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 34, "hasExp": false}, {"id": 362, "code": "[6수01-14]", "text": "‘( 자연수 )÷(자연수 )’에서 나눗셈의 몫을 소수로 나타낼 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "기타", "textLen": 41, "hasExp": false}, {"id": 363, "code": "[6수01-15]", "text": "소수의 나눗셈의 계산 원리를 탐구하고 그 계산을 할 수 있다 . 수학과 교육과정 26", "subject": "수학", "gradeGroup": "초5~6", "area": "수와 연산", "verb": "능력", "textLen": 47, "hasExp": true, "explanation": "소수의 나눗셈은 ‘(소수) ÷(자연수)’, ‘(자연수) ÷(소수)’, ‘(소수) ÷(소수)’를 다룬다."}, {"id": 364, "code": "[6수02-01]", "text": "한 양이 변할 때 다른 양이 그에 종속하여 변하는 대응 관계를 나타낸 표에서 규칙을 찾아 설명하고 , □, △ 등을 사용하여 식으로 나타낼 수 있다 . 숕 비와 비율", "subject": "수학", "gradeGroup": "초5~6", "area": "변화와 관계", "verb": "기타", "textLen": 92, "hasExp": false}, {"id": 365, "code": "[6수02-02]", "text": "두 양의 크기를 비교하는 상황을 통해 비의 개념을 이해하고 , 두 양의 관계를 비로 나타낼 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "변화와 관계", "verb": "기타", "textLen": 57, "hasExp": true, "explanation": "두 양을 비교할 때는 한 양을 기준으로 다른 양이 몇 배가 되는지를 나타낼 필 요성을 인식하면서 비의 개념을 이해하게 한다."}, {"id": 366, "code": "[6수02-03]", "text": "비율을 이해하고 , 비율을 분수 , 소수, 백분율로 나타낼 수 있다 . 숖 비례식과 비례배분", "subject": "수학", "gradeGroup": "초5~6", "area": "변화와 관계", "verb": "기타", "textLen": 51, "hasExp": false}, {"id": 367, "code": "[6수02-04]", "text": "비례식을 알고 , 그 성질을 이해하며 , 이를 활용하여 간단한 비례식을 풀 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "변화와 관계", "verb": "기타", "textLen": 48, "hasExp": false}, {"id": 368, "code": "[6수02-05]", "text": "비례배분을 알고 , 주어진 양을 비례배분 할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "변화와 관계", "verb": "능력", "textLen": 31, "hasExp": false}, {"id": 369, "code": "[6수03-01]", "text": "도형의 합동을 이해하고 , 합동인 도형의 성질을 탐구하고 설명할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "합동인 두 도형에서 대응점, 대응변, 대응각을 각각 찾게 하고 대응변의 길이 와 대응각의 크기를 비교하는 활동을 통해 합동인 도형의 성질을 탐구하고 설명하게 한다."}, {"id": 370, "code": "[6수03-02]", "text": "실생활과 연결하여 선대칭도형과 점대칭도형을 이해하고 그릴 수 있다 . 숕 직육면체와 정육면체", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "기타", "textLen": 51, "hasExp": false}, {"id": 371, "code": "[6수03-03]", "text": "직육면체와 정육면체를 이해하고 , 구성 요소와 성질을 탐구하고 설명할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 45, "hasExp": false}, {"id": 372, "code": "[6수03-04]", "text": "직육면체와 정육면체의 겨냥도와 전개도를 그릴 수 있다 . 숖 각기둥과 각뿔", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "기타", "textLen": 41, "hasExp": false}, {"id": 373, "code": "[6수03-05]", "text": "각기둥과 각뿔을 이해하고 , 구성 요소와 성질을 탐구하고 설명할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 42, "hasExp": false}, {"id": 374, "code": "[6수03-06]", "text": "각기둥의 전개도를 그릴 수 있다 . 숗 원기둥 , 원뿔, 구", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "기타", "textLen": 33, "hasExp": false}, {"id": 375, "code": "[6수03-07]", "text": "원기둥 , 원뿔, 구를 이해하고 , 구성 요소와 성질을 탐구하고 설명할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 46, "hasExp": false}, {"id": 376, "code": "[6수03-08]", "text": "원기둥의 전개도를 그릴 수 있다 . 수 입체도형의 공간 감각", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "기타", "textLen": 33, "hasExp": false}, {"id": 377, "code": "[6수03-09]", "text": "쌓기나무로 만든 입체도형을 보고 사용된 쌓기나무의 개수를 구할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 41, "hasExp": false}, {"id": 378, "code": "[6수03-10]", "text": "쌓기나무로 만든 입체도형의 위 , 앞, 옆에서 본 모양을 표현할 수 있고 , 이러한 표현을 보고 입체도형의 모양을 추측할 수 있다 . 공통 교육과정 29", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 85, "hasExp": true, "explanation": "여러 가지 물체, 건축물, 예술품, 쌓기나무로 만든 입체도형 등의 위, 앞, 옆에서 본 모양을 이용해서 전체 모양을 추측하게 하고, 이에 대해 자신의 추론 과정을 설명하게 한다."}, {"id": 379, "code": "[6수03-15]", "text": "여러 가지 원 모양 물체의 원주와 지름을 측정하는 활동을 통하여 , 원주율이 일정한 값임을 알고 그 근삿값을 사용할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 71, "hasExp": true, "explanation": "여러 가지 원에서 (원주) ÷(지름)의 값을 구하여 모든 원에서 원주율이 일정함 을 이해하게 하고, 원주율의 근삿값으로 3.14를 사용하게 한다."}, {"id": 380, "code": "[6수03-16]", "text": "원주와 원의 넓이를 구하는 방법을 이해하고 , 이를 구할 수 있다 . 숛 입체도형의 겉넓이와 부피", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 54, "hasExp": true, "explanation": "지름과 원주율을 이용하면 원주를 직접 측정하지 않고도 구할 수 있음을 알게 하고, 직사각형의 넓이를 구하는 방법을 이용하여 원의 넓이를 구하는 방법을 이해하게 한다."}, {"id": 381, "code": "[6수03-11]", "text": "평면도형의 둘레를 이해하고 , 기본적인 평면도형의 둘레를 구할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 41, "hasExp": false}, {"id": 382, "code": "[6수03-12]", "text": "넓이 단위 1cm², 1m², 1km² 를 알며 , 그 관계를 이해한다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "행위", "textLen": 41, "hasExp": false}, {"id": 383, "code": "[6수03-13]", "text": "직사각형과 정사각형의 넓이를 구하는 방법을 이해하고 , 이를 구할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 43, "hasExp": false}, {"id": 384, "code": "[6수03-14]", "text": "평행사변형 , 삼각형 , 사다리꼴 , 마름모의 넓이를 구하는 방법을 다양하게 추론하고 , 이와 관련된 문제를 해결할 수 있다 . 숚 원주율과 원의 넓이", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 84, "hasExp": false}, {"id": 385, "code": "[6수03-17]", "text": "직육면체와 정육면체의 겉넓이를 구하는 방법을 이해하고 , 이를 구할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 44, "hasExp": false}, {"id": 386, "code": "[6수03-18]", "text": "부피 단위 1cm³, 1m³ 를 알며 , 그 관계를 이해한다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "행위", "textLen": 35, "hasExp": false}, {"id": 387, "code": "[6수03-19]", "text": "직육면체와 정육면체의 부피를 구하는 방법을 이해하고 , 이를 구할 수 있다 . 수학과 교육과정 30•선대칭도형과 점대칭도형 그리기를 평가할 때 모눈종이, 점판, 공학 도구 등을 이용하여 쉽 게 그릴 수 있게 한다. •무늬 찾기, 종이 겹쳐 오리기, 도장 찍기, 데칼코마니 등 구체적인 조작 활동을 통하여 도형의 합동의 의미를 알게 한다. •실생활이나 자연 환경 등에서 도형의 합동, 선대칭도형, 점대칭도형의 예를 찾고 수학의 아름다움을 느낄 수 있게 한다. •입체도형의 전개도에 대한 평가는 전개도가 될 수 있는 것과 될 수 없는 것을 구별하는 데 중점을 둔다. •각기둥의 전개도는 간단한 형태만 다루고, 각뿔과 원뿔의 전개도는 다루지 않는다. •한 직선을 중심으로 직사각형, 직각삼각형, 반원을 돌리는 활동을 통하여 원기둥, 원뿔, 구를 만들어 보게 한다.", "subject": "수학", "gradeGroup": "초5~6", "area": "도형과 측정", "verb": "능력", "textLen": 424, "hasExp": false}, {"id": 388, "code": "[6수04-01]", "text": "평균의 의미를 알고 , 자료를 수집하여 평균을 구하고 해석할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "자료와 가능성", "verb": "능력", "textLen": 40, "hasExp": true, "explanation": "평균은 집단의 자료를 대표하는 값임을 이해하고, 여러 집단의 평균을 비교하 는 활동을 통해 수학의 유용성을 인식하게 한다."}, {"id": 389, "code": "[6수04-02]", "text": "자료를 수집하여 띠그래프나 원그래프로 나타내고 해석할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "자료와 가능성", "verb": "능력", "textLen": 36, "hasExp": false}, {"id": 390, "code": "[6수04-03]", "text": "탐구 문제를 설정하고 , 그에 맞는 자료를 수집 , 정리하여 적절한 그래프로 나타내고 해석할 수 있다 . 숕 가능성", "subject": "수학", "gradeGroup": "초5~6", "area": "자료와 가능성", "verb": "능력", "textLen": 64, "hasExp": true, "explanation": "해결하고자 하는 문제를 설정하고 그에 맞는 자료를 수집, 정리하여, 막대그래프, 꺾은선그래프, 띠그래프와 원그래프 중 적절한 그래프로 나타내고 해석하는 일련의 과정을 직접 경험하게 한다."}, {"id": 391, "code": "[6수04-04]", "text": "사건이 일어날 가능성을 말로 표현하고 비교할 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "자료와 가능성", "verb": "능력", "textLen": 31, "hasExp": true, "explanation": "‘확실하다’, ‘불가능하다’, ‘∼일 것 같다’, ‘∼아닐 것 같다’, ‘반반이다’ 등 일상에서 사건이 일어날 가능성을 나타내는 다양한 표현을 이해하고, 가능성의 크기를 비교하게 한다."}, {"id": 392, "code": "[6수04-05]", "text": "사건이 일어날 가능성을 수로 나타낼 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "자료와 가능성", "verb": "기타", "textLen": 26, "hasExp": true, "explanation": "가능성이 직관적으로 파악되는 생활 속의 간단한 사건에 대하여 그 가능성을 0, , 1 등과 같은 수로 표현하게 한다. 사건이 일어날 가능성과 일어나지 않을 가능성이 같은 경우에 사건이 일어날 가능성을 로 표현할 수 있음을 이해하게 한다."}, {"id": 393, "code": "[6수04-06]", "text": "자료를 이용하여 가능성을 예상하고 , 가능성에 근거하여 적절한 판단을 내릴 수 있다 .", "subject": "수학", "gradeGroup": "초5~6", "area": "자료와 가능성", "verb": "기타", "textLen": 48, "hasExp": true, "explanation": "제비뽑기, 동전 던지기, 주사위 던지기, 회전판 돌리기 등과 같은 간단한 실험 결과를 나타낸 표나 그래프를 보고 사건이 일어날 가능성을 비교하고 대략적으로 예상하게 한다."}, {"id": 394, "code": "[9수01-01]", "text": "소인수분해의 뜻을 알고 , 자연수를 소인수분해 할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "능력", "textLen": 34, "hasExp": false}, {"id": 395, "code": "[9수01-02]", "text": "소인수분해를 이용하여 최대공약수와 최소공배수를 구할 수 있다 . 숕 정수와 유리수", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "능력", "textLen": 45, "hasExp": true, "explanation": "초등학교에서 학습한 최대공약수와 최소공배수의 개념을 바탕으로 소인수분해를 이용하여 최대공약수와 최소공배수를 구하게 한다. 최대공약수와 최소공배수는 자연수의 소인수분해를 이용하는 범위에서 다루고, 최대공약수와 최소공배수의 활용 문제는 다루지 않는다."}, {"id": 396, "code": "[9수01-03]", "text": "다 양 한 상 황 을 이 용 하 여 음 수 의 필 요 성 을 인 식 하 고 , 양수와 음수 , 정수와 유리수의 개념을 이해한다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "행위", "textLen": 72, "hasExp": false}, {"id": 397, "code": "[9수01-04]", "text": "정수와 유리수의 대소 관계를 판단할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "능력", "textLen": 26, "hasExp": false}, {"id": 398, "code": "[9수01-05]", "text": "정수와 유리수의 사칙계산의 원리를 이해하고 , 그 계 산 을 할 수 있 다 . 숖 유리수와 순환소수", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "기타", "textLen": 55, "hasExp": true, "explanation": "정수의 사칙계산의 원리는 여러 가지 모델을 이용하여 직관적으로 이해하게 하고, 실생활에서 사칙계산의 유용성을 인식하게 한다."}, {"id": 399, "code": "[9수01-06]", "text": "순환소수의 뜻을 알고 , 유리수와 순환소수의 관계를 설명할 수 있다 . 숗 제곱근과 실수", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "능력", "textLen": 49, "hasExp": true, "explanation": "순환소수를 분수로 고치는 것은 순환소수가 유리수임을 이해할 수 있는 정도로 다룬다. 유한소수를 순환소수로 나타내는 것은 다루지 않는다. 수학과 교육과정 34"}, {"id": 400, "code": "[9수01-07]", "text": "제곱근의 뜻과 성질을 알고 , 제곱근의 대소 관계를 판단할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "능력", "textLen": 39, "hasExp": false}, {"id": 401, "code": "[9수01-08]", "text": "무리수의 개념을 이해하고 , 무리수의 유용성을 인식할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "능력", "textLen": 36, "hasExp": true, "explanation": "실생활에서 사용되는 무리수의 예를 찾아보는 활동을 통해 무리수의 필요성과 유용성을 인식하게 한다. 실수는 유리수와 무리수로 이루어짐을 이해하게 하고, 수 체계의 논리적인 아름다움에 관심을 갖게 한다."}, {"id": 402, "code": "[9수01-09]", "text": "실수의 대소 관계를 판단하고 설명할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "능력", "textLen": 26, "hasExp": false}, {"id": 403, "code": "[9수01-10]", "text": "근호를 포함한 식의 사칙계산의 원리를 이해하고 , 그 계 산 을 할 수 있 다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "수와 연산", "verb": "기타", "textLen": 45, "hasExp": false}, {"id": 404, "code": "[9수02-01]", "text": "다양한 상황을 문자를 사용한 식으로 나타내어 그 유용성을 인식하고 , 식의 값을 구할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 54, "hasExp": false}, {"id": 405, "code": "[9수02-02]", "text": "일차식의 덧셈과 뺄셈의 원리를 이해하고 , 그 계산을 할 수 있다 . 숕 일차방정식", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 46, "hasExp": false}, {"id": 406, "code": "[9수02-03]", "text": "방정식과 그 해의 뜻을 알고 , 등식의 성질을 설명할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 36, "hasExp": false}, {"id": 407, "code": "[9수02-04]", "text": "일차방정식을 풀 수 있고 , 이를 활용하여 문제를 해결할 수 있다 . 숖 좌표평면과 그래프", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 50, "hasExp": false}, {"id": 408, "code": "[9수02-05]", "text": "순서쌍과 좌표를 이해하고 , 그 편리함을 인식할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 33, "hasExp": true, "explanation": "실생활에서 좌표가 사용되는 예를 찾아보고 이를 수직선과 좌표평면 위에 표현 해 보며, 그 유용성과 편리함을 인식하게 한다."}, {"id": 409, "code": "[9수02-06]", "text": "다양한 상황을 그래프로 나타내고 , 주어진 그래프를 해석할 수 있다 . 공통 교육과정 35", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 50, "hasExp": true, "explanation": "다양한 상황을 그래프로 나타내어 증가와 감소, 주기적 변화 등 변화 상태를 쉽게 파악할 수 있게 한다. 주어진 그래프를 해석하여 그래프가 나타내는 상황을 설명하게 함으로써 그래프의 유용성을 인식하게 한다."}, {"id": 410, "code": "[9수02-07]", "text": "정비례 , 반비례 관계를 이해하고 , 그 관계를 표 , 식, 그래프로 나타낼 수 있다 . 숗 식의 계산", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "기타", "textLen": 57, "hasExp": true, "explanation": "속력과 거리, 속력과 시간과 같은 실생활의 예를 통해 정비례와 반비례 관계를 직관적으로 이해하게 하고, 정비례와 반비례 관계가 성립하는 실생활의 예를 찾아 설명하게 한다."}, {"id": 411, "code": "[9수02-08]", "text": "지수법칙을 이해하고 , 이를 이용하여 식을 간단히 할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 36, "hasExp": true, "explanation": "지수법칙은 지수가 자연수인 범위에서 단항식의 곱셈과 나눗셈을 하는 데 필요한 정도로 다룬다."}, {"id": 412, "code": "[9수02-09]", "text": "다항식의 덧셈과 뺄셈의 원리를 이해하고 , 그 계산을 할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 38, "hasExp": false}, {"id": 413, "code": "[9수02-10]", "text": "다항식의 나눗셈에서는 다항식을 단항식으로 나누어 그 몫이 다항식이 되는 경우만 다룬다.", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "기타", "textLen": 48, "hasExp": true, "explanation": "‘( 단항식 )×(다항식 )’, ‘(다항식 )÷(단항식 )’과 같은 곱셈과 나눗셈의 원리를 이해하고 , 그 계산을 할 수 있다 . 수 일차부등식"}, {"id": 414, "code": "[9수02-11]", "text": "부등식과 그 해의 뜻을 알고 , 부등식의 성질을 설명할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 37, "hasExp": false}, {"id": 415, "code": "[9수02-12]", "text": "일차부등식을 풀 수 있고 , 이를 활용하여 문제를 해결할 수 있다 . 숙 연립일차방정식", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 48, "hasExp": false}, {"id": 416, "code": "[9수02-13]", "text": "미지수가 2개인 연립일차방정식을 풀 수 있고 , 이를 활용하여 문제를 해결할 수 있다 . 숚 일차함수와 그 그래프", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 63, "hasExp": false}, {"id": 417, "code": "[9수02-14]", "text": "함수의 개념을 이해하고 , 함숫값을 구할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 29, "hasExp": false}, {"id": 418, "code": "[9수02-15]", "text": "일차함수의 개념을 이해하고 , 그 그래프를 그릴 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "기타", "textLen": 33, "hasExp": false}, {"id": 419, "code": "[9수02-16]", "text": "일차함수의 그래프의 성질을 이해하고 , 이를 활용하여 문제를 해결할 수 있다 . 숛 일차함수와 일차방정식의 관계", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 62, "hasExp": false}, {"id": 420, "code": "[9수02-17]", "text": "일차함수와 미지수가 2개인 일차방정식의 관계를 설명할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 36, "hasExp": false}, {"id": 421, "code": "[9수02-18]", "text": "두 일차함수의 그래프와 연립일차방정식의 관계를 설명할 수 있다 . 순 다항식의 곱셈과 인수분해", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 52, "hasExp": false}, {"id": 422, "code": "[9수02-19]", "text": "다항식의 곱셈과 인수분해를 할 수 있다 . 숝숦 이차방정식", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 32, "hasExp": true, "explanation": "다항식의 곱셈과 다항식의 인수분해의 역관계를 이해하고, 이와 유사한 관계를 찾아보는 활동을 하게 한다. 다항식의 곱셈과 인수분해는 다음의 경우를 다룬다.      "}, {"id": 423, "code": "[9수02-20]", "text": "이차방정식을 풀 수 있고 , 이를 활용하여 문제를 해결할 수 있다 . 숝숧 이차함수와 그 그래프", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 53, "hasExp": false}, {"id": 424, "code": "[9수02-21]", "text": "이차함수의 개념을 이해한다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "행위", "textLen": 16, "hasExp": false}, {"id": 425, "code": "[9수02-22]", "text": "이차함수의 그래프를 그릴 수 있고 , 그 성질을 설명할 수 있다 . 수학과 교육과정 36", "subject": "수학", "gradeGroup": "중1~3", "area": "변화와 관계", "verb": "능력", "textLen": 49, "hasExp": true, "explanation": "이차함수 에서 최댓값과 최솟값은 의 범위가 실수 전체인 경우만 다룬다."}, {"id": 426, "code": "[9수03-01]", "text": "점, 선, 면, 각과 관련된 용어는 다양한 상황에서 직관적으로 이해하게 한다.", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "기타", "textLen": 43, "hasExp": true, "explanation": "점, 선, 면, 각을 이해하고 , 실생활 상황과 연결하여 점 , 직선, 평면의 위치 관계를 설명할 수 있다 ."}, {"id": 427, "code": "[9수03-02]", "text": "평행선에서 동위각과 엇각의 성질을 이해하고 설명할 수 있다 . 숕 작도와 합동", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 43, "hasExp": false}, {"id": 428, "code": "[9수03-03]", "text": "삼각형을 작도하고 , 그 과정을 설명할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 28, "hasExp": true, "explanation": "주어진 삼각형과 합동인 삼각형을 작도하는 활동을 하고, 자신의 방법을 설명 하게 한다."}, {"id": 429, "code": "[9수03-04]", "text": "삼각형의 합동 조건을 이해하고 , 이를 이용하여 두 삼각형이 합동인지 판별할 수 있다 . 숖 평면도형의 성질", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 60, "hasExp": false}, {"id": 430, "code": "[9수03-05]", "text": "다각형의 성질을 이해하고 설명할 수 있다 . 수학과 교육과정 38", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 36, "hasExp": true, "explanation": "삼각형의 내각과 외각의 크기, 다각형의 내각과 외각의 크기의 합, 다각형의 대각선의 개수를 구하는 과정을 탐구하여 다각형의 성질을 추측하고 일반화할 수 있게 한다."}, {"id": 431, "code": "[9수03-06]", "text": "부채꼴의 중심각과 호의 관계를 이해하고 , 이를 이용하여 부채꼴의 호의 길이와 넓이를 구 할 수 있 다 . 숗 입체도형의 성질", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "기타", "textLen": 70, "hasExp": false}, {"id": 432, "code": "[9수03-07]", "text": "구체적인 모형이나 공학 도구를 이용하여 다면체와 회전체의 성질을 탐구하고 , 이를 설명할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 56, "hasExp": true, "explanation": "구체적인 사물, 전개도, 교구, 컴퓨터 프로그램 등을 이용하여 다면체와 회전체를 관찰하고 그 성질을 탐구하게 한다. 회전체 단면의 모양은 회전체의 성질을 이해하는 데 필요한 정도로 다룬다."}, {"id": 433, "code": "[9수03-08]", "text": "입체도형의 겉넓이와 부피를 구할 수 있다 . 수 삼각형과 사각형의 성질", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 39, "hasExp": false}, {"id": 434, "code": "[9수03-09]", "text": "이등변삼각형의 성질을 이해하고 정당화할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 28, "hasExp": true, "explanation": "종이접기, 작도, 공학 도구 등을 이용하여 이등변삼각형의 성질을 추측하게 하고, 그 성질을 삼각형의 합동 조건을 이용하여 정당화할 수 있게 한다. 이때, 증명이라는 용어를 도입하고, 그 필요성을 인식하게 한다."}, {"id": 435, "code": "[9수03-10]", "text": "삼각형의 외심과 내심의 성질을 이해하고 정당화할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 33, "hasExp": false}, {"id": 436, "code": "[9수03-11]", "text": "사각형의 성질을 이해하고 정당화할 수 있다 . 숙 도형의 닮음", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 34, "hasExp": true, "explanation": "사각형의 성질은 대각선에 관한 성질을 위주로 다룬다. 여러 가지 사각형의 성질을 통해 사각형 사이의 관계를 설명하게 한다."}, {"id": 437, "code": "[9수03-12]", "text": "도형의 닮음의 뜻과 닮은 도형의 성질을 이해하고 , 닮음비를 구할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 43, "hasExp": false}, {"id": 438, "code": "[9수03-13]", "text": "삼각형의 닮음 조건을 이해하고 , 이를 이용하여 두 삼각형이 닮음인지 판별할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 49, "hasExp": false}, {"id": 439, "code": "[9수03-14]", "text": "평행선 사이의 선분의 길이의 비를 구할 수 있다 . 숚 피타고라스 정리", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 39, "hasExp": false}, {"id": 440, "code": "[9수03-15]", "text": "피타고라스 정리를 이해하고 정당화할 수 있다 . 숛 삼각비", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 32, "hasExp": true, "explanation": "피타고라스 정리는 다양한 활동을 통하여 추측하고 정당화할 수 있게 한다. 피타고라스 정리의 역은 직관적으로 이해하게 하고, 이를 이용하여 세 변의 길이가 주어진 삼각형이 직각삼각형인지 판별하게 한다."}, {"id": 441, "code": "[9수03-16]", "text": "삼각비의 뜻을 알고 , 간단한 삼각비의 값을 구할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 34, "hasExp": false}, {"id": 442, "code": "[9수03-17]", "text": "삼각비를 활용하여 여러 가지 문제를 해결할 수 있다 . 순 원의 성질", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 38, "hasExp": true, "explanation": "삼각비를 활용하여 직접 측정하기 어려운 거리나 높이 등을 구해 보는 활동을 통해 유용성을 인식하고 흥미를 느낄 수 있게 한다."}, {"id": 443, "code": "[9수03-18]", "text": "원의 현에 관한 성질과 접선에 관한 성질을 이해하고 정당화할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 40, "hasExp": false}, {"id": 444, "code": "[9수03-19]", "text": "원주각의 성질을 이해하고 정당화할 수 있다 . 공통 교육과정 39", "subject": "수학", "gradeGroup": "중1~3", "area": "도형과 측정", "verb": "능력", "textLen": 36, "hasExp": false}, {"id": 445, "code": "[9수04-01]", "text": "중앙값 , 최빈값의 뜻을 알고 , 자료의 특성에 따라 적절한 대푯값을 선택하여 구할 수 있다 . 숕 도수분포표와 상대도수", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "능력", "textLen": 67, "hasExp": true, "explanation": "대푯값에는 초등학교에서 학습한 평균 이외에도 중앙값, 최빈값이 있음을 알고 그 필요성을 인식하게 한다. 자료의 특성에 따라 적절한 대푯값을 선택하여 구해 보고, 각 대푯값이 어떤 상황에서 유용하게 사용될 수 있는지 토론하게 한다."}, {"id": 446, "code": "[9수04-02]", "text": "자료를 줄기와 잎 그림 , 도수분포표 , 히스토그램 , 도수분포다각형으로 나타내고 해석할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "능력", "textLen": 56, "hasExp": false}, {"id": 447, "code": "[9수04-03]", "text": "상대도수를 구하고 , 상대도수의 분포를 표나 그래프로 나타내고 해석할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "능력", "textLen": 45, "hasExp": true, "explanation": "상대도수는 도수의 총합이 다른 두 집단의 분포를 비교하는 상황에서 간단히 다루고, 상대도수의 필요성과 유용성을 인식하게 한다."}, {"id": 448, "code": "[9수04-04]", "text": "통계적 탐구 문제를 설정하고 , 공학 도구를 이용하여 자료를 수집하여 분석하고 , 그 결과를 해석할 수 있다 . 숖 경우의 수와 확률", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "능력", "textLen": 74, "hasExp": true, "explanation": "다양한 맥락에서 해결하고자 하는 통계적 탐구 문제를 설정하고 적절한 계획을 세워 자료를 수집하게 한다. 수집한 자료를 자료의 특성과 목적에 맞게 표, 그래프, 수치 등으로 나타내어 분석하고, 그 결과를 탐구 문제와 연결하여 해석하게 한다. 자료를 수집하고 분석할 때는 인터넷 검색, 웹 기반 소프트웨어, 통계 프로그램 등을 활용하게 한다. 수집한 자료나 분석 결과가 적절한지 판단하여 계획을 수정하고, 통계적 근거를 바탕으로 토론하는 등 통계적 문제해결 과정에 주도적으로 참여하게 한다."}, {"id": 449, "code": "[9수04-05]", "text": "경우의 수를 구할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "능력", "textLen": 16, "hasExp": true, "explanation": "경우의 수는 두 경우의 수를 합하거나 곱하는 경우 정도로만 다루고, 순열과 조합을 이용하면 쉽게 해결되는 등의 복잡한 경우의 수를 구하는 문제는 다루지 않는다."}, {"id": 450, "code": "[9수04-06]", "text": "확률의 개념과 그 기본 성질을 이해하고 , 확률을 구할 수 있다 . 공통 교육과정 41", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "능력", "textLen": 48, "hasExp": true, "explanation": "확률은 실험이나 관찰을 통해 구한 상대도수로서의 의미와 경우의 수의 비율로서의 의미를 연결하여 이해하게 한다. 경우의 수의 비율로 확률을 다룰 때, 각 경우가 발생할 가능성이 동등하다는 것을 가정한다는 점에 유의하게 한다."}, {"id": 451, "code": "[9수04-08]", "text": "공학 도구를 이용하여 자료를 상자그림으로 나타내고 분포를 비교할 수 있다 .", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "상자그림을 다룰 때는 두 집단의 분포를 비교하고 해석하는 활동에 중점을 두고, 이를 통해 상자그림의 유용성을 인식하게 한다."}, {"id": 452, "code": "[9수04-09]", "text": "상관관계는 양의 상관관계, 음의 상관관계, 상관관계가 없는 경우로 구분하여 다룬다.", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "기타", "textLen": 46, "hasExp": true, "explanation": "자료를 산점도로 나타내고 상관관계를 말할 수 있다 . 수학과 교육과정 42산포도, 편차, 분산, 표준편차, 사분위수, 상자그림, 산점도, 상관관계’를 다룬다. •눈금 등을 부적절하게 사용하여 자료를 부정확하게 나타낸 표나 그래프에서 오류를 찾는 활동을 통해 비판적으로 사고하는 태도를 갖게 한다. •자료를 수집하고 정리하여 표나 그래프로 나타내거나 대푯값과 산포도를 구할 때 공학 도구를 이용할 수 있게 하고, 공학 도구의 편리함과 유용성을 인식하게 한다. •‘자료와 가능성’ 영역에서 환경, 지속가능한 발전 등 범교과 학습 주제를 소재로 다루고, 이를 탐구하는 과정에서 체계적으로 사고하고 합리적으로 의사 결정을 할 수 있게 한다. •진로연계교육을 실시할 때는 학생의 흥미, 관심, 진로에 맞는 탐구 문제를 설정하여 통계 프로젝트를 수행하게 할 수 있다. •‘계급값’, ‘경우의 수’ 용어는 교수 ⋅학습 상황에서 사용할 수 있다. 공통 교육과정 43 3. 교수 ⋅학습 및 평가"}, {"id": 453, "code": "[9수04-07]", "text": "분산과 표준편차를 구하고 자료의 분포를 설명할 수 있다 . 수 상자그림과 산점도", "subject": "수학", "gradeGroup": "중1~3", "area": "자료와 가능성", "verb": "능력", "textLen": 44, "hasExp": false}, {"id": 454, "code": "[4과01-01]", "text": "일상생활에서 힘과 관련된 현상에 흥미를 갖고 , 물체를 밀거나 당길 때 나타나는 현상을 관찰할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "능력", "textLen": 59, "hasExp": true, "explanation": "무거운 물체를 밀고 당길 때와 가벼운 물체를 밀고 당길 때 드는 힘의 크기 를 느끼는 데 중점을 둔다 ."}, {"id": 455, "code": "[4과01-02]", "text": "수평잡기 활동을 통해 물체의 무게를 비교할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "능력", "textLen": 30, "hasExp": false}, {"id": 456, "code": "[4과01-03]", "text": "무게와 질량을 구분하지 않으며 무게를 비교하는 단위로 g, ㎏을 사용한다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "무게를 정확히 비교하기 위해서는 저울이 필요함을 알고 , 저울을 사용해 무게를 비교할 수 있다."}, {"id": 457, "code": "[4과01-04]", "text": "지레, 빗면과 같은 도구를 이용하면 물체를 들어 올릴 때 드는 힘의 크기가 달라짐을 알고 , 도구가 일상생활에서 어떻게 쓰이는지 조사하여 공유할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "능력", "textLen": 87, "hasExp": true, "explanation": "지레, 빗면과 같은 간단한 도구를 이용할 때 힘의 크기가 달라진다는 점을 관찰하는 데 중점을 두며 , 도구의 원리나 구조적 특성을 다루지 않는다 ."}, {"id": 458, "code": "[4과02-01]", "text": "여러 가지 동물을 관찰하여 특징에 따라 동물을 분류할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "능력", "textLen": 36, "hasExp": true, "explanation": "동물의 형태적 특징을 찾고 그 특징에 따라 분류 기준을 정하여 분류하는 활동을 하도록 하며 생물학적 분류 체계는 다루지 않는다 ."}, {"id": 459, "code": "[4과02-02]", "text": "다양한 환경에 서식하는 동물을 조사하여 동물의 생김새와 생활 방식이 환경과 관련되어 있음을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "능력", "textLen": 61, "hasExp": true, "explanation": "서식지에 따른 동물의 생김새와 생활 방식의 다양성을 다루고 , 적응 개념은 다루지 않는다 ."}, {"id": 460, "code": "[4과02-03]", "text": "동물의 특징을 이용하여 일상생활에서 활용할 수 있는 생활용품을 설계하여 협력적으로 소 통 할 수 있 다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "기타", "textLen": 59, "hasExp": false}, {"id": 461, "code": "[4과03-01]", "text": "여러 가지 식물을 관찰하여 특징에 따라 식물을 분류할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 36, "hasExp": true, "explanation": "여러 가지 식물의 잎을 채집해 생김새 등과 같은 외형적 특징에 따라 기준을 세워 분류하는 활동을 하며 생물학적 분류 체계는 다루지 않는다 ."}, {"id": 462, "code": "[4과03-02]", "text": "다양한 환경에 서식하는 식물을 조사하여 식물의 생김새와 생활 방식이 환경과 관련되어 있음을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 61, "hasExp": true, "explanation": "서식지에 따른 식물의 생김새와 생활 방식의 다양성을 다루고 , 적응 개념은 다루지 않는다 ."}, {"id": 463, "code": "[4과03-03]", "text": "식물의 특징을 이용하여 일상생활에서 활용할 수 있는 생활용품을 설계하여 협력적으로 소 통 할 수 있 다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "기타", "textLen": 59, "hasExp": false}, {"id": 464, "code": "[4과04-01]", "text": "동물의 한살이를 직접 관찰하고 , 관찰한 내용을 글과 그림으로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "능력", "textLen": 45, "hasExp": false}, {"id": 465, "code": "[4과04-02]", "text": "식물이 자라는 데 필요한 조건을 찾는 실험을 설계하여 수행할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "능력", "textLen": 40, "hasExp": true, "explanation": "씨가 싹트는데 필요한 조건은 물과 온도로 한정하고 , 식물이 자라는데 필요 한 조건은 물과 햇빛으로 제한한다 ."}, {"id": 466, "code": "[4과04-03]", "text": "생물의 한살이 과정을 조사하여 생물에 따라 한살이의 유형이 다양함을 소개하는 자료를 만들어 공유할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "능력", "textLen": 61, "hasExp": true, "explanation": "한살이의 유형을 이해하는 생물의 범위는 동물과 식물에 한정하여 다루고 , 식물의 한살이 유형은 한해살이와 여러해살이로 구분하여 이해하도록 한다 ."}, {"id": 467, "code": "[4과05-01]", "text": "물체를 이루는 여러 가지 물질의 성질을 비교하고 , 물질의 종류에 따라 물체를 분류할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "과학과 사회", "verb": "능력", "textLen": 54, "hasExp": true, "explanation": "나무, 철, 유리, 플라스틱 등 학생들이 일상생활에서 쉽게 접할 수 있는 물 질의 다양한 성질을 관찰하고 비교하는 활동에 중점을 두고 , 이를 바탕으로 여러 가지 물 체를 물질의 종류에 따라 분류하도록 한다 ."}, {"id": 468, "code": "[4과05-02]", "text": "물질의 세 가지 상태인 고체 , 액체, 기체의 성질을 관찰하여 비교할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "과학과 사회", "verb": "능력", "textLen": 45, "hasExp": true, "explanation": "물질의 세 가지 상태인 고체 , 액체, 기체의 성질을 관찰하고 비교하는 활동에 중점을 두고 , 한 가지 물질이 여러 가지 상태로 존재한다는 것은 다루지 않는다 ."}, {"id": 469, "code": "[4과05-03]", "text": "다양한 물질의 성질을 이용하여 쓰임새 있는 물체를 설계할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "과학과 사회", "verb": "능력", "textLen": 38, "hasExp": false}, {"id": 470, "code": "[4과06-01]", "text": "지구가 대기로 둘러싸여 있음을 알고 , 지구 표면을 구성하는 육지와 바다의 특징을 비교 할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "능력", "textLen": 57, "hasExp": false}, {"id": 471, "code": "[4과06-02]", "text": "바닷물의 침식 , 운반, 퇴적 작용에 대해서는 다루지 않는다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "기타", "textLen": 35, "hasExp": true, "explanation": "바닷물의 특징을 육지의 물과 비교하고 , 바닷가에서 볼 수 있는 다양한 지형을 조사할 수 있다 ."}, {"id": 472, "code": "[4과06-03]", "text": "밀물과 썰물의 차이를 알고 , 갯벌의 가치와 보전의 필요성을 설득 ⋅홍보할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "능력", "textLen": 48, "hasExp": true, "explanation": "밀물과 썰물은 바닷물의 높이 변화를 다루는 수준이며 , 조석 용어와 원인에 대해서는 다루지 않는다 ."}, {"id": 473, "code": "[4과07-01]", "text": "여러 가지 물체를 이용하여 소리를 내보고 , 소리가 나는 물체는 떨림이 있음을 설명할 수 있다.", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "능력", "textLen": 53, "hasExp": false}, {"id": 474, "code": "[4과07-02]", "text": "큰 소리와 작은 소리 , 높은 소리와 낮은 소리를 구분하고 , 세기와 높낮이가 다른 소리를 낼 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "기타", "textLen": 59, "hasExp": false}, {"id": 475, "code": "[4과07-03]", "text": "여러 가지 물질을 통하여 소리가 전달되는 것을 관찰하고 , 소음을 줄이는 방법을 찾아 일상생활에서 실천할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "능력", "textLen": 65, "hasExp": true, "explanation": "소리가 여러 가지 물질을 통해 전달되는 현상을 관찰하는 데 중점을 두며 , 소리 전달의 과학적 원리는 다루지 않도록 한다 ."}, {"id": 476, "code": "[4과08-01]", "text": "생활 속 감염병의 사례를 알고 , 다양한 질병과 그 위험성에 대해 토의할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 47, "hasExp": true, "explanation": "질병은 예방접종이나 범유행 상황 등 학생이 경험하거나 인지할 수 있는 생 활 속 질병을 다룬다 ."}, {"id": 477, "code": "[4과08-02]", "text": "감염병으로부터 안전한 사회에 관심을 가지고 , 여러 감염 과정을 통해 생활 습관과 감염병 유행과의 연관성을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 70, "hasExp": true, "explanation": "감염 과정은 생활 습관과 관련지을 수 있는 접촉 감염 , 비말 감염 , 공기 감염 , 수인 감염 , 타액 감염 등의 사례로 한정하여 다루며 , 감염병의 특성과 면역 반응을 구체 적으로 다루지 않는다 ."}, {"id": 478, "code": "[4과08-03]", "text": "건강한 생활을 위해 필요한 감염병 예방 수칙을 공유하고 , 생활 속에서 실천할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 50, "hasExp": false}, {"id": 479, "code": "[4과09-01]", "text": "자석과 여러 가지 물체를 가까이했을 때 나타나는 현상을 관찰하고 , 자석과 자석에 붙는 물체 사이에 작용하는 힘의 특징을 말할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "능력", "textLen": 77, "hasExp": false}, {"id": 480, "code": "[4과09-02]", "text": "자석과 자석을 가까이했을 때 나타나는 현상을 관찰하여 그 특징을 자석의 극과 관련지어 설 명 할 수 있 다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "기타", "textLen": 61, "hasExp": false}, {"id": 481, "code": "[4과09-03]", "text": "자석을 이용하여 일상생활을 편리하게 하는 장치를 설계할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "운동과 에너지", "verb": "능력", "textLen": 37, "hasExp": false}, {"id": 482, "code": "[4과10-01]", "text": "물이 세 가지 상태로 변할 수 있음을 알고 , 우리 주변에서 예를 찾을 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "기타", "textLen": 46, "hasExp": true, "explanation": "물의 상태 변화는 관찰 가능한 현상 수준에서만 다루고 , 물의 상태가 변하는 까닭은 다루지 않는다 ."}, {"id": 483, "code": "[4과10-02]", "text": "물이 얼 때 , 얼음이 녹을 때 , 물이 증발할 때와 끓을 때 , 수증기가 응결할 때의 변화를 관 찰 할 수 있 다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "기타", "textLen": 66, "hasExp": true, "explanation": "물이 얼 때와 얼음이 녹을 때의 부피 변화는 물기둥의 높이 변화로 관찰하 도록 한다 . 물의 증발과 끓음을 비교할 때는 물이 수증기로 상태가 변하는 현상이라는 공 통점에 중점을 둔다 ."}, {"id": 484, "code": "[4과10-03]", "text": "물의 상태 변화를 이용하여 물을 얻을 수 있는 장치를 설계하고 만들 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "기타", "textLen": 44, "hasExp": false}, {"id": 485, "code": "[4과11-01]", "text": "흐르는 물의 작용과 강 주변 지형의 특징을 관련지을 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "기타", "textLen": 35, "hasExp": true, "explanation": "강 주변 지형은 흐르는 물에 의한 침식 , 운반, 퇴적 작용을 중심으로 다룬다 ."}, {"id": 486, "code": "[4과11-02]", "text": "화산 활동과 화산 분출물을 중심으로 학습한다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "행위", "textLen": 26, "hasExp": true, "explanation": "화산의 의미와 화산 활동으로 나오는 물질을 알고 , 화산 활동을 모형으로 표현할 수 있다 ."}, {"id": 487, "code": "[4과11-03]", "text": "화성암을 관찰하고 분류할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "능력", "textLen": 20, "hasExp": true, "explanation": "화성암은 현무암과 화강암만 다룬다 ."}, {"id": 488, "code": "[4과11-04]", "text": "화산 활동과 지진이 우리 생활에 미치는 영향을 조사하여 , 대 처 방 법 을 실 천 할 수 있 다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "기타", "textLen": 56, "hasExp": true, "explanation": "화산 활동의 피해와 이로운 점을 함께 다루며 , 지진 발생 원인은 다루지 않는다."}, {"id": 489, "code": "[4과12-01]", "text": "균류⋅원생생물 ⋅세균을 관찰하여 특징과 사는 곳을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 38, "hasExp": false}, {"id": 490, "code": "[4과12-02]", "text": "균류⋅원생생물 ⋅세균이 우리 생활에 미치는 영향을 조사하여 발표할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 43, "hasExp": false}, {"id": 491, "code": "[4과12-03]", "text": "우리 생활에 생명과학이 이용되는 사례를 소개하는 자료를 만들어 공유할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 45, "hasExp": true, "explanation": "우리 생활에 생명과학이 이용되는 사례는 균류 , 원생생물 , 세균을 중심으로 학생들이 생활 속에서 경험하고 인지할 수 있는 수준으로 다룬다 ."}, {"id": 492, "code": "[4과13-01]", "text": "달의 모양과 표면 , 달의 위상변화를 관찰하여 밤하늘 관찰에 흥미를 가질 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "기타", "textLen": 47, "hasExp": true, "explanation": "달의 위상변화 원인을 다루지 않고 , 달의 모양이 주기적으로 바뀌는 현상을 관찰하여 확인하는 데 초점을 둔다 ."}, {"id": 493, "code": "[4과13-02]", "text": "태양계 구성원을 알고 , 태양과 행성을 조사할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "능력", "textLen": 32, "hasExp": true, "explanation": "태양계를 구성하는 행성들의 표면적인 특징 위주로 조사하고 , 태양과 행성의 실제 크기나 태양에서 행성까지의 실제 거리 , 행성의 질량 , 자전 속도 , 대기 성분 등과 • 해캄과 짚신벌레 관찰하기 공통 교육과정 23같은 구체적인 물리량은 다루지 않는다 ."}, {"id": 494, "code": "[4과13-03]", "text": "별의 정의를 알고 , 북극성 주변의 별자리를 관찰할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "지구와 우주", "verb": "능력", "textLen": 35, "hasExp": true, "explanation": "별의 정의는 행성과 비교하여 스스로 빛을 내는 천체라는 수준에서만 다룬"}, {"id": 495, "code": "[4과14-01]", "text": "생태계의 구성 요소를 조사하여 생물 요소와 비생물 요소로 분류할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "숲, 바다, 강 등 다양한 생태계를 다루고 , 각 생태계에서 생물 요소와 비생물 요소를 분류할 수 있게 한다 ."}, {"id": 496, "code": "[4과14-02]", "text": "생물 요소들의 먹고 먹히는 관계를 조사하여 먹이그물로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 40, "hasExp": true, "explanation": "생태계에서 다양한 먹이 관계를 알아보고 먹이 관계가 복잡할수록 생물이 생 존하는 데 유리함을 이해하게 한다 ."}, {"id": 497, "code": "[4과14-03]", "text": "인간 활동이 생태계에 미치는 영향을 조사하고 , 생태계 보전을 위해 우리가 할 수 있는 일을 토의하여 실천할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "생명", "verb": "능력", "textLen": 67, "hasExp": true, "explanation": "대기오염 , 수질오염 , 토양오염 등의 환경오염에 관한 사례를 중심으로 다루고 , 생태계 보전을 위해 우리가 해야 할 일을 조사하여 실천함으로써 생태계 보전에 대한 의식을 가지게 한다 . 과학과 교육과정 24"}, {"id": 498, "code": "[4과15-01]", "text": "실험을 통해 기체가 무게가 있음을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "능력", "textLen": 29, "hasExp": true, "explanation": "부피가 같은 용기에 공기를 1기압으로 담은 상태와 이 상태에서 공기를 넣 거나 뺀 상태의 무게를 비교하는 실험을 바탕으로 기체가 무게가 있음을 설명한다 ."}, {"id": 499, "code": "[4과15-02]", "text": "온도나 압력에 따라 기체의 부피가 달라지는 현상을 관찰하고 , 우리 주변에서 예를 찾을 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "기타", "textLen": 55, "hasExp": true, "explanation": "온도를 높일 때와 낮출 때 공기의 부피 변화 , 압력을 높일 때와 낮출 때 공기 의 부피 변화를 관찰하도록 한다 . 온도나 압력에 따라 기체의 부피가 어떻게 변하는지를 정 성적으로 이해하도록 하고 , 입자 모형으로 기체의 부피가 변하는 까닭은 설명하지 않는다 ."}, {"id": 500, "code": "[4과15-03]", "text": "일상생활에서 이용되는 기체의 종류와 성질을 조사하고 , 여러 가지 기체에 대해 흥미를 느 낄 수 있 다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "기타", "textLen": 59, "hasExp": false}, {"id": 501, "code": "[4과15-04]", "text": "기체의 성질을 이용하여 작동시킬 수 있는 장치를 설계하고 만들 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "물질", "verb": "기타", "textLen": 41, "hasExp": false}, {"id": 502, "code": "[4과16-01]", "text": "기후변화 현상의 예를 알고 , 기후변화가 인간의 활동과 관련되어 있음을 토의할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "과학과 사회", "verb": "능력", "textLen": 50, "hasExp": true, "explanation": "기후변화의 과학적 원인은 다루지 않으며 기온 , 강수량 등 기후요소가 평년 값에 비해 현저히 높거나 낮은 사례 (가뭄, 폭설, 폭염, 한파, 홍수 등 )를 탐구하도록 한다 ."}, {"id": 503, "code": "[4과16-02]", "text": "기후변화의 심각성에 관심을 가지고 , 기후변화가 우리 생활과 환경에 미치는 영향을 설 명 할 수 있 다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "과학과 사회", "verb": "기타", "textLen": 59, "hasExp": true, "explanation": "인간의 삶에 부정적인 영향을 미치는 기후변화 현상의 사례를 모형이나 실험 활동을 통해 알아보고 , 이에 기반하여 기후변화로 인한 인간의 피해를 예측하고 설명할 수 있도록 한다 ."}, {"id": 504, "code": "[4과16-03]", "text": "기후변화 대응 방법을 조사하고 , 생활 속에서 기후변화 대응 방법을 실천할 수 있다 .", "subject": "과학", "gradeGroup": "초3~4", "area": "과학과 사회", "verb": "능력", "textLen": 48, "hasExp": false}, {"id": 505, "code": "[6과01-01]", "text": "지층의 특징을 알고 , 지층의 형성 과정을 모형으로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 39, "hasExp": true, "explanation": "지층의 두께나 색 등을 다루고 , 지층이 휘어지거나 끊어진 모습을 소개하되 생성 원리는 다루지 않는다 ."}, {"id": 506, "code": "[6과01-02]", "text": "퇴적암은 이암 , 사암, 역암만 다룬다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "기타", "textLen": 23, "hasExp": true, "explanation": "지층이 퇴적암으로 이루어짐을 알고 , 퇴적암을 알갱이의 크기에 따라 분류할 수 있다 ."}, {"id": 507, "code": "[6과01-03]", "text": "화석의 생성 과정을 모형으로 설명하고 , 지구의 과거 생물과 환경을 추리하는 활동을 통해 화석의 가치를 인식할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 68, "hasExp": true, "explanation": "화석 표본은 동물과 식물의 특징이 분명하게 드러나는 것을 사용한다 ."}, {"id": 508, "code": "[6과02-01]", "text": "물체를 보기 위해서 빛이 있어야 함을 알고 , 빛의 성질에 대해 흥미를 느낄 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "기타", "textLen": 49, "hasExp": false}, {"id": 509, "code": "[6과02-02]", "text": "빛이 나아가는 현상을 관찰하여 빛이 직진 , 반사, 굴절하는 성질이 있음을 말할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "능력", "textLen": 51, "hasExp": true, "explanation": "빛이 직진 , 반사, 굴절하는 성질은 햇빛이나 레이저 광선의 진행으로 나타나 는 현상을 관찰하여 알 수 있도록 하되 , 반사와 굴절의 법칙은 다루지 않는다 . 또, 볼록 렌즈와 물체 사이의 거리 , 볼록렌즈와 눈 사이의 거리에 따른 물체의 모습 차이는 다루지 않는다 ."}, {"id": 510, "code": "[6과02-03]", "text": "거울과 렌즈의 쓰임새를 조사하고 거울이나 렌즈를 이용한 장치를 창의적으로 만들 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "기타", "textLen": 50, "hasExp": false}, {"id": 511, "code": "[6과03-01]", "text": "용해 현상의 의미를 알고 , 용질의 종류와 물의 온도에 따라 물에 녹는 용질의 양이 달라 짐 을 비 교 할 수 있 다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "생명", "verb": "기타", "textLen": 67, "hasExp": true, "explanation": "용질, 용매, 용액, 용해의 개념을 다루되 , 입자 모형으로 용해 현상을 설명하 거나 용해 현상이 일어나는 과학적 이유나 원리를 설명하지 않는다 . 용해 전과 후의 무게를 비교하여 용해 과정에서 물질이 사라지지 않음을 이해하도록 한다 .• 렌즈를 이용하여 빛의 굴절 실험하기 과학과 교육과정 28"}, {"id": 512, "code": "[6과03-02]", "text": "용질이나 용매의 양에 따라 용액의 진하기가 달라짐을 관찰하고 , 용액의 상대적인 진하 기 를 비 교 할 수 있 다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "생명", "verb": "기타", "textLen": 65, "hasExp": true, "explanation": "진하기가 다른 두 용액에서 같은 물체의 뜨는 정도가 다름을 이용하여 용액의 상대적인 진하기를 비교하도록 한다 ."}, {"id": 513, "code": "[6과03-03]", "text": "일상생활에서 용액이 쓰이는 사례를 조사하여 용액의 필요성을 알리는 자료를 만들고 공 유 할 수 있 다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "생명", "verb": "기타", "textLen": 58, "hasExp": false}, {"id": 514, "code": "[6과04-01]", "text": "뼈와 근육의 생김새를 관찰하고 모형을 만들어 몸이 움직이는 원리를 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "능력", "textLen": 47, "hasExp": true, "explanation": "중학교와 고등학교 과정에서는 뼈와 근육에 대해서 학습하지 않으므로 , 뼈와 근육의 구조와 기능을 기초적으로 이해하는 데 중점을 둔다 ."}, {"id": 515, "code": "[6과04-02]", "text": "우리 몸의 각 기관은 종류 , 위치, 생김새 , 기능을 중심으로 탐구한다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "소화, 순환, 호흡, 배설 기관의 구조와 기능을 알아보고 , 우리 몸의 여러 기관이 서로 관 련되어 있음을 설명할 수 있다 ."}, {"id": 516, "code": "[6과04-03]", "text": "우리 몸의 여러 기관과 관련된 질병을 조사하고 , 건강을 유지하기 위한 생활 방식을 실 천 할 수 있 다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "기타", "textLen": 60, "hasExp": true, "explanation": "질병은 소화 , 순환, 호흡, 배설 기관과 관련된 것으로 조사하고 건강을 유지 하기 위한 생활 방식은 각 질병의 예방법을 중심으로 다룬다 ."}, {"id": 517, "code": "[6과05-01]", "text": "알갱이의 크기가 다른 고체 혼합물과 골고루 섞이지 않는 액체 혼합물을 분리할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "과학과 사회", "verb": "능력", "textLen": 49, "hasExp": true, "explanation": "혼합물의 의미를 학습한 뒤 혼합물의 분리 실험을 진행하도록 한다 . 혼합물은 두 가지 이상의 물질이 성질이 변하지 않고 섞여 있는 상태라는 수준에서 다룬다 . 골고루 섞이지 않는 액체 혼합물 분리에서 액체가 골고루 섞이지 않는 까닭은 다루지 않는다 ."}, {"id": 518, "code": "[6과05-02]", "text": "물에 용해되는 성질을 이용하여 고체 혼합물을 분리하고 , 물을 증발시켜 물에 용해된 고체 물질을 분리할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "과학과 사회", "verb": "능력", "textLen": 64, "hasExp": false}, {"id": 519, "code": "[6과05-03]", "text": "지속가능한 삶을 위한 과학기술 사례 중 혼합물의 분리를 이용한 장치를 조사하여 공유 할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "과학과 사회", "verb": "능력", "textLen": 55, "hasExp": false}, {"id": 520, "code": "[6과06-01]", "text": "기상 요소를 조사하고 , 날씨가 우리 생활에 주는 영향을 인식할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "기상 요소는 기온 , 바람, 습도, 구름의 양 , 강수량을 중심으로 다루고 , 기상 자료에서 규칙성을 파악하도록 한다 ."}, {"id": 521, "code": "[6과06-02]", "text": "이슬, 안개, 구름을 관찰하고 , 공통점과 차이점을 찾을 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "기타", "textLen": 38, "hasExp": true, "explanation": "구름에서 비와 눈이 내리는 과정을 다루지 않고 현상을 중심으로 다루며 , 단열 팽창과 관련된 구름의 생성 과정은 다루지 않는다 ."}, {"id": 522, "code": "[6과06-03]", "text": "고기압과 저기압의 분포에 따른 날씨의 특징을 기상 요소로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "고기압과 저기압의 날씨와 고기압에서 저기압으로 부는 바람의 방향을 이해 하는 수준에서 현상 중심으로 다룬다 ."}, {"id": 523, "code": "[6과07-01]", "text": "물체의 따뜻하고 차가운 정도를 온도로 표현함을 알고 , 온도계를 이용하여 온도를 측정 할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 56, "hasExp": false}, {"id": 524, "code": "[6과07-02]", "text": "온도가 다른 두 물체가 접촉했을 때 두 물체의 온도 변화를 관찰하고 그 원인을 추리할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 54, "hasExp": true, "explanation": "온도가 다른 두 물체를 접촉하는 탐구에서는 두 물체의 온도 변화를 측정하는 데 중점을 두고 , 물체의 온도가 변하는 원인이 온도가 높은 물체에서 온도가 낮은 물체로 열이 이동하기 때문이라는 사실을 추리하도록 한다 . 단, 열평형이라는 용어는 사용하지 않는다 ."}, {"id": 525, "code": "[6과07-03]", "text": "주위에서 열의 이동으로 나타나는 현상을 관찰하여 열의 이동 방식이 다양함을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 52, "hasExp": true, "explanation": "전도, 대류, 복사는 고체 , 액체, 기체에서의 열의 이동과 , 빛에 의한 열 이동 현상을 관찰하는 데 중점을 두고 다룬다 ."}, {"id": 526, "code": "[6과07-04]", "text": "일상생활에서 단열을 이용하는 사례를 조사하고 , 온도를 오랫동안 일정하게 유지할 수 있는 장치를 창의적으로 만들 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "기타", "textLen": 69, "hasExp": false}, {"id": 527, "code": "[6과08-01]", "text": "우리가 생활에서 이용하는 다양한 자원을 조사하고 , 자원의 유한함을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "과학과 사회", "verb": "능력", "textLen": 48, "hasExp": false}, {"id": 528, "code": "[6과08-02]", "text": "재생에너지의 종류를 조사하고 , 에너지를 지속가능하게 이용하는 방법에 관심을 갖는다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "과학과 사회", "verb": "태도", "textLen": 48, "hasExp": true, "explanation": "재생에너지는 태양 에너지 , 풍력, 수력, 해양 에너지 , 지열 에너지 , 바이오 에너지 등을 의미한다 ."}, {"id": 529, "code": "[6과08-03]", "text": "자원과 에너지의 효율적인 이용 방법에 대해 탐색하고 , 생활 속에서 실천할 수 있는 다 양한 사례를 공유할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "과학과 사회", "verb": "능력", "textLen": 66, "hasExp": true, "explanation": "효율적인 자원의 이용 방법에서 물 자원과 산림 자원 , 광물 자원을 종합적으로 다루며 , 학생들이 배운 내용을 바탕으로 생활 속에서 자원의 소중함을 느끼고 , 효율적인 이용 방법을 공유하고 실천할 수 있도록 한다 ."}, {"id": 530, "code": "[6과09-01]", "text": "여러 가지 용액에 지시약을 넣었을 때의 변화를 관찰하여 용액을 산성 용액과 염기성 용 액으로 분류할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "능력", "textLen": 62, "hasExp": true, "explanation": "리트머스 시험지 , 페놀프탈레인 용액 , 붉은 양배추 용액 등과 같은 지시약의 색깔 변화를 이용하여 여러 가지 용액을 산성 용액과 염기성 용액으로 분류하도록 한다 ."}, {"id": 531, "code": "[6과09-02]", "text": "산성 용액과 염기성 용액의 성질을 관찰하고 , 산성 용액과 염기성 용액을 섞을 때 용액 의 성질 변화를 실험을 통해 추론할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "능력", "textLen": 75, "hasExp": true, "explanation": "산성 용액은 탄산 칼슘과 반응하고 염기성 용액은 단백질과 반응하는 성질을 중심으로 다룬다 . 산성 용액과 염기성 용액을 섞을 때 용액의 성질 변화에서 지시약이 들어 있는 용액의 색깔이 변하는 현상을 관찰하는 수준에서만 다루고 중성 , pH, 중화 개념은 다루지 않는다 ."}, {"id": 532, "code": "[6과09-03]", "text": "우리 주변에서 산성 용액과 염기성 용액을 이용하는 예를 찾아서 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "능력", "textLen": 45, "hasExp": false}, {"id": 533, "code": "[6과09-04]", "text": "산성화로 인한 환경의 피해 사례를 소개하는 자료를 만들고 공유할 수 있다 . 공통 교육과정 33", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "능력", "textLen": 53, "hasExp": false}, {"id": 534, "code": "[6과10-01]", "text": "운동하는 물체는 시간에 따라 위치가 변화함을 알고 그 변화를 표현할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 44, "hasExp": true, "explanation": "시간에 따라 위치가 변하는 다양한 운동을 다루면서 처음 위치와 나중 위치를 간단한 좌표 평면 위에 표현하되 두 위치 사이의 거리는 구하지 않는다 ."}, {"id": 535, "code": "[6과10-02]", "text": "물체의 이동 거리와 걸린 시간을 측정하여 속력을 구하고 빠르기를 비교할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 46, "hasExp": true, "explanation": "물체의 속력을 구할 때 물체가 한 길을 따라 한 방향으로 운동하는 경우만 다루며 , 속력의 단위 변환에 중점을 두지 않는다 ."}, {"id": 536, "code": "[6과10-03]", "text": "속력과 관련된 안전 수칙과 안전장치를 조사한 결과를 공유하고 일상생활에서 교통안전을 실천할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 57, "hasExp": false}, {"id": 537, "code": "[6과11-01]", "text": "생물을 이루고 있는 기본 단위인 세포를 현미경으로 관찰할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "생명", "verb": "능력", "textLen": 38, "hasExp": true, "explanation": "세포 관찰은 식물 세포로 하고 , 세포의 구조는 핵 , 세포막 , 세포벽을 용어 수준에서 다룬다 ."}, {"id": 538, "code": "[6과11-02]", "text": "식물의 각 기관의 구조를 관찰하고 , 기능을 알아보는 실험을 수행하여 식물 각 기관의 구조와 기능을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "생명", "verb": "능력", "textLen": 66, "hasExp": true, "explanation": "식물의 기관에서 물과 양분의 이동을 탐구하면서 식물의 기관이 서로 연결되어 있음을 다룬다 .• 같은 시간 동안에 물체가 이동한 거리 비교하기 공통 교육과정 35"}, {"id": 539, "code": "[6과11-03]", "text": "여러 가지 식물의 특징을 설명하는 자료를 만들어 공유할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "생명", "verb": "능력", "textLen": 37, "hasExp": true, "explanation": "학생들이 관심 있는 식물의 구조와 기능을 관찰하거나 조사하고 이를 설명하는 자료를 만들어 발표하고 공유하게 한다 ."}, {"id": 540, "code": "[6과12-01]", "text": "하루 동안 태양과 별을 관찰하여 위치 변화의 규칙성을 찾을 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "기타", "textLen": 39, "hasExp": true, "explanation": "남쪽 하늘을 바라보는 관측자 관점에서 태양과 별의 위치가 달라지는 현상을 중심으로 다룬다 ."}, {"id": 541, "code": "[6과12-02]", "text": "지구의 자전을 알고 , 낮과 밤이 생기는 이유를 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "능력", "textLen": 37, "hasExp": true, "explanation": "지구의 자전에서는 지구가 자전축이 기울어진 채 하루에 한 바퀴 도는 것을 중심으로 다룬다 ."}, {"id": 542, "code": "[6과12-03]", "text": "지구의 공전을 알고 , 계절에 따라 달라지는 별자리를 관찰할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "능력", "textLen": 40, "hasExp": true, "explanation": "별자리 명칭보다는 계절에 따라 보이는 별자리와 별자리의 위치가 달라지는 까닭을 이해하는 데 초점을 둔다 . 과학과 교육과정 36"}, {"id": 543, "code": "[6과13-01]", "text": "태양 고도 측정기로 하루 동안 태양 고도 , 그림자 길이 , 기온을 측정하여 이들의 관계를 찾 을 수 있 다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "기타", "textLen": 62, "hasExp": false}, {"id": 544, "code": "[6과13-02]", "text": "계절에 따른 태양의 남중 고도와 낮의 길이 사이의 관계를 자료에 근거하여 추론할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "능력", "textLen": 51, "hasExp": false}, {"id": 545, "code": "[6과13-03]", "text": "계절 변화의 원인을 지구의 자전축이 기울어진 채 공전하는 것으로 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "지구와 우주", "verb": "능력", "textLen": 46, "hasExp": true, "explanation": "지구 자전축이 기울어진 채 공전하기 때문에 계절에 따라 태양의 남중 고도가 달라져 지표가 받는 태양 에너지의 차이로 계절의 변화가 생김을 이해하게 한다 ."}, {"id": 546, "code": "[6과14-01]", "text": "물질의 성질이 달라지는 변화와 달라지지 않는 변화를 관찰하여 비교할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "능력", "textLen": 44, "hasExp": true, "explanation": "서로 다른 물질을 섞었을 때 물질의 성질이 달라지는 변화를 활용한 재미있고 간단한 실험을 실시한다 . 물질을 섞은 후 물질의 성질이 달라지는 까닭은 다루지 않으며 , 물리 변화나 화학 변화 용어를 도입하지 않는다 ."}, {"id": 547, "code": "[6과14-02]", "text": "양초, 알코올 , 나무 등과 같은 물질의 연소를 중심으로 다룬다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "기타", "textLen": 37, "hasExp": true, "explanation": "물질이 연소할 때 나타나는 공통적인 현상을 관찰하고 , 연소의 조건을 찾을 수 있다 ."}, {"id": 548, "code": "[6과14-03]", "text": "연소 전과 후의 물질을 비교하여 연소 과정에서 물질의 성질이 달라짐을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "능력", "textLen": 49, "hasExp": true, "explanation": "물이나 이산화 탄소와 같은 연소 생성물은 염화 코발트 종이나 석회수 등을 이용한 실험으로 확인하고 , 그을음은 연소 생성물로 다루지 않는다 ."}, {"id": 549, "code": "[6과14-04]", "text": "연소 과정에서 생성되는 물질로 인한 생태계의 피해 사례를 수집하고 분석하여 해결책을 제안하고 공유할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "물질", "verb": "능력", "textLen": 62, "hasExp": true, "explanation": "생태계의 피해 사례는 연소 생성물 중 이산화 탄소로 인한 피해 사례를 중 심으로 조사한다 ."}, {"id": 550, "code": "[6과15-01]", "text": "전지와 전구 , 전선을 연결하여 전구에 불을 켜보고 , 불이 켜지는 전기 회로의 특징을 말 할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 59, "hasExp": false}, {"id": 551, "code": "[6과15-02]", "text": "전구의 직렬연결과 병렬연결은 다루지 않고 , 전지의 연결은 직렬연결만 다룬다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "기타", "textLen": 44, "hasExp": true, "explanation": "전지 한 개를 연결한 전기 회로와 전지 두 개를 직렬연결한 전기 회로의 특징을 비교할 수 있다 ."}, {"id": 552, "code": "[6과15-03]", "text": "전자석을 만들어 전자석의 성질을 탐색하고 전자석이 사용되는 예를 조사할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 46, "hasExp": true, "explanation": "전자석은 전지를 이용하여 제작하고 , 전지의 수에 따라 전자석의 세기가 달라 지는 현상 , 전지의 연결 방향에 따라 전자석의 극이 달라지는 현상을 관찰하여 영구 자석 과의 차이를 비교하도록 하되 , 전류에 의한 자기장 개념은 도입하지 않는다 ."}, {"id": 553, "code": "[6과15-04]", "text": "전기를 효율적이고 안전하게 사용하는 방법을 조사하여 실천 계획을 세우고 일상생활에서 실천할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "운동과 에너지", "verb": "능력", "textLen": 57, "hasExp": false}, {"id": 554, "code": "[6과16-01]", "text": "단순한 상상이 아니라 현재의 다양한 정보를 기반으로 미래 사회의 문제를 예상해보도록 한다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "과학과 사회", "verb": "기타", "textLen": 51, "hasExp": true, "explanation": "미래 사회에 일어날 수 있는 문제를 조사하고 , 문 제 를 해 결 하 는 데 과 학 이 기 여 할 수 있 는 방법을 토의할 수 있다 ."}, {"id": 555, "code": "[6과16-02]", "text": "다양한 진로가 과학과 관련됨을 알고 , 자신의 진로를 과학과 관련지어 설명할 수 있다 .", "subject": "과학", "gradeGroup": "초5~6", "area": "과학과 사회", "verb": "능력", "textLen": 49, "hasExp": true, "explanation": "과학자와 관련된 직업을 다루는 것이 아니라 학생이 희망하는 다양한 직업을 기준으로 하여 해당 직업과 관련된 과학적 요소를 찾도록 한다 ."}, {"id": 556, "code": "[9과01-01]", "text": "과학적 탐구 방법을 이해하고 , 일상생활의 문제에 대한 과학적 해결 방안을 제안할 수 있다.", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 51, "hasExp": true, "explanation": "간단한 탐구 실험을 제시하여 탐구 절차 및 방법을 익히도록 하며 , 학생이 스스로 발견한 문제를 일정 기간 동안 지속적으로 탐구하여 해결해 보는 기회를 제공할 수 있다 ."}, {"id": 557, "code": "[9과01-02]", "text": "과학의 발전이 인류 문명에 미친 영향을 이해하고 , 인공지능 등 첨단 과학기술이 가져올 미래 사회의 변화를 조사하여 발표할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 75, "hasExp": true, "explanation": "과학적 탐구 방법을 통해 얻은 과학 지식과 방법이 인류 문명과 문화 발달에 미친 영향을 중심으로 학습하고 , 원리보다는 활용 측면에서 첨단 과학기술 사례를 함께 다룬다 ."}, {"id": 558, "code": "[9과01-03]", "text": "인류의 지속가능한 삶을 위한 과학기술의 중요성과 역할에 대해 토의하고 , 개인과 사회 차원의 활동 방안을 찾아 실천할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 72, "hasExp": false}, {"id": 559, "code": "[9과02-01]", "text": "세포는 생명 활동이 일어나는 기본 단위임을 이해하고 , 세포의 구조와 기능의 관계를 추 론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 58, "hasExp": true, "explanation": "세포의 구조는 세포벽 , 세포막 , 핵, 엽록체 , 미토콘드리아를 , 세포의 특징으 로는 생명 활동을 유추할 수 있는 세포 (적혈구 , 신경세포 , 상피세포 등 )를 다룬다 ."}, {"id": 560, "code": "[9과02-02]", "text": "생물의 유기적 구성 단계를 이해하고 , 동물과 식물을 비교하여 분석할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 45, "hasExp": false}, {"id": 561, "code": "[9과02-03]", "text": "생물다양성을 이해하고 , 변이와 생물다양성의 관계를 추론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 39, "hasExp": false}, {"id": 562, "code": "[9과02-04]", "text": "종의 개념과 분류 체계를 이해하고 , 생물을 계 수준에서 분류할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "종은 생물학적 종 개념만을 , 생물 분류 체계는 5계만을 다루도록 한다 ."}, {"id": 563, "code": "[9과02-05]", "text": "생물다양성 보전의 필요성을 이해하고 , 생물다양성 유지를 위한 방안을 조사하고 실천할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 54, "hasExp": false}, {"id": 564, "code": "[9과03-01]", "text": "온도와 열평형 과정을 물질을 구성하는 입자들의 배치나 움직임 등으로 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 48, "hasExp": true, "explanation": "온도가 다른 두 물체가 열평형에 도달하는 과정을 시간 -온도 그래프 등을 활용하여 설명할 수 있도록 한다 ."}, {"id": 565, "code": "[9과03-02]", "text": "열은 전도 , 대류, 복사로 전달됨을 알고 , 열전달 과정을 모형 등을 사용하여 다양하게 표 현할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 61, "hasExp": true, "explanation": "열의 이동 방식을 주변 도구나 신체를 이용하여 비유적으로 다양하게 표현하고 , 그 차이를 설명할 수 있도록 한다 ."}, {"id": 566, "code": "[9과03-03]", "text": "물질에 따라 비열과 열팽창 정도가 다름을 알고 , 이러한 성질이 일상생활에서 유용하게 활용됨을 인식할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 63, "hasExp": false}, {"id": 567, "code": "[9과04-01]", "text": "확산 및 증발 현상을 관찰하여 물질을 구성하는 입자가 운동하고 있음을 추론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 49, "hasExp": false}, {"id": 568, "code": "[9과04-02]", "text": "물질의 세 가지 상태의 특징을 설명하고 , 이를 입자 모형으로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 45, "hasExp": true, "explanation": "물질의 상태를 나타내는 입자 모형은 입자 사이의 상대적 거리 , 입자 배열의 불규칙한 정도 , 입자의 운동성 등을 비교한 내용을 포함한다 ."}, {"id": 569, "code": "[9과04-03]", "text": "여러 가지 물질의 상태 변화를 관찰하고 , 이를 입자 모형으로 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 45, "hasExp": true, "explanation": "여러 가지 물질의 상태 변화를 관찰하여 융해 , 응고, 기화, 액화, 승화를 구 분하고 , 물질의 상태가 변할 때 부피는 변하고 질량과 물질의 성질은 변하지 않는 이유를 입자 모형으로 설명한다 ."}, {"id": 570, "code": "[9과04-04]", "text": "물질의 상태 변화와 열에너지 출입 관계를 이해하고 , 이를 실생활에 적용하여 과학의 유 용성을 인식할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 63, "hasExp": true, "explanation": "물질의 상태 변화 시 온도가 일정한 이유를 상태 변화 과정에서 출입하는 열에너지와 관련지어 설명한다 ."}, {"id": 571, "code": "[9과05-01]", "text": "물체에 작용하는 힘을 화살표를 이용하여 나타내고 , 힘의 평형을 이루는 조건을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "과학과 사회", "verb": "능력", "textLen": 54, "hasExp": true, "explanation": "힘의 정의를 알고 힘을 크기와 방향으로 나타낼 수 있도록 하며 , 나란한 힘의 합력만을 다루도록 한다 ."}, {"id": 572, "code": "[9과05-02]", "text": "중력을 지도할 때 , 질량과 무게를 구별하도록 한다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "과학과 사회", "verb": "기타", "textLen": 30, "hasExp": true, "explanation": "중력, 탄성력 , 마찰력 , 부력을 이해하고 , 각 힘의 특징을 크기와 방향으로 설명할 수 있다 ."}, {"id": 573, "code": "[9과05-03]", "text": "알짜힘이 0이 아닐 때 물체의 운동 상태가 변함을 알고 , 그 예를 조사하여 분류할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "과학과 사회", "verb": "능력", "textLen": 53, "hasExp": true, "explanation": "물체가 힘을 받았을 때 물체의 운동을 속력이 변하거나 운동 방향이 바뀌거나 두 가지가 모두 변하는 사례로 분류하도록 한다 ."}, {"id": 574, "code": "[9과05-04]", "text": "다양한 사례에서 작용하는 힘과 힘의 평형 관계를 설명하고 , 일상생활에서 힘의 특징을 이용한 기구나 장치를 설계할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "과학과 사회", "verb": "능력", "textLen": 70, "hasExp": true, "explanation": "바닥에 놓인 물체에 작용하는 힘을 설명할 때 , 중력과 함께 바닥이 물체를 떠받치는 힘을 도입한다 ."}, {"id": 575, "code": "[9과06-01]", "text": "압력의 의미를 알고 , 기체의 압력을 입자의 운동으로 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 40, "hasExp": true, "explanation": "압력의 의미는 일상생활에서 경험할 수 있는 예시로 설명하고 , 기체의 압력은 일정한 면적에 입자의 충돌로 가해지는 힘의 수준에서 다룬다 . •[9과06-02 ∼03] 기체의 압력과 부피 , 기체의 온도와 부피를 측정한 각각의 실험 결과에서 두 변인 간 관계를 찾고 그 이유를 입자 모형으로 설명한다 ."}, {"id": 576, "code": "[9과06-02]", "text": "기체의 압력과 부피 관계를 실험 결과로부터 알아내고 , 이를 입자 모형 으 로 해 석할 수 있다.", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 54, "hasExp": false}, {"id": 577, "code": "[9과06-03]", "text": "기체의 온도와 부피 관계를 실험 결과로부터 알아내고 , 이를 입자 모형 으 로 해 석할 수 있다.", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 54, "hasExp": false}, {"id": 578, "code": "[9과07-01]", "text": "태양계를 구성하는 천체의 특징을 알고 , 행성을 목성형 행성과 지구형 행성으로 구분할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 54, "hasExp": true, "explanation": "태양계를 구성하는 천체인 태양 , 행성, 왜소행성 , 소행성 , 위성, 혜성을 개괄 적으로 학습하며 , 자세한 특징은 다루지 않는다 ."}, {"id": 579, "code": "[9과07-02]", "text": "태양의 표면과 대기에서 일어나는 현상을 알고 , 태양의 활동이 지구에 미치는 영향을 추 론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 58, "hasExp": false}, {"id": 580, "code": "[9과07-03]", "text": "지구 자전에 의한 천체의 겉보기 운동과 지구 공전에 의한 별자리 변화를 이해하고 , 밤 하늘 천체에 호기심을 가진다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "태도", "textLen": 66, "hasExp": true, "explanation": "관측자의 위치 (고위도 , 저위도 , 중위도 )에 따른 일주운동은 다루지 않는다 . 지구의 자전과 공전을 우주에서 바라보는 관점으로 설명한다 ."}, {"id": 581, "code": "[9과07-04]", "text": "달을 관측하여 달의 위상변화 원리를 이해하고 , 일식과 월식을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 45, "hasExp": false}, {"id": 582, "code": "[9과08-01]", "text": "물질의 특성의 의미를 알고 , 실험을 통해 밀도 , 용해도 , 녹는점 , 끓는점 등을 설명할 수 있다.", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 57, "hasExp": true, "explanation": "물질의 특성은 특정한 조건에서 항상 일정한 값을 가지며 물질의 양에 따라 달라지지 않는 것으로 물질을 구분하는 중요한 정보가 됨을 이해하고 , 그 사례로 밀도 , 용해도 , 녹는점 , 끓는점 등이 있음을 다룬다 ."}, {"id": 583, "code": "[9과08-02]", "text": "물질의 특성을 근거로 우리 주변의 물질을 순물질과 혼합물로 분류할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 43, "hasExp": false}, {"id": 584, "code": "[9과08-03]", "text": "물질의 특성을 이용하여 혼합물이 분리되는 원리를 이해하고 , 이를 이용한 사례를 주변 에서 찾을 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "기타", "textLen": 60, "hasExp": false}, {"id": 585, "code": "[9과09-01]", "text": "지구계의 구성 요소를 알고 , 지권의 층상 구조와 그 특징을 조사 ⋅발표할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 48, "hasExp": true, "explanation": "지구계의 구성 요소 및 지권을 구성하는 각 층의 명칭과 상태만 다루며 , 지구 내부구조 탐사에서 지진파의 특성은 다루지 않는다 ."}, {"id": 586, "code": "[9과09-02]", "text": "조암 광물의 주요 특성을 관찰하고 , 암석과 광물의 활용 방안 및 자원으로서 가치에 대해 조사할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 60, "hasExp": true, "explanation": "광물의 특성은 색 , 조흔색 , 굳기, 염산 반응 , 자성만 다루고 , 굳기는 방해석과 석영 정도만 비교하여 제시한다 ."}, {"id": 587, "code": "[9과09-03]", "text": "지각을 이루는 암석을 생성 과정에 따라 분류하고 , 암석의 순환 과정을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 50, "hasExp": true, "explanation": "지각에 분포하는 다양한 암석 중 , 화성암은 현무암 , 유문암 , 화강암 , 반려암을 , 퇴적암은 이암 , 사암, 역암, 석회암을 , 변성암은 편암 , 편마암 , 대리암 , 규암만을 대표적으로 다룬다 ."}, {"id": 588, "code": "[9과09-04]", "text": "풍화 과정을 이해하고 , 토양 생성 과정을 풍화 작용의 예로 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 44, "hasExp": false}, {"id": 589, "code": "[9과09-05]", "text": "대륙이동설을 이해하고 , 지진과 화산이 발생하는 지역의 분포를 판의 경계와 관련지어 설 명 할 수 있 다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "기타", "textLen": 60, "hasExp": true, "explanation": "화산대와 지진대의 분포가 판의 경계와 일치한다는 정도만 다루고 , 판의 경계 에서 나타나는 다양한 지질학적 특성은 고등학교 ‘지구과학 ’에서 다룬다 ."}, {"id": 590, "code": "[9과10-01]", "text": "실험을 통해 빛의 반사 , 굴절의 특징을 확인하고 , 굴절 법칙은 정량적으로 다루지 않는다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "기타", "textLen": 52, "hasExp": true, "explanation": "빛의 반사와 굴절의 원리를 이해하고 , 물체를 보는 과정을 빛의 경로를 이용하여 표현할 수 있다 ."}, {"id": 591, "code": "[9과10-02]", "text": "평면거울에서 상이 생기는 원리를 설명하고 , 일상생활에서 사용되는 거울과 렌즈의 종류를 분류하고 상의 특징을 비교할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 71, "hasExp": true, "explanation": "상이 생기는 원리는 평면거울에 의한 상만을 빛의 반사 법칙을 적용하여 이 해하도록 한다 . 다양한 거울과 렌즈에 의해 생기는 상의 위치나 크기를 정량적으로 계산 하거나 실상과 허상을 구분하는 활동은 하지 않고 , 정성적인 특징을 다양한 예를 통해 비 교하도록 한다 ."}, {"id": 592, "code": "[9과10-03]", "text": "물체의 색을 빛의 반사와 관련지어 설명하고 , 영상 장치에서 빛의 합성을 이용하여 다양한 색이 표현되는 원리를 이해할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 72, "hasExp": false}, {"id": 593, "code": "[9과10-04]", "text": "파동의 발생과 전달 과정을 이해하고 , 소리의 특성을 진폭 , 진동수 , 파형 등의 과학적 용 어로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 66, "hasExp": true, "explanation": "소리는 파동의 일종으로 매질을 통해 전달됨을 설명하고 , 다양한 소리의 파 형을 비교하여 파동의 진폭 , 진동수 , 파장의 개념을 설명하도록 한다 . 종파와 횡파를 구 분하여 설명하지는 않는다 ."}, {"id": 594, "code": "[9과11-01]", "text": "원소와 화합물의 정의를 알고 , 원소와 화합물을 화학식으로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 43, "hasExp": false}, {"id": 595, "code": "[9과11-02]", "text": "질량수나 동위 원소는 다루지 않는다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "기타", "textLen": 21, "hasExp": true, "explanation": "원소를 구성하는 입자인 원자는 양성자 , 중성자 , 전자로 구성되며 , 양성자의 수에 따라 원소의 종류가 달라짐을 입자 모형을 활용하여 설명할 수 있다 ."}, {"id": 596, "code": "[9과11-03]", "text": "원소는 양성자의 수에 따라 주기율표에 배치됨을 알고 , 주기율표에서 성질이 유사한 원소를 찾을 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "기타", "textLen": 59, "hasExp": true, "explanation": "동족 원소의 유사성은 1족 원소의 물과의 반응성 , 18족 원소의 안정성 등 비슷한 성질을 지닌 원소들이 있음을 탐구를 통해 추론하고 , 각 반응에 관한 구체적 설명 이나 원리 및 원소의 주기성은 다루지 않는다 ."}, {"id": 597, "code": "[9과11-04]", "text": "물질을 이루는 입자는 원자 , 분자, 이온 등으로 존재할 수 있음을 알고 , 이온은 전하를 띠고 있음을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 68, "hasExp": true, "explanation": "이온의 경우 원자가 전기적으로 중성임을 토대로 전자를 잃으면 양이온이 되고 , 전자를 얻으면 음이온이 된다는 수준에서 다룬다 ."}, {"id": 598, "code": "[9과12-01]", "text": "광합성 과정을 이해하고 , 환경 요인과 광합성의 관계를 탐구하는 실험을 설계할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 50, "hasExp": false}, {"id": 599, "code": "[9과12-02]", "text": "식물의 호흡과 광합성의 관계를 이해하고 , 호흡과 광합성 과정에서 출입하는 에너지와 물질의 변화를 분석할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 65, "hasExp": false}, {"id": 600, "code": "[9과12-03]", "text": "광합성 산물의 저장과 이용 과정을 이해하고 , 모형으로 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 41, "hasExp": true, "explanation": "광합성 결과 만들어진 산물은 생명 활동에 필요한 에너지원임을 강조하여 다룬다 ."}, {"id": 601, "code": "[9과13-01]", "text": "소화계의 구조와 기능을 이해하고 , 소화 과정을 소화 효소의 작용과 관련지어 추론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 53, "hasExp": true, "explanation": "소화 기관에서 일어나는 소화 과정은 아밀레이스 , 펩신, 트립신 , 라이페이스 등 대표적인 몇 가지 소화 효소 중심으로 간단하게 언급한다 ."}, {"id": 602, "code": "[9과13-02]", "text": "순환계의 구조와 기능을 이해하고 , 혈액의 순환 경로를 종합하여 발표할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 46, "hasExp": false}, {"id": 603, "code": "[9과13-03]", "text": "호흡계의 구조와 기능을 이해하고 , 호흡 운동의 원리를 나타내는 모형을 만들 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "기타", "textLen": 49, "hasExp": false}, {"id": 604, "code": "[9과13-04]", "text": "배설계의 구조와 기능을 이해하고 , 노폐물이 배설되는 과정을 모식도로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 49, "hasExp": false}, {"id": 605, "code": "[9과13-05]", "text": "동물이 세포호흡을 통해 에너지를 얻는 과정을 소화 , 순환, 호흡, 배설과 관련지어 통합적 으로 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 64, "hasExp": true, "explanation": "각 기관계의 구조와 기능에 대한 자세한 언급보다는 에너지를 얻기 위한 통 합적 관계에 중점을 두고 다룬다 ."}, {"id": 606, "code": "[9과14-01]", "text": "마찰 전기 , 정전기 유도 현상을 관찰하고 , 이를 전기력과 원자 모형을 이용하여 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 56, "hasExp": false}, {"id": 607, "code": "[9과14-02]", "text": "전기 회로에서 전류를 모형으로 설명하고 , 실험을 통해 저항 , 전류, 전압 사이의 관계를 이끌어낼 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "기타", "textLen": 62, "hasExp": true, "explanation": "일상생활에 활용되는 다양한 물질의 저항이 다름을 도체와 부도체의 예를 들어 설명하고 , 반도체를 소개한다 ."}, {"id": 608, "code": "[9과14-03]", "text": "저항의 직렬연결과 병렬연결의 특징을 비교하고 , 일상생활에서 전기 에너지가 다양한 형 태의 에너지로 전환됨을 소비 전력과 관련지어 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 83, "hasExp": true, "explanation": "저항의 연결에 따른 합성 저항의 정량적인 계산과 혼합 연결은 다루지 않는다 . 소비 전력은 정량적인 계산보다는 에너지 전환 관점에서 다루도록 하고 , 효율적인 전기 사용의 중요성을 인식하도록 한다 . 공통 교육과정 53"}, {"id": 609, "code": "[9과14-04]", "text": "자기장 안에 놓인 전류가 흐르는 코일이 받는 힘의 특성을 추리하고 , 전 동 기 등 일 상 생 활에서 활용한 예를 찾을 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "기타", "textLen": 73, "hasExp": true, "explanation": "코일을 이용하여 전류의 세기와 방향에 따른 자기장의 세기와 방향을 정성적 으로 확인하고 , 전류가 흐르는 코일과 자석의 상호작용 관점에서 전동기의 원리를 이해하 도록 한다 ."}, {"id": 610, "code": "[9과15-01]", "text": "연주시차를 이용하여 별까지의 거리를 구할 수 있고 , 별의 등급과 밝기의 관계 및 표면 온도와 색의 관계를 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 70, "hasExp": true, "explanation": "별까지의 거리를 구하는 방법은 수식을 도입하지 않으며 , 연주시차와 겉보기 등급과 절대등급의 개념을 중심으로 다룬다 . 별의 표면 온도는 별의 색을 이용하여 비교 하는 수준으로만 다룬다 ."}, {"id": 611, "code": "[9과15-02]", "text": "우리은하의 구조와 크기를 이해하고 , 성운과 성단의 특징을 비교할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 43, "hasExp": false}, {"id": 612, "code": "[9과15-03]", "text": "모형을 이용하여 우주가 팽창하고 있음을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 32, "hasExp": true, "explanation": "우주 팽창과 관련된 심화 내용 (적색 편이 , 허블 법칙 , 가속 팽창 등 )은 다루지 않는다 . 과학과 교육과정 54"}, {"id": 613, "code": "[9과15-04]", "text": "우주탐사의 의의와 인류에게 미치는 영향을 조사하여 과학의 유용성을 인식할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 47, "hasExp": false}, {"id": 614, "code": "[9과16-01]", "text": "물리 변화와 화학 변화의 의미를 알고 , 화학 변화에서 새로운 물질이 생성됨을 관찰할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 54, "hasExp": false}, {"id": 615, "code": "[9과16-02]", "text": "간단한 화학 반응을 화학 반응식으로 표현하고 , 화학 반응식에서 계수의 비를 입자 수의 비로 해석할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 62, "hasExp": false}, {"id": 616, "code": "[9과16-03]", "text": "화학 반응에서 질량이 보존됨을 실험을 통해 추론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 34, "hasExp": true, "explanation": "화학 반응이 일어날 때 물질을 구성하는 원자의 배열만 변하고 , 원자의 종류와 수는 변하지 않음을 강조하여 설명한다 ."}, {"id": 617, "code": "[9과16-04]", "text": "화합물을 구성하는 성분 원소의 질량비가 일정함을 실험 자료를 해석하여 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 49, "hasExp": false}, {"id": 618, "code": "[9과16-05]", "text": "기체 반응에서 기체 부피 사이의 비가 일정함을 실험 자료를 해석하여 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 48, "hasExp": false}, {"id": 619, "code": "[9과16-06]", "text": "화학 반응에서 열에너지가 출입함을 알고 , 생활 속 사례를 조사하여 발표할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "물질", "verb": "능력", "textLen": 48, "hasExp": false}, {"id": 620, "code": "[9과17-01]", "text": "지구 대기권을 4개 권역으로 구분하며 , 온실효과와 지구온난화를 복사 평형의 관점으로 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 58, "hasExp": false}, {"id": 621, "code": "[9과17-02]", "text": "대기 대순환에서 위도별 바람의 특성을 파악하고 , 대기 대순환의 역할을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 50, "hasExp": true, "explanation": "위도별로 지상에서 부는 바람은 북반구를 기준으로 설명하고 , 대기 대순환 설명 시 전향력이나 지구가 자전하지 않을 경우는 다루지 않는다 ."}, {"id": 622, "code": "[9과17-03]", "text": "상대습도 , 단열 팽창 및 응결 현상의 관계를 이해하고 , 구름의 생성과 강수 과정을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 58, "hasExp": true, "explanation": "대기 중의 수증기량과 이슬점 , 포화 수증기압 , 상대습도 등의 관계를 파악하고 , 구름의 생성은 모형실험으로 다룬다 . 강수 과정은 빙정설과 병합설에 대해 정성적으로 간단하게 설명한다 ."}, {"id": 623, "code": "[9과17-04]", "text": "기압, 기단, 전선의 개념을 이해하고 , 일기도에서 저기압과 고기압의 분포에 따른 날씨를 해석할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 60, "hasExp": true, "explanation": "기압의 개념과 크기 및 지표면의 차등 가열에 따른 온도 차이로 인해 기압의 변화가 생겨서 바람이 분다는 것을 다룬다 . 등압선 그리기 , 일기 예보의 과정 , 일기도 작 성은 다루지 않는다 . 과학과 교육과정 56"}, {"id": 624, "code": "[9과18-01]", "text": "수권에서 해수 , 담수, 빙하의 분포와 활용 사례를 조사하고 , 자원으로서 물의 가치에 대해 토론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 62, "hasExp": true, "explanation": "자원으로서의 물의 가치에서는 지하수의 가치와 활용 방안 , 지속가능한 수자원 활용 방안 조사 ⋅실천 등을 포함하여 다룬다 ."}, {"id": 625, "code": "[9과18-02]", "text": "해수의 수온과 염분의 분포 및 변화를 해석하여 해수의 특성을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 44, "hasExp": true, "explanation": "위도에 따른 해수의 연직 수온 분포 차이보다는 우리나라 주변 해역의 계절 별 연직 수온 분포를 위주로 다룬다 ."}, {"id": 626, "code": "[9과18-03]", "text": "대기 대순환과 해양 표층 순환과의 관계를 이해하고 , 기후변화에 영향을 미치는 해류의 역할을 설명할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "지구와 우주", "verb": "능력", "textLen": 62, "hasExp": true, "explanation": "해류가 전 지구적인 에너지 재분배를 통하여 기후변화에 미치는 영향을 이해 하게 하고 , 북태평양의 아열대 순환을 구성하는 해류만을 다룬다 . 공통 교육과정 57"}, {"id": 627, "code": "[9과19-01]", "text": "직선상에서 움직이는 물체의 운동을 그래프로 나타내고 해석할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 39, "hasExp": true, "explanation": "물체의 직선 운동에서 등속 운동과 속력이 일정하게 증가하거나 감소하는 운 동을 다루며 , 속력이 변하는 경우에는 시간 -속력 그래프를 그려서 운동을 분석한다 ."}, {"id": 628, "code": "[9과19-02]", "text": "자유 낙하하는 물체의 운동에서 시간에 따른 속력의 변화가 일정함을 분석할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 47, "hasExp": true, "explanation": "자유 낙하하는 물체의 운동에서 물체의 종류나 질량에 상관없이 단위 시간당 속력 변화량이 9.8m/s 로 일정함을 자료를 분석하여 이끌어내도록 한다 ."}, {"id": 629, "code": "[9과19-03]", "text": "중력이 한 일은 운동 에너지 , 중력에 대해서 한 일은 위치 에너지로 전환됨 을 확인한다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "행위", "textLen": 51, "hasExp": true, "explanation": "일의 정의를 알고 , 자유 낙하하는 물체의 운동에서 중력이 한 일을 위치 에너지와 운동 에너지로 표현할 수 있다 ."}, {"id": 630, "code": "[9과19-04]", "text": "물체의 운동에서 역학적 에너지의 전환과 보존을 이해하고 , 이를 활용하여 일상생활 속 물체의 운동을 예측할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "운동과 에너지", "verb": "능력", "textLen": 66, "hasExp": true, "explanation": "단진자나 자유 낙하하는 물체 등의 사례에서 역학적 에너지 보존 법칙을 이 용해 물체의 운동 상태를 예측할 수 있음을 설명한다 . 과학과 교육과정 58"}, {"id": 631, "code": "[9과20-01]", "text": "감각기관의 구조와 기능을 이해하고 , 실험을 통해 자극이 뇌로 전달되는 과정을 추론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 54, "hasExp": true, "explanation": "감각 기관의 구조는 간단히 언급하고 , 자극이 감각 기관에서 뇌로 전달되는 과정을 중점적으로 설명한다 ."}, {"id": 632, "code": "[9과20-02]", "text": "뉴런과 신경계의 구조와 기능을 이해하고 , 자극에서 반응이 일어나기까지의 과정을 모형 으 로 설 명 할 수 있 다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "기타", "textLen": 65, "hasExp": false}, {"id": 633, "code": "[9과20-03]", "text": "우리 몸의 기능 조절에 호르몬이 관여함을 알고 , 관련 자료를 조사하여 발표할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 50, "hasExp": true, "explanation": "호르몬의 종류는 성장호르몬 , 인슐린 , 글루카곤 , 티록신 정도만 언급하고 , 신경 계와 호르몬의 작용으로 몸을 최적의 상태로 유지함을 강조하여 설명한다 ."}, {"id": 634, "code": "[9과21-01]", "text": "개체의 생장에 세포분열이 필요한 이유를 세포의 표면적과 부피의 관계로 추론할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 49, "hasExp": false}, {"id": 635, "code": "[9과21-02]", "text": "염색체와 유전자의 관계를 이해하고 , 체세포분열과 생식세포 형성과정의 특징을 염색체 행동을 중심으로 해석할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 66, "hasExp": true, "explanation": "체세포분열과 생식 세포 형성 과정은 염색체의 행동을 중심으로 간단하게 다루며, 분열 과정의 단순한 암기보다 분열의 생물학적 의미를 이해하는 데 중점을 둔다."}, {"id": 636, "code": "[9과21-03]", "text": "수정란으로부터 개체가 발생하는 과정을 모형으로 표현할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 36, "hasExp": true, "explanation": "발생 과정은 수정란의 초기 발생에서 난할만을 간단하게 다룬다 ."}, {"id": 637, "code": "[9과21-04]", "text": "멘델 유전 실험의 의의와 원리를 이해하고 , 멘델 유전 원리가 적용되는 유전 현상을 조사 하여 협력적으로 소통할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 69, "hasExp": false}, {"id": 638, "code": "[9과21-05]", "text": "사람의 유전 형질과 유전 연구 방법을 알고 , 가계도를 분석하여 사람의 유전 현상을 설명 할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "생명", "verb": "능력", "textLen": 58, "hasExp": false}, {"id": 639, "code": "[9과22-01]", "text": "재해⋅재난 사례와 관련된 자료를 조사하고 , 그 발생 원인과 피해에 대해 과학적으로 분석 할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "과학과 사회", "verb": "능력", "textLen": 58, "hasExp": true, "explanation": "재해⋅재난에 대한 사례 조사는 감염병 질병 확산 , 화학물질 유출 , 운송 수단 사고, 지진, 화산, 기상재해 등에서 선택하여 다룬다 ."}, {"id": 640, "code": "[9과22-02]", "text": "과학적 원리를 이용하여 재해 ⋅재난에 대한 대비 및 대처 방안을 세울 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "과학과 사회", "verb": "기타", "textLen": 45, "hasExp": true, "explanation": "재해⋅재난의 피해를 줄이기 위한 방안을 논의할 때는 사후 대처뿐만 아니라 사전 예방 및 대비를 다룬다 ."}, {"id": 641, "code": "[9과23-01]", "text": "과학과 관련된 직업의 종류와 하는 일을 조사하고 , 과학기술의 발달로 생기는 미래 사회의 직업 변화를 예상할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "과학과 사회", "verb": "능력", "textLen": 67, "hasExp": false}, {"id": 642, "code": "[9과23-02]", "text": "자신의 진로와 관련 있는 과학 분야를 조사하고 , 진로 선택을 위하여 필요한 과학 학습을 계획할 수 있다 .", "subject": "과학", "gradeGroup": "중1~3", "area": "과학과 사회", "verb": "능력", "textLen": 60, "hasExp": true, "explanation": "과학과 직접적으로 관련된 직업에서 과학의 역할 뿐만 아니라 기술 , 공학, 사회, 예술, 문학 분야 등의 직업에서 필요한 과학 학문을 조사하여 , 과학의 중요성과 유 용성을 깨닫고 과학 학습 계획을 세우도록 한다 ."}, {"id": 643, "code": "[6실01-01]", "text": "아동기의 발달 특징을 이해하고 성장발달에 필요한 조건과 방법을 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 41, "hasExp": true, "explanation": "이 성취기준은 아동기의 신체, 사회⋅정서, 성, 진로 발달의 특징을 이해하 여 자신이 여러 영역에서 발달과정에 있다는 것과 발달의 개인차가 있다는 것을 인식하 도록 한다. 또한 건강하게 발달하기 위해서는 가족이나 어른들의 도움만이 아니라 자신의 다양한 노력이 필요함을 이해하여 이를 실천한다 ."}, {"id": 644, "code": "[6실01-02]", "text": "건강한 발달을 위한 자기 관리 방법을 탐색하고 , 일상생활 속에서 올바른 생활습관과 태도를 갖도록 계획하여 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 66, "hasExp": false}, {"id": 645, "code": "[6실01-03]", "text": "건강한 가정생활을 위해 가족원 모두에게 다양한 요구가 있음을 이해하여 서로에 대한 배려와 돌봄을 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 60, "hasExp": true, "explanation": "이 성취기준은 삶의 기본적 조건인 의식주생활을 충족시키는 가족의 역할은 가족이 처한 상황이나 조건에 따라 다양할 수 있음을 알도록 하며, 이 과정에서 가정생활 의 중요성과 가정일에 있어서 협력적 소통에 기반한 가족의 역할 분담에 대해 이해하고 실천하도록 한다."}, {"id": 646, "code": "[6실01-04]", "text": "균형 잡힌 식사의 중요성과 조건을 탐색하여 자신의 식습관을 검토해 보고 건강한 식습관 형성에 적용한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 58, "hasExp": false}, {"id": 647, "code": "[6실01-05]", "text": "옷의 기능을 이해하여 평소 자신의 옷차림을 살펴보고 건강하고 적절한 옷 입기를 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 50, "hasExp": true, "explanation": "이 성취기준은 옷이 자기 몸을 보호하고 활동을 편하게 하면서 자신을 표현 하는 수단임을 이해하도록 하여 때와 장소, 상황에 따라 건강, 안전, 위생, 예절을 고려한 옷차림을 영위하는 능력과 태도를 기르도록 한다."}, {"id": 648, "code": "[6실01-06]", "text": "가정일을 수행하는 과정에서 일의 가치와 중요성을 이해하고 , 가정생활을 유지하는 데 필요한 가정일의 종류를 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 66, "hasExp": false}, {"id": 649, "code": "[6실01-07]", "text": "직업의 필요성을 이해하고 적성, 흥미, 성격에 따라 진로 발달 계획을 세우고 주도적으로 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 55, "hasExp": true, "explanation": "이 성취기준은 가정일 뿐 아니라 직업으로서 일에 대한 필요성을 알고 다양한 직업 중에서 적성, 흥미, 성격 등의 특성을 고려하여 진로 발달 계획을 주도적으로 탐색 하도록 한다. 공통 교육과정 – 실과(기술⋅가정) - 13"}, {"id": 650, "code": "[6실02-01]", "text": "시간이나 용돈과 같은 생활자원이 제한되어 있음을 이해하고 , 생활자원의 사용가치를 높 이는 방법을 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 61, "hasExp": false}, {"id": 651, "code": "[6실02-02]", "text": "생활자원 관리의 필요성을 인식하고 , 생활자원의 합리적인 보관과 활용방법을 익힌다.", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "기타", "textLen": 46, "hasExp": false}, {"id": 652, "code": "[6실02-03]", "text": "생활자원의 올바른 사용이 가정과 환경에 도움이 됨을 이해하고 재활용, 재사용 등 환경을 고려한 관리 방법을 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 66, "hasExp": true, "explanation": "이 성취기준은 옷, 음식, 생활용품 등 생활자원은 올바른 사용 방법 및 사용 후 버리기 여부의 선택과 처리 방법에 따라 또 다른 생활자원이나 혹은 쓰레기가 될 수 있음을 알고 쓰레기 줄이기 및 분리배출 방법 등을 익혀 실천하도록 한다. 아울러 개인과 가족의 자원 사용이 지구환경에 미치는 영향을 이해하여 생활자원을 소중히 여기고 지속 가능한 삶의 태도로서 나눔과 기부를 실천하도록 한다."}, {"id": 653, "code": "[6실02-04]", "text": "식재료 생산과 선택의 중요성을 인식하고 여러 식재료의 고유하고 다양한 맛을 경험하여 자신의 식사에 적용한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 61, "hasExp": true, "explanation": "이 성취기준은 자연에서 먹거리로 생산되는 다양한 식재료의 맛을 느끼고 즐 길 수 있으며 이 과정에서 맛에 대한 경험을 통해 자연이 주는 먹거리의 의미를 이해하 고, 이를 편식 교정 등에 적용할 수 있도록 한다. 특히 지역 및 제철 식품의 이용을 통해 친 환경적인 식생활의 의미를 알게 한다."}, {"id": 654, "code": "[6실02-05]", "text": "음식의 조리과정을 체험하여 자기 간식이나 식사를 스스로 마련하는 식생활을 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 47, "hasExp": false}, {"id": 655, "code": "[6실02-06]", "text": "우리나라 밥상차림을 이해하고 , 함께 식사하는 즐거움을 경험하면서 이 과정에서 식사 예절을 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 57, "hasExp": true, "explanation": "이 성취기준은 먹는다는 것의 의미와 음식문화의 기본으로서 우리나라의 고 유한 식사 형식인 밥상차림을 이해하도록 한다. 또한 음식을 준비하여 함께 먹는 의미와 즐거움을 경험할 수 있도록 하며 이 과정에서 식사예절이 필요함을 인식하고 이를 실천할 수 있도록 한다."}, {"id": 656, "code": "[6실02-07]", "text": "의생활 용품이 만들어지는 과정을 탐색하여 옷이나 생활용품이 어떻게 구성되는지를 설명 한다.", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "기타", "textLen": 50, "hasExp": false}, {"id": 657, "code": "[6실02-08]", "text": "다양한 도구와 재료를 활용하여 간단한 생활용품을 만들어 보면서 직접 만들어 쓰는 즐거움과 창의적 태도를 가진다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "태도", "textLen": 63, "hasExp": true, "explanation": "이 성취기준은 다양한 바느질 도구와 재료를 활용하여 간단한 생활용품을 만 들어 보는 과정에서 즐거움과 의미를 느낄 수 있도록 한다. 아울러 이러한 활동을 통해 손 조작 능력, 도전성 , 창의성 등 다양한 능력을 향상할 수 있도록 한다."}, {"id": 658, "code": "[6실02-09]", "text": "간단한 옷의 수선 등 의생활과 관련된 문제를 스스로 해결하려는 태도를 가진다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "태도", "textLen": 44, "hasExp": false}, {"id": 659, "code": "[6실02-10]", "text": "자신의 생활공간을 쾌적하고 위생적으로 관리하는 것의 중요성을 알고, 정리정돈과 청소 및 쓰레기 처리의 방법을 익혀 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 70, "hasExp": false}, {"id": 660, "code": "[6실02-11]", "text": "생태 지향적 삶을 위해 자신의 의식주 생활에서 할 수 있는 구체적인 행동을 계획하여 실천한다 . 실과(기술⋅가정)/정보과 교육과정 14", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "생활환경과 지속가능한 선택", "verb": "기타", "textLen": 75, "hasExp": true, "explanation": "이 성취기준은 건강과 환경을 생각하고 배려의 마음이 깃든 생태 지향적 삶이 왜 필요하고 중요한지를 이해하고 , 평소 자신의 의식주 생활습관을 살펴보면서 이를 바탕 으로 하여 지속가능한 의식주생활을 위한 구체적인 행동을 계획하고 실천하도록 한다."}, {"id": 661, "code": "[6실03-01]", "text": "발명의 의미를 이해하고 , 일상생활을 바꾼 발명품을 탐색하여 발명과 기술에 대한 중요성과 가치를 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 60, "hasExp": true, "explanation": "이 성취기준은 발명의 의미를 발견과 비교하여 이해하도록 하고 일상생활에 영향을 끼친 다양한 발명품 사례를 탐색하도록 한다. 또한 발명품 중에서 소외된 지역의 사람들에게 도움을 주는 적정기술 사례를 찾아 나눔과 공유의 가치를 인식하도록 한다."}, {"id": 662, "code": "[6실03-02]", "text": "발명사고기법과 기술적 문제 해결 과정을 이해하고 , 다양한 재료를 활용하여 생활 속 문제를 해결할 수 있는 창의적인 제품을 구상하고 만들어 봄으로써 실천적 태도를 갖는다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "기술적 문제해결과 혁신", "verb": "태도", "textLen": 96, "hasExp": true, "explanation": "이 성취기준은 일상생활에서 불편한 문제를 찾고 이를 해결하기 위하여 다양 한 발명 사고 기법을 적용하여 개선된 아이디어를 내도록 한다. 이를 위해 기술적 문제해 결 과정(문제 확인, 아이디어 탐색 및 구체화 , 실행, 평가)에 따라 창의적인 물건을 구상 하고 만들어서 공유하는 메이커 활동으로 연결되도록 한다."}, {"id": 663, "code": "[6실03-03]", "text": "발명과 특허의 관계를 이해하고 , 특허 침해 사례를 통하여 지식재산권의 중요성을 인식 하여 올바른 방법으로 활용한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 66, "hasExp": false}, {"id": 664, "code": "[6실03-04]", "text": "수송의 의미와 수송 수단의 발달과정에 대한 이해를 바탕으로 생활 속 다양한 수송 수단을 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 55, "hasExp": false}, {"id": 665, "code": "[6실03-05]", "text": "수송 수단의 구성 요소를 이해하고 , 친환경 에너지를 적용한 다양한 수송 수단의 시제품을 만들어 수송기술의 가치를 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 70, "hasExp": true, "explanation": "이 성취기준은 수송 수단의 기본 요소가 구동장치 , 조향장치 , 제동장치 등으 로 구성되어 있음을 일상생활에서의 수송 수단 사례를 들어 설명하여 간단한 수송 수단을 만들고 공유하는 메이커 활동으로 연결한다 . 수송 수단의 구동장치를 작동시키기 위하여 태양광 전지와 같은 친환경 에너지를 사용하여 수송 수단을 만들어 보면서 수송기술의 중요성과 가치를 인식하도록 한다."}, {"id": 666, "code": "[6실04-01]", "text": "친환경 건설 구조물을 이해하고 , 생활 속 건설 구조물을 탐색하여 간단한 구조물을 체험 하면서 건설기술에 대한 가치를 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 72, "hasExp": true, "explanation": "이 성취기준은 건설기술의 의미와 특성에 대한 이해를 바탕으로 건설 구조물 에는 건축 구조물과 토목 구조물이 있음을 알고 건설 구조물을 탐색하는 체험 활동을 통해 중등의 건설기술과 연계되도록 설정하였다 . 특히, 최근 대두되고 있는 친환경 건설 구조 물의 사례를 탐색하고 간단한 구조물을 만드는 메이커 활동을 제시한다 . 공통 교육과정 – 실과(기술⋅가정) - 17"}, {"id": 667, "code": "[6실04-02]", "text": "생활 속 디지털 기술의 중요성을 이해하고 , 디지털 기기와 디지털 콘텐츠 저작 도구를 사용하여 발표 자료를 만들어 보면서 디지털 기기의 활용 능력을 기른다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "태도", "textLen": 88, "hasExp": false}, {"id": 668, "code": "[6실04-03]", "text": "제작한 발표 자료를 사이버 공간에 공유하고 , 건전한 정보기기의 활용을 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 46, "hasExp": true, "explanation": "이 성취기준은 활동으로 만든 발표 자료를 사이버 공간에 공유하는 방법에 대한 이해를 바탕으로 자료를 공유할 때 개인 정보 및 저작권 보호의 중요성을 인식하고 실천하도록 설정하였다 . 여기에서는 정보윤리를 지키는 방법에 관해 사례나 구체적인 방 법을 제시하도록 한다."}, {"id": 669, "code": "[6실04-04]", "text": "로봇의 개념과 구조를 이해하고 , 생활 속 로봇 기능을 체험하여 로봇의 중요성을 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 51, "hasExp": false}, {"id": 670, "code": "[6실04-05]", "text": "로봇의 종류와 활용 사례를 통해 작동 원리를 이해하고 , 로봇에 대한 관심과 흥미를 가진다.", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "태도", "textLen": 51, "hasExp": false}, {"id": 671, "code": "[6실04-06]", "text": "로봇의 융합 기술을 이해하고 , 간단한 로봇을 만들어 코딩과 프로그램을 적용하여 동작시키는 체험을 통해 융합 기술의 가치를 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 75, "hasExp": true, "explanation": "이 성취기준은 로봇에 다양한 정보기술이 융합되는 사례를 탐색하여 로봇과 융합된 다양한 제품 개발에 대해 알고, 로봇의 다양한 센서와 동작을 위하여 블록 기반 프로그램으로 제어할 수 있는 활동을 하도록 하였다 . 여기에서는 ‘디지털 사회와 인공지 능’에서 학습한 블록 기반의 교육용 프로그래밍 도구를 활용하여 움직이는 간단한 인공지 능형 로봇을 제작하여 구동시켜 보면서 로봇의 작동 원리를 학습하도록 한다."}, {"id": 672, "code": "[6실04-07]", "text": "생활 속 동식물 자원을 활용 목적에 따라 분류하고 이와 관련된 다양한 생명기술을 탐색 한다.", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "기타", "textLen": 51, "hasExp": false}, {"id": 673, "code": "[6실04-08]", "text": "생활 속 동식물을 기르고 가꾸는 방법을 알고, 동식물을 기르고 가꾸는 체험을 통해 생태 존중감을 가진다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "태도", "textLen": 59, "hasExp": false}, {"id": 674, "code": "[6실04-09]", "text": "동식물 자원의 친환경 농업 사례를 통해 지속가능한 농업이 순환되고 있음을 인식하고 농업의 미래가치를 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 62, "hasExp": true, "explanation": "이 성취기준은 친환경 농업에 대한 이해를 바탕으로 이를 이루기 위한 농업 사례들을 구분하여 지속가능한 농업이 이루어지기 위한 농업의 순환성을 이해하고 중요성을 인식하도록 설정하였다 . 특히, 지속가능성 농업의 순환에 대한 다양한 사례(예, 친환경 농 업, 스마트팜 , 로컬 푸드, 푸드 마일리지 등)를 통해 학습하도록 한다."}, {"id": 675, "code": "[6실04-10]", "text": "생활 속에서 농업활동과 관련된 모습을 분석하고 이에 따른 농업활동을 체험하여 농업에 대한 관심을 두고 이를 생활 속에서 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 73, "hasExp": true, "explanation": "이 성취기준은 생활 속에서 농업활동과 연관 지을 수 있는 모습에 대한 예측을 바탕으로 다양한 농업활동 분야들을 알고 이와 관련된 농업활동 체험을 통해 농업에 대한 관심과 흥미를 가질 수 있도록 설정하였다 . 특히, 농업활동은 실내원예활동 , 농업생산물 가공 활동, 원예 및 동물치료 활동 등과 같은 생활상의 변화와 관련된 체험을 제시하도록 한다."}, {"id": 676, "code": "[6실04-11]", "text": "농업과 농촌의 다원적인 역할과 가치를 이해하고 미래 농업과 관련된 다양한 직업 세계를 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 54, "hasExp": true, "explanation": "이 성취기준은 농업과 농촌은 농산물 생산뿐 아닌 그 외에도 다원적인 역할을 하고 있음을 이해하고 이에 대한 인식과 이해를 바탕으로 농업과 농촌에 대한 올바른 진로역량을 기르기 위해서 설정하였다 . 특히, 다원적인 농업과 농촌의 가치를 환경, 생태, 사회, 문화적인 가치로 분류하여 이와 관련된 진로를 탐색하고 건전한 진로역량을 기르도 록 한다."}, {"id": 677, "code": "[6실05-01]", "text": "컴퓨터를 활용한 생활 속 문제해결 사례를 탐색하고 일상생활 속 문제를 해결하기 위한 알고리즘을 다양한 방법으로 표현한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "디지털 기초소양", "verb": "행위", "textLen": 68, "hasExp": true, "explanation": "과 연계하여 , 생활 속 문제를 해결하는 알고리즘의 다양한 사례를 이 야기로 제시하거나 신체를 움직이고 , 다양한 도구 및 학습지를 활용하여 알고리즘을 이해하며 필요성을 설명할 수 있어야 한다. Ÿ[06자율-3]"}, {"id": 678, "code": "[6실05-02]", "text": "컴퓨터에게 명령하는 방법을 체험하고 , 주어진 문제를 해결하는 프로그램을 작성한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "디지털 기초소양", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "와 연계하여 , 우리 주변의 가까운 곳에서 프로그래밍으로 해결된 문제를 찾아 간단한 프로그램을 작성하며 자료의 입⋅출력, 변수를 이용하는 경험을 하고 순차, 반복, 선택 과정을 이해할 수 있어야 한다. Ÿ[06자율-5]"}, {"id": 679, "code": "[6실05-03]", "text": "실생활의 문제를 해결하는 프로그램을 협력하여 작성하고 , 산출물을 타인과 공유한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "디지털 기초소양", "verb": "행위", "textLen": 47, "hasExp": false}, {"id": 680, "code": "[6실05-04]", "text": "디지털 데이터와 아날로그 데이터의 특징을 이해하고 , 인공지능에 활용할 수 있는 데이터의 유형이나 형태를 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "디지털 기초소양", "verb": "행위", "textLen": 65, "hasExp": true, "explanation": "와 연계하여 , 인공지능이 우리에게 추천하는 다양한 내용, 즉, 인터넷 동영상 플랫폼에서 추천, 서점에서 내가 좋아하는 책 종류 추천 등을 할 때, 인공지능은 어떤 기준을 갖고 내가 선호하는 것을 알아서 추천하는 지 등의 과정을 체험해서 인공지능의 분류 과정을 내면화 할 수 있어야 한다. 선택 중심 교육과정 – 융합 선택 과목 - 141【 성취기준 적용 시 고려사항 】 Ÿ<교수학습 > 컴퓨팅 사고력을 함양하기 위해 언플러그드 , 문제기반학습 , 프로젝트학습 , 디자인 기반학습 등 각 영역의 핵심아이디어를 습득하는데 적절한 교수⋅학습 방법을 각 성취기준에서 달성하고자 하는 내용을 고려하여 활용한다 . Ÿ알고리즘을 체험하고 표현하는 활동 다양한 형태의 데이터를 조작하는 활동 등에서 놀이 중심 언플러그드 활동을 실시하여 교수⋅학습에 흥미와 재미를 갖도록 한다."}, {"id": 681, "code": "[6실05-05]", "text": "인공지능이 만들어지는 과정을 체험하고 , 인공지능이 사회에 미치는 영향을 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "초5~6", "area": "디지털 기초소양", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "이 성취기준은 기계학습이 적용된 간단한 인공지능 도구의 체험을 통해 기계 학습의 기본 원리를 이해하고 인공지능으로 인한 사회의 발전과 직업의 변화를 이해하여 인 공지능이 사회에 미치는 영향을 탐색할 수 있어야 한다."}, {"id": 682, "code": "[9기가01-01]", "text": "자아 존중감을 향상시키고 긍정적인 자아 정체성을 형성하기 위해 청소년기의 발달 특 징을 자신의 발달 특징과 연결 지어 자신을 총체적으로 이해한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 82, "hasExp": false}, {"id": 683, "code": "[9기가01-02]", "text": "의생활, 식생활이 청소년기 성장과 건강에 미치는 영향을 탐색하고 성장과 건강을 위해 바람직한 의생활과 식생활의 실천 방안을 탐색하여 이를 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 83, "hasExp": true, "explanation": "이 성취기준은 의생활과 식생활을 어떻게 영위하는지에 따라 청소년기 발 달에 차이가 발생할 수 있음을 이해하고 , 건강한 생활을 영위하고 청소년기의 긍정적인 발달을 이끄는 방안을 탐색하여 실천하도록 한다."}, {"id": 684, "code": "[9기가01-03]", "text": "건강과 성장을 위한 청소년기 영양의 중요성을 이해하여 자신의 식생활을 평가하고 , 식생활 문제를 개선하여 건강한 식생활을 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 74, "hasExp": false}, {"id": 685, "code": "[9기가01-04]", "text": "의복디자인 요소를 고려한 자기이미지에 맞는 옷차림으로 자신을 긍정적으로 표현한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 46, "hasExp": true, "explanation": "이 성취기준은 자기 이미지에 맞는 옷차림을 하는 것이 자아를 표현하는 효 과적인 수단이 될 수 있음을 인식하고 , 의복디자인 요소를 고려한 옷차림으로 자신을 긍 공통 교육과정 – 실과(기술⋅가정) - 21정적으로 표현할 수 있도록 한다. 또한 한복에서 자신에게 맞는 디자인 요소를 찾아보는 활동을 추가하여 진행할 수 있다."}, {"id": 686, "code": "[9기가01-05]", "text": "청소년기의 건강한 발달을 위협하는 스트레스 , 분노, 우울 등의 여러 가지 행동 및 심리 문제의 원인을 분석하고 , 적응 유연성을 기를 수 있는 다양한 예방 및 해결방안을 탐 색하여 적용한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 108, "hasExp": false}, {"id": 687, "code": "[9기가01-06]", "text": "사회변화로 증가하는 여러 가지 청소년 중독의 유형을 탐색하여 이를 예방하고 대응할 수 있는 방안을 제안한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 61, "hasExp": true, "explanation": "이 성취기준은 디지털 생활환경의 확산으로 나타나는 중독 문제(게임, 스 마트폰 , 도박 등)와 청소년 건강과 관련된 중독 문제(니코틴 , 카페인 , 약물 등)의 발생 원 인과 영향을 분석하고 , 이를 예방 및 해결하는 방안을 제안하도록 한다."}, {"id": 688, "code": "[9기가01-07]", "text": "자기 이해를 기반으로 전 생애적 관점에서 진로 설계의 중요성을 인식하고 , 자기 적성에 맞는 진로를 설계한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 62, "hasExp": false}, {"id": 689, "code": "[9기가01-08]", "text": "성적 자기 결정권의 중요성을 이해하고 , 성인지 감수성과 건강한 성 가치관을 함양하여 상호 존중의 관계를 실천할 수 있는 방안을 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 78, "hasExp": true, "explanation": "이 성취기준은 이차 성징의 변화를 경험하는 중학교 학습자들이 남성과 여 성의 서로 다른 성에 대해 이해하여 부정확한 지식이나 편견을 갖지 않도록 하며, 성인지 감수성을 바탕으로 자신의 뜻을 분명히 하는 주체적이고 책임감 있는 태도를 길러 자기 자 신과 상대방을 보호하며 존중할 수 있는 성적 자기 결정권에 대한 이해를 함양하도록 한다. 이 권리는 왜곡된 성 관련 정보와 위험한 환경으로부터 자신을 보호할 수 있는 근거가 될 수 있으며 , 다른 의미로 해석되지 않도록 유의한다 ."}, {"id": 690, "code": "[9기가01-09]", "text": "일상생활 및 가상공간에서 만나는 또래와 건강한 관계를 형성하고 , 다양한 주변인들과 친밀한 세대 간 관계를 형성하는 방안을 탐색하여 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 80, "hasExp": true, "explanation": "이 성취기준은 자신을 둘러싼 관계에는 횡적(또래) 관계뿐 아니라 종적(다 양한 세대) 관계도 있음을 인식하고 , 다양한 주변인들과 건강하고 친밀한 관계를 형성하 는 방안을 실천하도록 한다. 이때, 현실 세계에서 교류하는 타인뿐만 아니라 확장된 생활환 경 (사회 관계망 서비스 (SNS), 게임, 메타버스와 같은 가상세계 )에서 교류하는 타인도 함께 다룬다 . 인터넷상의 익명성을 올바르게 활용할 수 있는 방안과 인터넷 언어폭력 , 사이버 폭력의 심각성을 알아보는 활동을 추가하여 진행할 수 있다."}, {"id": 691, "code": "[9기가01-10]", "text": "다양한 현대 가족에 내재된 가족생활의 보편성과 고유한 가치를 존중하는 동시에 가족에 대한 유연한 태도를 길러, 뉴노멀 사회에서의 새로운 가족문화를 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 88, "hasExp": true, "explanation": "이 성취기준은 사회 변화로 인해 가족 유형의 다양성이 증가하고 있지만, 이 러한 다양성을 관통하는 가족이 지닌 고유의 가치를 인식하도록 한다. 또한 다양한 가족에 대한 유연한 태도와 더불어 살아가는 공동체의 가치에 대해 탐색하도록 한다. 나아가 테크놀로지와 미디어 발달로 인해 발생한 변화에 적합한 새로운 가족문화를 탐색 하여 실천할 수 있도록 한다."}, {"id": 692, "code": "[9기가01-11]", "text": "대인 관계에서 발생하는 갈등의 원인과 배경을 분석하고 , 효과적인 의사소통을 통해 갈등을 해결하는 방안을 탐색하여 이를 적용한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 73, "hasExp": true, "explanation": "이 성취기준은 갈등을 원만하게 해결하기 위한 의사소통능력의 필요성을 인 식하고 , 효과적 의사소통 방법의 의미와 원리를 파악한다 . 또한 객관적 관점에서 갈등을 조 망하여 타인과의 갈등을 해결하고 원만한 대인 관계를 형성할 수 있도록 한다."}, {"id": 693, "code": "[9기가01-12]", "text": "성폭력과 가정폭력의 사회⋅구조적인 원인과 영향을 분석하고 , 다양한 문제 상황을 중심 으로 이를 대처하고 지원하는 방안을 탐색한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "인간 발달과 주도적 삶", "verb": "행위", "textLen": 74, "hasExp": false}, {"id": 694, "code": "[9기가02-01]", "text": "생활자원의 종류와 특성 및 순환과정을 이해하고 , 의식주 자원관리의 중요성을 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 49, "hasExp": true, "explanation": "이 성취기준은 생활자원을 인적⋅물적 자원으로 구분하고 일상생활을 영위 하는데 필수적인 의식주 자원이 물적 자원에 포함됨을 이해한다 . 점차 심각해지는 기후위 기에 대응하여 인간과 자연이 공존하기 위해서는 순환 가능성을 고려한 의식주 자원관리 가 중요함을 인식할 수 있게 한다."}, {"id": 695, "code": "[9기가02-02]", "text": "한국인 영양소 섭취기준과 식사구성안을 바탕으로 균형 잡힌 식사를 계획한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 42, "hasExp": false}, {"id": 696, "code": "[9기가02-03]", "text": "건강과 환경을 고려한 식품의 선택, 관리, 보관 방법을 탐색하여 실생활에 적용한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 47, "hasExp": false}, {"id": 697, "code": "[9기가02-04]", "text": "개인과 가족의 영양 요구와 지속가능성을 충족하는 식사를 계획하고 조리한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 42, "hasExp": true, "explanation": "이 성취기준은 식사 계획 시 개인과 가족의 영양 및 기호 등을 고려하는 것뿐만 아니라 제철 식품, 로컬 푸드, 대체식품 , 탄소배출 , 음식물 쓰레기 감량 등의 지 실과(기술⋅가정)/정보과 교육과정 24속가능성을 고려하여 식품을 선택하고 , 조리 시에도 건강 및 안전을 고려한 조리법을 적 용하도록 한다."}, {"id": 698, "code": "[9기가02-05]", "text": "의복 재료의 특성을 이해하고 건강과 환경을 고려한 의복의 세탁과 관리 방안을 탐색 하여 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 55, "hasExp": false}, {"id": 699, "code": "[9기가02-06]", "text": "지속가능성을 고려하여 의복 마련 계획을 세우고, 이를 창의적이고 친환경적인 의생활에 적용한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 53, "hasExp": true, "explanation": "이 성취기준은 패스트 패션과 같은 현대 사회의 의생활 문제를 분석하여 의복 구매 시 디자인 , 가격 등의 개인적 요구뿐 아니라 자신의 선택이 사회, 환경에 미치는 영향까지도 고려해야 함을 성찰한다 . 나아가 3R(Reduce, Reuse, Re(Up)cycle) 을 일상 생활에서 실천하는 방안을 탐색하여 실천하도록 한다."}, {"id": 700, "code": "[9기가02-07]", "text": "주거의 의미와 가치가 변화함에 따라 나타나는 다양한 생활 양식을 탐색하고 , 더불어 살아가는 주거 문화를 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 65, "hasExp": true, "explanation": "이 성취기준은 주거의 의미와 기능을 살펴보고 , 현대 사회 주거 가치와 인식 변화에 따른 다양한 주생활 양식을 탐색한다 . 또한 대면 교류가 줄어들고 있는 현실에서 더불어 사는 주거 문화의 중요성을 인식하고 실천 방안을 탐색하여 공동체 가치 함양 및 역량이 강화되도록 한다."}, {"id": 701, "code": "[9기가02-08]", "text": "생활공간으로서 주거환경의 조건을 분석하고 , 쾌적하고 안전한 주거 관리 방안을 탐색 하여 실생활에 적용한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 61, "hasExp": true, "explanation": "이 성취기준은 열, 빛, 공기, 소음이 인간에게 미치는 영향을 이해하여 쾌 적한 주거환경을 조성하기 위한 능력을 기른다 . 특히 디지털 환경 확대에 따른 인공지능 기반 주거 서비스 (안전성 , 쾌적성 , 편의성 , 유지 및 관리 등)의 쾌적성과 안전성에 대해 분석해 보도록 한다. 또한 주생활에서 탄소중립을 실천하기 위해 가정생활에서의 탄소발 자국 줄이기 활동 등을 진행할 수 있다."}, {"id": 702, "code": "[9기가02-09]", "text": "효율적인 주거 공간 구성 방안을 탐색하여 자신의 생활에 적합한 주거 공간 구성에 활용 한다.", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "기타", "textLen": 51, "hasExp": false}, {"id": 703, "code": "[9기가02-10]", "text": "의식주 생활자원의 생산과 폐기과정을 탐색하고 , 일상생활에서 의식주 생활자원을 선택한 과정과 그 결과를 성찰한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 64, "hasExp": true, "explanation": "이 성취기준은 의식주 생활자원의 순환과정에 초점을 두어 그 일생을 추론 하고, 자신과 가족의 선택이 미치는 영향을 실천적 추론 등의 방법을 통해 성찰한다 ."}, {"id": 704, "code": "[9기가02-11]", "text": "급변하는 소비환경의 변화를 이해하고 , 다양한 소비자 정보를 비판적으로 분석하여 자신의 소비생활에 활용한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 61, "hasExp": true, "explanation": "이 성취기준은 디지털 소비환경으로 변화함에 따라 무분별하게 쏟아지는 사회 관계망 광고, 추적 광고, 맞춤형 광고 등의 소비자 정보를 비판적으로 분석하여 문 제점을 인식한다 . 신유형 광고와 중립적 소비자 정보를 구분하는 활동을 통해 미디어 리 터러시 역량을 함양하고 , 유용한 소비자 정보를 선별하여 자신의 소비생활에 가치 있게 활용할 수 있도록 지도한다 ."}, {"id": 705, "code": "[9기가02-12]", "text": "청소년 소비자의 특성을 이해하고 소비자 의사 결정 과정을 통한 합리적인 소비생활을 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 52, "hasExp": false}, {"id": 706, "code": "[9기가02-13]", "text": "책임 있는 소비자로서 소비자의 권리와 역할을 인식하고 , 소비생활에서 발생하는 소비자 문제와 해결 방안을 탐색하여 소비생활에 적용한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 76, "hasExp": true, "explanation": "이 성취기준은 소비자 문제와 관련된 사회적 현안을 선정하여 소비자 문제의 발생 원인을 파악하고 적합한 문제 해결 방안을 선택하고 실천하여 , 비판적 사고능력을 기르고 적극적인 소비자 시민으로서의 사회적 역할을 탐색해 보도록 한다."}, {"id": 707, "code": "[9기가02-14]", "text": "디지털 생활환경으로 나타난 일상생활의 혁신과 변화를 비판적으로 분석한 결과를 삶의 질 향상에 활용할 수 있는 방안을 탐색하여 제안한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "생활환경과 지속가능한 선택", "verb": "행위", "textLen": 76, "hasExp": true, "explanation": "이 성취기준은 디지털 생활환경으로 변화함에 따라 의식주 생활에 새롭게 등장한 변화를 찾아 이것이 우리 삶에 미친 긍정적 영향과 부작용을 모두 살펴보고 , 이를 삶의 질 향상에 활용할 수 있는 방안을 탐색하여 제안하도록 한다."}, {"id": 708, "code": "[9기가03-01]", "text": "기술의 의미와 특성을 이해하고 기술의 발달에 따른 사회의 변화를 파악하며 , 미래의 기술과 사회의 변화를 평가하고 예측함으로써 기술에 대한 가치를 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 88, "hasExp": false}, {"id": 709, "code": "[9기가03-02]", "text": "기술의 표준화, 적정 기술과 같은 기술 활용 사례를 탐구하고 , 기술이 사회에 미치는 영향을 바르게 인식하여 기술 혁신과 사회 발전에 참여하는 태도를 갖는다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "태도", "textLen": 89, "hasExp": false}, {"id": 710, "code": "[9기가03-03]", "text": "기술적 문제 해결 과정의 이해를 바탕으로 문제를 확인하고 , 정보를 수집하며 , 확산적 사고와 수렴적 사고를 통해 해결방안을 탐색하고 대안을 선정한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 85, "hasExp": false}, {"id": 711, "code": "[9기가03-04]", "text": "기술적 문제 해결 방안을 시각화하고 도면을 작성하며 , 올바른 도구를 선택하여 시제품 또는 모형을 제작 및 평가하는 과정에서 협업 능력, 공감 능력과 의사소통 능력을 기른다.", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "태도", "textLen": 97, "hasExp": true, "explanation": "이 성취기준은 기술적 문제 해결 과정에서 아이디어 시각화가 중요한 수단이라는 것을 인지하고 , 사투상법 , 등각투상법 , 투시투상법 등의 입체투상법과 스 케치를 중심으로 아이디어의 산출 및 기록, 소통의 중요성을 이해하는데 주안점을 둔다. 다만 제도 통칙(KS)에 따라 도면을 작성하는 체험은 성취기준"}, {"id": 712, "code": "[9기가03-05]", "text": "발명의 개념을 이해하고 , 발명 문제 해결 과정을 바탕으로 발명 활동을 체험하여 창조에 대한 자신감을 갖고 발명이 사회에 미친 영향과 가치를 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 85, "hasExp": false}, {"id": 713, "code": "[9기가03-06]", "text": "지식재산권의 종류와 특징을 이해하고 , 지식재산과 관련한 다양한 사례 조사 및 체험을 통해 지식재산권의 창출, 보호, 활용을 이해하고 실천한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 81, "hasExp": false}, {"id": 714, "code": "[9기가03-07]", "text": "재료의 종류와 특성을 이해하며 , 목적에 맞는 재료를 선택하고 , 안전한 가공 방법을 실천 한다.", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "기타", "textLen": 54, "hasExp": true, "explanation": "이 성취기준은 기술적 활동에 사용되는 주요 재료인 목재, 금속, 플라스틱 등의 종류, 특성, 용도에 대해 이해하고 안전하고 바른 방법으로 재료를 가공 및 활용하 는 능력을 기르는데 주안점이 있다."}, {"id": 715, "code": "[9기가03-08]", "text": "공통 교육과정 – 실과(기술⋅가정) - 27에서 다룰 수 있다.", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "기타", "textLen": 35, "hasExp": true, "explanation": "이 성취기준은 기술적 산출물을 제작하거나 아이디어를 표현하고자 할 때 도면의 작성 방법, 도면의 기능과 필요성을 인식하는데 주안점을 둔다. 또한 정투상도 , 도면의 크기, 척도, 선의 종류와 용도, 치수 기재 등 제도 통칙(KS)을 이 해하고 도면 작성을 체험하도록 한다."}, {"id": 716, "code": "[9기가03-09]", "text": "제품의 제작 순서를 이해하고 올바른 도구를 선택하여 제품을 안전하게 제작하고 평가한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 49, "hasExp": true, "explanation": "이 성취기준은 학생이 기술적 문제 해결 능력을 함양하기 위해 제품을 직 접 제작하는 것은 중요한 학습 활동이므로 설정하였다 . 따라서 문제 해결에 필요한 제품 가공 방법을 이해할 수 있도록 하는데 주안점을 둔다."}, {"id": 717, "code": "[9기가03-10]", "text": "친환경 에너지 자원의 특성을 이해하고 , 종류와 활용 사례를 조사하여 친환경 에너지 개발의 중요성을 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 62, "hasExp": true, "explanation": "이 성취기준은 기후변화 , 환경오염 및 에너지 자원 고갈 문제는 기술의 발 달과 함께 지속적으로 제기되고 있는 문제이며 , 친환경 에너지 자원은 지속가능한 기술의 발전을 위해 중요하기 때문에 친환경 에너지의 다양한 활용과 개발 사례를 조사함으로써 우리의 생활에서 친환경 에너지의 필요성을 인식하도록 하는데 주안점을 둔다."}, {"id": 718, "code": "[9기가03-11]", "text": "에너지와 관련된 문제를 발견하고 창의적인 해결방안을 탐색하여 실현하고 평가한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 45, "hasExp": false}, {"id": 719, "code": "[9기가03-12]", "text": "다양한 수송 수단과 물류 체제를 이해하고 발달과정 및 특징과 혁신적인 활용 사례를 조사하여 수송 분야의 발달을 전망한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "행위", "textLen": 68, "hasExp": true, "explanation": "이 성취기준은 현대 사회가 내연기관뿐 아니라 다양한 형태의 동력 발생 장치를 이용한 수송 수단을 활용하고 있으며 , 자율주행 기술로 인해 물류가 자동화 되면서 수송기술의 중요성이 더욱 강조되고 있으므로 육상, 해상, 항공우주 분야의 혁신적인 수송 장치와 물류 시스템을 이해하고 이를 활용하는 방안을 종합적으로 살펴봄으로써 미래 수송 분야의 발달을 예측할 수 있도록 하는데 주안점을 둔다."}, {"id": 720, "code": "[9기가03-13]", "text": "수송 수단 및 물류 체제와 관련된 문제를 이해하고 해결방안을 탐색하여 실현하고 평가 한다.", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "기술적 문제해결과 혁신", "verb": "기타", "textLen": 50, "hasExp": false}, {"id": 721, "code": "[9기가04-01]", "text": "건설기술의 개념 및 발달과정 , 건설 구조물의 종류와 특성을 이해하고 , 건설 구조물의 혁신사례를 탐구함으로써 건설기술의 중요성을 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 79, "hasExp": false}, {"id": 722, "code": "[9기가04-02]", "text": "건설 구조물의 종류에 따른 계획, 설계, 시공, 유지관리 방법을 탐구하고 건설과정의 중요성을 이해하며 건설 구조물의 가치를 인식한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 75, "hasExp": false}, {"id": 723, "code": "[9기가04-03]", "text": "사용자 요구 및 주어진 환경과 조건을 충족하는 지속가능한 건설 구조물의 모형을 설계⋅제작 및 평가한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 58, "hasExp": true, "explanation": "이 성취기준은 주어진 환경과 조건에 따른 건설 구조물의 종류와 형태, 설계 및 시공 방법의 이해를 바탕으로 건설 구조물의 설계와 시공 방법을 기술적 문제 해결 과정을 통해 학습하기 위해 설정하였다 ."}, {"id": 724, "code": "[9기가04-04]", "text": "전기⋅전자 부품의 종류와 기능을 이해하고 기능에 맞는 부품을 선택하여 문제를 해결하기 위한 간단한 회로를 구성하고 제작 및 평가한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 75, "hasExp": true, "explanation": "이 성취기준은 제어 및 자동화를 위해서는 전기⋅전자 부품을 이용한 회로 구성이 필수적인 요소이므로 주어진 문제를 해결할 수 있는 반도체를 포함한 전기⋅전자 부품들을 선택하고 이들의 회로 구성을 통해 액추에이터를 제어할 수 있는 학습이 되도록 하는 데 초점을 둔다."}, {"id": 725, "code": "[9기가04-05]", "text": "정보통신과 인공지능 기술의 활용 사례를 탐구하고 , 정보통신과 인공지능 기술이 우리 삶에 미치는 영향을 다양한 관점에서 평가한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 73, "hasExp": true, "explanation": "이 성취기준은 현대 사회에서 정보통신 기술이 다른 기술 영역과 융합하여 기술적 문제 해결 능력을 기를 기회를 제공하기 때문에 설정한 것이다 . 또한, 인공지능 기술 발달에 따른 사회 문화적 영향을 이해하고 , 이와 관련된 윤리적인 이슈를 다양한 관점에 서 바라볼 수 있도록 하는 데 초점을 둔다."}, {"id": 726, "code": "[9기가04-06]", "text": "정보통신과 인공지능 기술 관련 문제를 이해하고 해결 방안을 탐색, 실현, 평가함 으로써 긍정적인 문제 해결 태도를 갖는다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "태도", "textLen": 69, "hasExp": true, "explanation": "이 성취기준은 빅데이터 , 사물인터넷 , 인공지능 기술을 비롯한 정보통신 관련 프로젝트 활동을 기반으로 관련 분야의 문제를 탐색하고 이를 해결할 수 있는 최적의 방안을 도출하며 , 제품을 제작 및 평가, 피드백 하는 과정을 통해 정보통신과 인공지능 기술을 활용하는 역량을 키우는 데 초점을 둔다."}, {"id": 727, "code": "[9기가04-07]", "text": "기계의 구성 요소 및 동력 전달 장치의 종류와 특징을 이해하고 , 작동 원리에 맞는 기계요소를 선택하여 평가한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 64, "hasExp": true, "explanation": "이 성취기준은 기계요소와 동력 전달 장치가 다양한 영역의 기술에 기초가 되므로 기계요소와 동력 전달장치의 종류와 특징을 이해하도록 설정하였다 . 특히 다양한 체험활동을 통해 기계요소 및 동력 전달 장치의 종류와 특징을 이해하고 , 자동화 및 로봇 등에 활용되는 기계요소와 동력 전달 장치를 바르게 선택하여 활용할 수 있는 역량을 신 장할 수 있는 학습이 이루어지도록 한다."}, {"id": 728, "code": "[9기가04-08]", "text": "다양한 기계요소와 동력 전달 방법을 활용하여 주어진 문제를 해결할 수 있는 운동 물체를 안전하게 제작하고 평가한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 65, "hasExp": false}, {"id": 729, "code": "[9기가04-09]", "text": "로봇에 활용되고 있는 제어 및 자동화 기술 등을 탐구하여 간단한 로봇을 제작하고 평가함으로써 창조에 대한 자신감을 갖는다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "태도", "textLen": 69, "hasExp": true, "explanation": "이 성취기준은 우리 생활 주변에는 다양한 형태의 로봇이 있으며 , 로봇은 인간의 삶을 보다 편리하게 영위할 수 있도록 도와주므로 학습자가 기술적 체험을 통해 로봇에 대한 이해가 필요하기 때문에 설정하였다 . 다양한 전기⋅전자 부품, 기계요소와 동력전달 장치 등을 활용하여 제한된 조건을 해결할 수 있는 간단한 로봇(자동화 장치)을 설계, 제작, 평가할 수 있는 문제 해결 기반 프로젝트 학습이 이루어지도록 한다."}, {"id": 730, "code": "[9기가04-10]", "text": "인간의 건강과 생명 연장을 위해 의료 분야에서 활용되는 생명기술 사례를 조사하고, 생명기술이 개인과 사회에 미친 영향을 평가한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 73, "hasExp": true, "explanation": "이 성취기준은 생명기술이 인간의 건강과 생명 연장을 위해 의공학의 발전 과 신약 개발에 힘써왔다는 것에 대한 이해를 바탕으로 생명기술과 생명 윤리의 중요성 을 인식할 수 있도록 설정한 것이다 . 여기서는 생명기술의 발달과 생명기술 사례를 다양 한 관점에서 탐구하며 그 영향에 대한 평가가 이루어질 수 있도록 한다."}, {"id": 731, "code": "[9기가04-11]", "text": "생명기술을 이해하며 , 이와 관련된 문제의 해결 방안을 탐색, 실현, 평가하고 , 생명 존 중 및 윤리적 태도를 갖는다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "태도", "textLen": 68, "hasExp": false}, {"id": 732, "code": "[9기가04-12]", "text": "기술적 문제에 대한 도전적 태도로 다양한 분야에 활용되고 있는 융합 기술의 사례를 탐구하고 미래의 기술 변화를 전망한다 .", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "행위", "textLen": 68, "hasExp": false}, {"id": 733, "code": "[9기가04-13]", "text": "긍정적이고 공감하는 문제 해결 태도를 바탕으로 지속가능한 발전과 혁신을 위해 융합 기술 문제를 해결하고 과정과 결과를 평가한다 . 공통 교육과정 – 실과(기술⋅가정) - 29", "subject": "실과_기술가정", "gradeGroup": "중1~3", "area": "지속가능한 기술과 융합", "verb": "기타", "textLen": 97, "hasExp": true, "explanation": "이 성취기준은 우리 생활에 실제 이용되고 있는 기술 대부분은 다양한 지 식이 융합되어 이용되며 , 기술의 발전이 가속화됨에 따라 기술의 융합도 더욱 가속화되고 실과(기술⋅가정)/정보과 교육과정 30있음을 이해하고 , 융합적 사고와 사용자 중심의 공감 및 긍정적 문제 해결 태도를 바탕으 로 융합 프로젝트를 수행하도록 한다."}, {"id": 734, "code": "[9정01-01]", "text": "컴퓨팅 시스템의 구성요소와 동작 원리를 이해하고 , 운영 체제의 기능을 분석한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "컴퓨팅과 디지털 세계", "verb": "행위", "textLen": 46, "hasExp": true, "explanation": "컴퓨팅 시스템은 컴퓨터라는 특정한 기기에서 더욱 큰 범위의 시스템으로 확 장되었음을 인식하고 , 현실 세계에서 볼 수 있는 다양한 컴퓨팅 시스템이 문제를 해결하는 방식을 설명할 수 있어야 한다. 컴퓨팅 시스템이 올바르게 동작하기 위해 운영 체제라는 특수한 형태의 소프트웨어가 필요함을 이해하고 , 운영 체제가 컴퓨팅 시스템을 효율적으 로 활용하기 위해 수행하는 작업을 설명할 수 있어야 한다."}, {"id": 735, "code": "[9정01-02]", "text": "피지컬 컴퓨팅의 개념을 이해하고 , 생활 속에서 적용된 사례 조사를 통해 컴퓨팅 시스템의 필요성과 가치를 판단한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "컴퓨팅과 디지털 세계", "verb": "행위", "textLen": 65, "hasExp": true, "explanation": "다양한 구성요소가 컴퓨팅 시스템에서 고유한 역할을 담당하고 있음을 이해 하고, 목적에 맞는 물리적인 장치와 소프트웨어를 결합하여 피지컬 컴퓨팅 시스템을 구현 하는 과정을 통해 사회의 다양한 영역에서 피지컬 컴퓨팅 시스템이 유용하게 사용될 수 있음을 판단할 수 있어야 한다. 실과(기술⋅가정)/정보과 교육과정 152"}, {"id": 736, "code": "[9정01-03]", "text": "문제 해결 목적에 맞는 피지컬 컴퓨팅 구성요소를 선택하여 시스템을 구상한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "컴퓨팅과 디지털 세계", "verb": "행위", "textLen": 43, "hasExp": false}, {"id": 737, "code": "[9정02-01]", "text": "실생활의 데이터가 디지털 형태로 변환되어 활용되는 긍정적 가치를 탐색하고 , 다양한 데이터를 디지털 형태로 표현한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "알고리즘과 프로그래밍", "verb": "행위", "textLen": 66, "hasExp": true, "explanation": "디지털 형태의 데이터가 갖는 특징과 장점을 탐색하고 , 문자, 이미지 , 소리, 동영상 등의 데이터를 컴퓨팅 시스템에서 표현하기 위해 사용하는 기법을 활용하여 실제로 데이터를 디지털 형태로 표현할 수 있어야 한다."}, {"id": 738, "code": "[9정02-02]", "text": "문제 해결에 적합한 데이터를 수집하고 , 목적에 맞게 구분하여 관리한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "알고리즘과 프로그래밍", "verb": "행위", "textLen": 41, "hasExp": true, "explanation": "여러 가지 문제 상황을 해결하는 데 활용 가능한 데이터를 다양한 방식으로 수집 하고 분류하여 활용도를 높일 수 있어야 한다. 데이터의 종류, 데이터의 의미, 공통점 등 데이 터가 가지고 있는 의미나 형식에 따라 데이터를 구분하여 저장하고 활용할 수 있어야 한다. 공통 교육과정 – 정보 - 153"}, {"id": 739, "code": "[9정02-03]", "text": "실생활의 데이터를 표, 다이어그램 등 다양한 형태로 구조화한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "알고리즘과 프로그래밍", "verb": "행위", "textLen": 36, "hasExp": false}, {"id": 740, "code": "[9정02-04]", "text": "사례를 중심으로 데이터 간의 관계를 파악하고 , 데이터에 기반하여 의미를 해석한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "알고리즘과 프로그래밍", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "수집, 관리하는 데이터를 분석하기 용이한 형태로 나타내고 , 이를 소프트웨 어나 프로그래밍으로 분석하여 얻은 결과의 가치를 인식하고 , 데이터를 기반으로 자신의 주장을 논리적으로 설명할 수 있어야 한다."}, {"id": 741, "code": "[9정02-05]", "text": "여러 학문 분야의 사례를 중심으로 데이터를 수집⋅분석하여 융합적으로 문제를 해결한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "알고리즘과 프로그래밍", "verb": "행위", "textLen": 48, "hasExp": false}, {"id": 742, "code": "[9정03-01]", "text": "문제의 상태를 정의하고 수행 가능한 형태로 구조화한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 31, "hasExp": false}, {"id": 743, "code": "[9정03-02]", "text": "문제 해결을 위한 추상화의 중요성을 이해하고 , 핵심요소를 중심으로 알고리즘을 표현한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 50, "hasExp": false}, {"id": 744, "code": "[9정03-03]", "text": "알고리즘의 중요성을 이해하고 , 문제를 해결하는 다양한 알고리즘을 비교⋅분석한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 46, "hasExp": true, "explanation": "문제를 해결하는 알고리즘은 여러 가지 방식으로 나타날 수 있으나 정보 과 목에서 추구하는 목표는 문제를 효과적이고 효율적으로 해결하는 알고리즘임을 인식하고 , 하나의 문제를 해결하는 여러 알고리즘에 어떠한 장단점이 존재하는지를 비교⋅분석하여 논리적으로 설명할 수 있어야 한다. 실과(기술⋅가정)/정보과 교육과정 154"}, {"id": 745, "code": "[9정03-04]", "text": "사례를 중심으로 문제 해결에 적합한 전략을 선택하여 알고리즘을 설계한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 41, "hasExp": true, "explanation": "문제를 해결하기 위해 정보 분야에서 활용하는 문제 해결 전략을 이해하고 , 문제 해결 과정에 적절한 전략을 활용하여 문제를 해결할 수 있어야 한다."}, {"id": 746, "code": "[9정03-05]", "text": "데이터를 순차적으로 저장할 수 있는 구조를 활용하여 문제 해결 프로그램을 작성한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 47, "hasExp": true, "explanation": "입력된 데이터를 처리하여 결과 데이터를 도출하는 형태로 프로그램이 제작 된다는 개념을 이해하고 , 배열이나 리스트 등 데이터를 순차적으로 저장할 수 있는 구조를 활용하여 많은 양의 데이터를 효과적으로 처리할 수 있어야 한다."}, {"id": 747, "code": "[9정03-06]", "text": "논리 연산과 중첩 제어 구조를 활용하여 문제를 해결하는 프로그램을 작성한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 43, "hasExp": false}, {"id": 748, "code": "[9정03-07]", "text": "프로그램 작성에서 함수를 활용하고 , 프로그램 수행 결과를 디버거로 분석하여 오류를 수정한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 53, "hasExp": false}, {"id": 749, "code": "[9정03-08]", "text": "실생활의 문제를 탐색하여 발견하고 , 프로그래밍을 통해 해결한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 37, "hasExp": false}, {"id": 750, "code": "[9정03-09]", "text": "다양한 학문 분야의 문제 해결을 위해 협력하여 소프트웨어를 개발한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "데이터와 인공지능", "verb": "행위", "textLen": 39, "hasExp": false}, {"id": 751, "code": "[9정04-01]", "text": "인공지능의 개념과 특성을 설명하고 인공지능 소프트웨어를 구별한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "디지털 사회와 윤리", "verb": "행위", "textLen": 37, "hasExp": true, "explanation": "인공지능의 기초적인 개념을 이해하고 모델, 학습, 데이터 등 인공지능 시스템 이 구성되는 원리와 문제를 해결하는 과정에 대해 설명할 수 있어야 한다. 이러한 이해를 기반 공통 교육과정 – 정보 - 155으로 소프트웨어가 문제를 해결할 때 인공지능 시스템을 사용하는 부분을 구체적인 방식 으로 설명할 수 있어야 한다."}, {"id": 752, "code": "[9정04-02]", "text": "인공지능 학습에서 데이터의 중요성을 이해하고 , 학습에 필요한 데이터를 수집하여 분류한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "디지털 사회와 윤리", "verb": "행위", "textLen": 51, "hasExp": false}, {"id": 753, "code": "[9정04-03]", "text": "다양한 데이터를 활용하여 인공지능 시스템을 구성하고 적용한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "디지털 사회와 윤리", "verb": "행위", "textLen": 35, "hasExp": true, "explanation": "이미지 , 소리, 글자 등의 데이터를 활용하여 인공지능 시스템을 학습시키고 학습한 시스템을 활용하여 문제를 해결하는 과정을 수행할 수 있어야 한다."}, {"id": 754, "code": "[9정04-04]", "text": "인공지능 시스템으로 해결 가능한 문제를 발견하고 , 문제 해결에 적합한 인공지능 시스템을 적용한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "디지털 사회와 윤리", "verb": "행위", "textLen": 56, "hasExp": false}, {"id": 755, "code": "[9정04-05]", "text": "인공지능 학습에 필요한 데이터의 수집과 활용에서 발생하는 윤리적인 문제의 해결 방안을 구상한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "디지털 사회와 윤리", "verb": "행위", "textLen": 54, "hasExp": true, "explanation": "인공지능 학습에 필요한 데이터의 수집과 활용에서 나타날 수 있는 여러 가지 현실적인 문제들에 대해 법적, 사회적 , 윤리적으로 타당성을 가지는 해결 방안을 제시할 수 있어야 한다. 하나의 문제를 바라보는 여러 측면에 대해 고려하고 각각의 해결 방안이 가지는 장단점을 정리한 후 결론을 도출하는 과정을 경험하면서 인공지능의 사회적 역할과 가치를 판단할 수 있어야 한다."}, {"id": 756, "code": "[9정05-01]", "text": "디지털 사회의 특성을 탐구하고 , 사회 변화에 따른 직업의 변화를 탐구한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "디지털 문화", "verb": "행위", "textLen": 43, "hasExp": false}, {"id": 757, "code": "[9정05-02]", "text": "디지털 사회의 구성원으로서 편리하고 안전한 생활을 위한 규칙에 대해 민주적으로 논의 하고 실천 방안을 수립한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "디지털 문화", "verb": "행위", "textLen": 63, "hasExp": true, "explanation": "디지털 사회를 안전하고 편리하게 살아가는 데 필요한 정보 윤리, 사이버 폭력 및 범죄 예방에 대한 기본적인 소양을 갖추고 스마트폰 중독, 인터넷 중독, 게임 과몰입 등의 구체적인 사례를 분석할 수 있어야 한다. 분석 내용을 기반으로 개인과 사회가 각각 수행해야 하는 실천 방안을 도출하여 자신의 삶에 적용하려는 태도를 갖출 수 있어야 한다. 실과(기술⋅가정)/정보과 교육과정 156"}, {"id": 758, "code": "[9정05-03]", "text": "사례를 중심으로 디지털 공간에서 함께 살아가기 위해 개인 정보 및 권리와 저작권을 보호 하는 실천 방법을 탐구한다 .", "subject": "정보", "gradeGroup": "중1~3", "area": "디지털 문화", "verb": "행위", "textLen": 65, "hasExp": false}, {"id": 759, "code": "[4영01-01]", "text": "알파벳과 쉽고 간단한 단어의 소리를 듣고 식별한다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "행위", "textLen": 29, "hasExp": false}, {"id": 760, "code": "[4영01-02]", "text": "알파벳 대소문자를 식별하여 읽는다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "기타", "textLen": 20, "hasExp": false}, {"id": 761, "code": "[4영01-03]", "text": "쉽고 간단한 단어 , 어구, 문장을 듣고 강세 , 리듬, 억양을 식별한다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "행위", "textLen": 42, "hasExp": false}, {"id": 762, "code": "[4영01-04]", "text": "소리와 철자의 관계를 이해하며 쉽고 간단한 단어 , 어구, 문장을 소리 내어 읽는다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "기타", "textLen": 48, "hasExp": true, "explanation": "이 성취기준은 단어, 어구, 문장을 개별 소리와 철자 관계에 주목하며 소리 내 어 읽음으로써 독자적인 문자 해독의 기초를 형성하는 데 초점이 있다. 초기 학습 단계에서 는 소리와 철자 관계가 규칙적이면서 친숙한 단어를 읽고, 나아가 두음이나 각운이 같은 단어를 포함한 어구나 문장, 의미를 알고 있는 어구나 문장을 반복하여 읽으며 소리와 철자 관계를 이해하는 것을 의미한다."}, {"id": 763, "code": "[4영01-05]", "text": "쉽고 간단한 단어 , 어구, 문장의 의미를 이해한다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "행위", "textLen": 30, "hasExp": false}, {"id": 764, "code": "[4영01-06]", "text": "자기 주변 주제에 관한 담화의 주요 정보를 파악한다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "행위", "textLen": 30, "hasExp": true, "explanation": "이 성취기준은 말이나 대화를 듣고 명시적이고 구체적으로 언급된 정보를 파악 하는 사실적 이해의 수준을 말하며, 담화의 상황과 내용을 이해하는 데 가장 핵심이 되는 한두 가지의 정보를 파악하는 것을 의미한다."}, {"id": 765, "code": "[4영01-07]", "text": "적절한 전략을 활용하여 담화나 문장을 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "기타", "textLen": 30, "hasExp": true, "explanation": "이 성취기준은 영어 듣기와 읽기 전략에 관한 것으로 실물, 그림, 동작 등의 시 각 정보를 활용하여 담화의 상황이나 내용, 문장의 의미를 파악하는 것을 의미한다."}, {"id": 766, "code": "[4영01-08]", "text": "다양한 매체로 표현된 담화나 문장을 흥미를 가지고 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "기타", "textLen": 37, "hasExp": false}, {"id": 767, "code": "[4영01-09]", "text": "시, 노래, 이야기를 공감하며 듣는다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "기타", "textLen": 22, "hasExp": true, "explanation": "이 성취기준은 시, 노래, 이야기 등 문학이나 예술적 감성을 불러일으키는 듣기 자료를 통해 기쁨, 슬픔 등의 감정을 느끼고 공감하는 것을 의미한다."}, {"id": 768, "code": "[4영01-10]", "text": "자기 주변 주제나 문화에 관한 담화나 문장을 존중의 태도로 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "듣기", "verb": "기타", "textLen": 42, "hasExp": false}, {"id": 769, "code": "[4영02-01]", "text": "쉽고 간단한 단어 , 어구, 문장을 강세 , 리듬, 억양에 맞게 따라 말한다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "행위", "textLen": 44, "hasExp": false}, {"id": 770, "code": "[4영02-02]", "text": "알파벳 대소문자를 구별하여 쓴다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "기타", "textLen": 19, "hasExp": false}, {"id": 771, "code": "[4영02-03]", "text": "소리와 철자의 관계를 바탕으로 쉽고 간단한 단어를 쓴다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "기타", "textLen": 32, "hasExp": true, "explanation": "이 성취기준은 단어를 쓰는 단계에서 학습자가 기계적으로 철자를 외워서 쓰는 것이 아니라 단어의 개별 소리에 대응하는 철자를 생각해 보며 쓰도록 하는 것을 의미한다."}, {"id": 772, "code": "[4영02-04]", "text": "실물, 그림, 동작 등을 보고 쉽고 간단한 문장으로 말하거나 단어나 어구를 쓴다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "기타", "textLen": 46, "hasExp": false}, {"id": 773, "code": "[4영02-05]", "text": "자신, 주변 사람이나 사물의 소개나 묘사를 쉽고 간단한 문장으로 말하거나 보고 쓴다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "기타", "textLen": 48, "hasExp": true, "explanation": "이 성취기준은 간단한 인사말과 함께 자신과 가족, 친구 등의 이름이나 외모, 주변의 물건이나 동물 등의 특징을 쉬운 언어 형식의 한두 문장으로 말하거나 제시된 문장을 그대로 보고 쓰는 것을 의미한다."}, {"id": 774, "code": "[4영02-06]", "text": "행동 지시를 쉽고 간단한 문장으로 말하거나 보고 쓴다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "기타", "textLen": 31, "hasExp": false}, {"id": 775, "code": "[4영02-07]", "text": "자신의 감정을 쉽고 간단한 문장으로 말하거나 보고 쓴다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "기타", "textLen": 32, "hasExp": false}, {"id": 776, "code": "[4영02-08]", "text": "자기 주변 주제에 관한 담화의 주요 정보를 묻거나 답한다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "행위", "textLen": 33, "hasExp": false}, {"id": 777, "code": "[4영02-09]", "text": "적절한 매체나 전략을 활용하여 창의적으로 의미를 표현한다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "행위", "textLen": 33, "hasExp": true, "explanation": "이 성취기준은 의사소통 과정에서 사진, 그림, 디지털 매체 등을 활용하여 다양한 방식으로 의미를 전달하거나 교환하는 것을 말한다. 이는 표정, 몸짓, 동작 등의 비언어적 수단을 수반하여 말하는 것과 함께 그림 글자나 단어 쓰기, 고안 철자(invented spelling) 쓰기, 철자 점검하며 다시 쓰기 등의 전략을 적절하게 사용하는 것을 의미한다."}, {"id": 778, "code": "[4영02-10]", "text": "의사소통 활동에 흥미와 자신감을 가지고 대화 예절을 지키며 참여한다 .", "subject": "영어", "gradeGroup": "초3~4", "area": "말하기", "verb": "행위", "textLen": 39, "hasExp": true, "explanation": "이 성취기준은 말하기 ⋅쓰기 활동 및 과업을 수행하는 과정에서 학습자가 흥 미와 자신감을 가지고 능동적으로 참여하도록 다양한 학습 경험을 제공하는 데 초점이 있으며, 대화 상대자의 영어 사용 수준이나 문화적 차이를 고려하여 상대방을 배려하고 차례를 공통 교육과정 13지키며 대화에 참여하도록 하는 것을 의미한다."}, {"id": 779, "code": "[6영01-01]", "text": "간단한 단어 , 어구, 문장을 듣고 강세 , 리듬, 억양을 식별한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "행위", "textLen": 39, "hasExp": false}, {"id": 780, "code": "[6영01-02]", "text": "간단한 단어 , 어구, 문장을 강세 , 리듬, 억양에 맞게 소리 내어 읽는다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "기타", "textLen": 44, "hasExp": false}, {"id": 781, "code": "[6영01-03]", "text": "간단한 단어 , 어구, 문장의 의미를 이해한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "행위", "textLen": 27, "hasExp": false}, {"id": 782, "code": "[6영01-04]", "text": "일상생활 주제에 관한 담화나 글의 세부 정보를 파악한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "행위", "textLen": 32, "hasExp": false}, {"id": 783, "code": "[6영01-05]", "text": "일상생활 주제에 관한 담화나 글의 중심 내용을 파악한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "행위", "textLen": 32, "hasExp": false}, {"id": 784, "code": "[6영01-06]", "text": "일상생활 주제에 관한 담화나 글에서 일이나 사건의 순서를 파악한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "행위", "textLen": 38, "hasExp": true, "explanation": "이 성취기준은 말이나 대화, 글의 흐름을 파악하는 데 초점을 둔 것으로, 주요 한 일이나 사건의 전후 관계 및 시간적 순서를 파악하는 것을 의미한다. 그림이나 만화 등을 이용하여 사건이 일어난 순서에 따라 연결하거나 배열하기, 일이 일어난 순서대로 번호 쓰기 등의 활동을 하는 수준을 말한다."}, {"id": 785, "code": "[6영01-07]", "text": "적절한 전략을 활용하여 일상생활 주제에 관한 담화나 글을 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "기타", "textLen": 41, "hasExp": true, "explanation": "이 성취기준은 듣기나 읽기 전 ⋅중⋅후 과정에서 다양한 단서를 활용하여 담 화나 글의 내용을 예측하기, 특정 정보를 찾아 듣거나 읽기, 내용 확인을 위해 다시 듣거나 읽기 등의 전략을 활용하는 것을 의미한다."}, {"id": 786, "code": "[6영01-08]", "text": "다양한 매체로 표현된 담화나 글을 흥미와 자신감을 가지고 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "기타", "textLen": 41, "hasExp": true, "explanation": "이 성취기준은 일상생활 주제에 관해 다양한 매체로 표현된 학습 자료를 듣거나 읽으면서 영어에 대한 흥미와 자신감을 높이고, 학습자 스스로 자신의 수준에 맞는 다양한 영어 자료를 자기주도적으로 찾아 즐기는 것을 의미한다."}, {"id": 787, "code": "[6영01-09]", "text": "시, 노래, 이야기를 공감하며 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "기타", "textLen": 26, "hasExp": false}, {"id": 788, "code": "[6영01-10]", "text": "일상생활 주제나 문화에 관한 담화나 글을 포용의 태도로 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "듣기", "verb": "기타", "textLen": 40, "hasExp": true, "explanation": "이 성취기준은 공동체 구성원으로서의 가치 ⋅태도와 관련된 것으로, 일상생활 주제나 문화에 관한 담화나 글을 듣거나 읽으면서 다른 사람의 생각과 의견을 존중하고 이해하는 태도를 갖는 것을 의미한다. 이는 우리나라와 다른 문화권의 다양한 의사소통 방식과 생활 양식을 수용하는 것을 포함한다. 영어과 교육과정 16"}, {"id": 789, "code": "[6영02-01]", "text": "간단한 단어 , 어구, 문장을 강세 , 리듬, 억양에 맞게 말한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "행위", "textLen": 38, "hasExp": false}, {"id": 790, "code": "[6영02-02]", "text": "실물, 그림, 동작 등을 보고 간단한 단어 , 어구, 문장으로 말하거나 쓴다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "기타", "textLen": 44, "hasExp": false}, {"id": 791, "code": "[6영02-03]", "text": "알파벳 대소문자와 문장 부호를 문장에서 바르게 사용한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "행위", "textLen": 32, "hasExp": false}, {"id": 792, "code": "[6영02-04]", "text": "주변 사람이나 사물을 간단한 문장으로 소개하거나 묘사한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "행위", "textLen": 33, "hasExp": false}, {"id": 793, "code": "[6영02-05]", "text": "주변 장소나 위치 , 행동 순서나 방법을 간단한 문장으로 설명한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "행위", "textLen": 38, "hasExp": true, "explanation": "이 성취기준은 주변의 장소를 찾아가는 방법이나 위치, 일상생활에서 이루어지 는 활동을 위한 일련의 행동 순서나 방법에 대하여 두세 문장으로 말하거나 쓰는 것을 의미한다. 이때 문장과 문장을 이어 주는 말(and, but 등)이나 순서를 나타내는 말(first, second 등)을 적절하게 활용할 수 있다."}, {"id": 794, "code": "[6영02-06]", "text": "자신의 감정이나 의견 , 경험이나 계획을 간단한 문장으로 표현한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "행위", "textLen": 38, "hasExp": false}, {"id": 795, "code": "[6영02-07]", "text": "일상생활 주제에 관한 담화나 글의 세부 정보를 간단한 문장으로 묻거나 답한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "행위", "textLen": 44, "hasExp": false}, {"id": 796, "code": "[6영02-08]", "text": "예시문을 참고하여 목적에 맞는 간단한 글을 쓴다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "기타", "textLen": 28, "hasExp": true, "explanation": "이 성취기준은 초대, 감사, 축하 등을 목적으로 하는 카드나 이메일, 경험을 담은 일기나 기행문 등 일상생활에서 빈번하게 일어나는 쓰기의 상황과 목적을 고려하여 글을 쓰는 것으로서, 예시문을 참고하여 글의 형식에 맞게 적절한 내용으로 변형하거나 응용하여 쓰는 수준을 말한다."}, {"id": 797, "code": "[6영02-09]", "text": "적절한 매체와 전략을 활용하여 창의적으로 의미를 생성하고 표현한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "행위", "textLen": 38, "hasExp": true, "explanation": "이 성취기준은 구어나 문어로 의사소통하는 과정에서 학습자의 수준과 특성에 알맞은 매체와 전략을 사용하여 창의적으로 의미를 생성하고 표현하는 것을 말한다. 이는 브레인스토밍이나 생각 그물 등을 활용하여 아이디어를 생성하고, 이를 동작이나 그림과 같은 전통적인 매체뿐만 아니라 다양한 앱이나 디지털 매체 등을 활용하여 새로운 방법으로 말하거나 쓰는 것을 의미한다. 또한 의사소통 과정에서 발생하는 어려움을 극복하기 위해 반복하기, 반복 및 확인 요청하기 등의 말하기 전략과 고쳐 쓰거나 다시 쓰기 등의 쓰기 영어과 교육과정 18전략을 활용하는 것을 의미한다."}, {"id": 798, "code": "[6영02-10]", "text": "의사소통 활동에 흥미와 자신감을 가지고 참여하여 협력적으로 수행한다 .", "subject": "영어", "gradeGroup": "초5~6", "area": "말하기", "verb": "행위", "textLen": 39, "hasExp": true, "explanation": "이 성취기준은 온오프라인 공간에서 제공된 다양한 형태의 말하기 ⋅쓰기 과업 이나 활동에 흥미와 자신감을 가지고 능동적으로 참여하는 것을 의미한다. 지속적으로 이루어지는 짝이나 모둠별 말하기 ⋅쓰기 활동을 통해 학습자들이 서로 가르쳐 주거나 배우는 과정에서 긍정적인 피드백을 주고받으며 말하거나 쓰고 싶은 의욕과 자신감을 높이는 것을 말한다."}, {"id": 799, "code": "[9영01-01]", "text": "단어, 어구, 문장을 듣고 연음이나 축약된 소리를 식별한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "행위", "textLen": 34, "hasExp": true, "explanation": "이 성취기준은 자주 사용되는 단어나 어구 또는 다양한 언어 형식의 문장을 듣고 영어의 리듬, 강세, 억양뿐만 아니라 연음이나 축약된 소리를 식별하여 자연스럽게 영어로 말하는 것을 듣고 이해할 수 있는 것을 의미한다."}, {"id": 800, "code": "[9영01-02]", "text": "친숙한 주제에 관한 담화나 글에서 세부 정보를 파악한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "행위", "textLen": 32, "hasExp": true, "explanation": "이 성취기준은 학습자가 개인 생활, 학교생활, 사회생활 등에서 흔히 접할 수 있는 친숙한 주제에 관하여, 말이나 대화를 듣거나 글을 읽고 그 속에서 숫자, 위치, 사건 등의 세부 정보를 파악할 수 있으며, 그림, 사진, 도표 등의 시각적 정보를 포함한 말, 대화, 글에서 세부 정보를 파악할 수 있는 것을 의미한다."}, {"id": 801, "code": "[9영01-03]", "text": "친숙한 주제에 관한 담화나 글의 중심 내용을 파악한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "행위", "textLen": 31, "hasExp": true, "explanation": "이 성취기준은 학습자가 개인 생활, 학교생활, 사회생활 등에서 흔히 접할 수 있는 친숙한 주제에 관하여, 말이나 대화를 듣거나 글을 읽고, 줄거리, 주제, 요지 등의 중심 내용을 파악할 수 있는 것을 의미한다."}, {"id": 802, "code": "[9영01-04]", "text": "친숙한 주제에 관한 담화나 글에서 일이나 사건의 논리적 관계를 파악한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "행위", "textLen": 41, "hasExp": true, "explanation": "이 성취기준은 학습자가 개인 생활, 학교생활, 사회생활 등에서 흔히 접할 수 있는 친숙한 주제에 관하여, 말이나 대화를 듣거나 글을 읽고 일이나 사건의 순서, 전후 관계, 원인과 결과 등의 논리적 관계를 파악할 수 있는 것을 의미한다."}, {"id": 803, "code": "[9영01-05]", "text": "친숙한 주제에 관한 담화나 글에서 인물의 기분이나 감정을 추론한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "행위", "textLen": 38, "hasExp": false}, {"id": 804, "code": "[9영01-06]", "text": "친숙한 주제에 관한 담화나 글에서 화자나 필자의 의도나 목적을 추론한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "행위", "textLen": 41, "hasExp": false}, {"id": 805, "code": "[9영01-07]", "text": "단어, 어구, 문장의 함축적 의미를 추론한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "행위", "textLen": 26, "hasExp": false}, {"id": 806, "code": "[9영01-08]", "text": "적절한 전략을 활용하여 다양한 매체로 표현된 담화나 글을 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "기타", "textLen": 41, "hasExp": true, "explanation": "이 성취기준은 학습자가 방송, 영상, 인터넷 등 다양한 매체로 표현된 친숙한 주제에 관한 말, 대화 또는 글을 듣거나 읽을 때, ‘다음에 나올 내용을 추측하며 듣거나 읽기’와 ‘훑어보기’와 같은 다양한 전략을 적절하게 활용할 수 있는 것을 의미한다. 공통 교육과정 21"}, {"id": 807, "code": "[9영01-09]", "text": "다양한 관점을 존중하는 태도로 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "기타", "textLen": 26, "hasExp": false}, {"id": 808, "code": "[9영01-10]", "text": "자신의 관심사에 관한 다양한 담화나 글을 선택하여 적극적으로 듣거나 읽는다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "듣기", "verb": "기타", "textLen": 43, "hasExp": true, "explanation": "성취기준의 경우 지필평가보다는 수행평가, 학생의 자기 평가, 동료 평가 등의 방법을 활용하여 평가하며, 각 성취기준에 어느 정도 도달하였는지를 독립적으로 평가하기보다는 다른 성취기준과 연계하여 평가한다. 영어과 교육과정 22(2) 표현"}, {"id": 809, "code": "[9영02-01]", "text": "연음이나 축약된 소리를 활용하여 단어 , 어구, 문장을 말한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "행위", "textLen": 36, "hasExp": true, "explanation": "이 성취기준은 학습자가 영어의 리듬, 강세, 억양뿐만 아니라 연음이나 축약된 소리를 적절히 활용하여 실제 상황에서 단어, 어구, 문장을 이해할 수 있는 발음으로 자연스럽게 말할 수 있는 것을 의미한다."}, {"id": 810, "code": "[9영02-02]", "text": "대상이나 인물의 감정을 묘사한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "행위", "textLen": 19, "hasExp": true, "explanation": "이 성취기준은 학습자가 개인 생활, 학교생활, 사회생활 등에서 흔히 접할 수 있는 친숙한 주제에 관해, 자신이나 상대방이 느끼는 기분이나 감정을 묘사하는 말이나 대화를 하거나 문장 또는 문단으로 쓸 수 있는 것을 의미한다. 또한 주변 사람이나 사물 등에 대해 적절하게 묘사하는 말이나 대화를 하거나 문장 또는 문단으로 쓸 수 있는 것을 의미한다."}, {"id": 811, "code": "[9영02-03]", "text": "친숙한 주제에 관해 사실적 정보를 설명한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "행위", "textLen": 25, "hasExp": true, "explanation": "이 성취기준은 학습자가 개인 생활, 학교생활, 사회생활 등에서 흔히 접할 수 있는 친숙한 주제에 관해 사람, 사물, 위치나 장소, 방법이나 절차 등을 적절하게 설명하는 말이나 대화를 하거나 문장이나 문단으로 쓸 수 있는 것을 의미한다. 또한 그림, 사진, 도표 등 시각적 정보와 관련하여 특정 정보를 설명하는 말이나 대화를 하거나 문장이나 문단으로 쓸 수 있는 것을 의미한다."}, {"id": 812, "code": "[9영02-04]", "text": "친숙한 주제에 관해 경험이나 계획을 설명한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "행위", "textLen": 26, "hasExp": false}, {"id": 813, "code": "[9영02-05]", "text": "친숙한 주제에 관해 일이나 사건의 논리적 관계를 설명한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "행위", "textLen": 33, "hasExp": true, "explanation": "이 성취기준은 학습자가 개인 생활, 학교생활, 사회생활 등에서 흔히 접할 수 있는 친숙한 주제에 관한 일이나 사건의 상황에 대해 분석적으로 생각해 보고 이를 통해 일이나 사건의 순서, 전후 관계, 원인과 결과 등의 논리적 관계에 대해 말이나 대화를 하거나 문장이나 문단으로 쓸 수 있는 것을 의미한다. 공통 교육과정 23"}, {"id": 814, "code": "[9영02-06]", "text": "친숙한 주제에 관해 자신의 의견을 주장한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "행위", "textLen": 25, "hasExp": true, "explanation": "이 성취기준은 학습자가 개인 생활, 학교생활, 사회생활 등에서 흔히 접할 수 있는 친숙한 주제에 관해 자신의 의견을 주장하는 말이나 대화를 하거나 문장이나 문단으로 쓸 수 있는 것을 의미한다. 이는 또한 학습자의 주장이 설득력을 갖추기 위해 의견을 뒷받침할 만한 근거를 함께 제시할 수 있도록 하는 것이다."}, {"id": 815, "code": "[9영02-07]", "text": "친숙한 주제에 관해 듣거나 읽고 내용을 요약한다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "행위", "textLen": 28, "hasExp": false}, {"id": 816, "code": "[9영02-08]", "text": "간단한 일기 , 편지, 이메일 등의 글을 쓴다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "기타", "textLen": 27, "hasExp": false}, {"id": 817, "code": "[9영02-09]", "text": "적절한 매체를 활용하여 정보 윤리를 준수하며 말하거나 쓴다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "기타", "textLen": 34, "hasExp": true, "explanation": "이 성취기준은 학습자가 인용한 내용이나 자료의 출처를 언급하는 등의 정보 윤리를 준수하며 이미지, 영상, 인터넷 등 다양한 매체를 적절하게 활용하여 자신의 생각을 말하거나 문장이나 문단으로 쓸 수 있는 것을 의미한다."}, {"id": 818, "code": "[9영02-10]", "text": "적절한 전략을 활용하여 상황이나 목적에 맞게 말하거나 쓴다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "기타", "textLen": 34, "hasExp": true, "explanation": "이 성취기준은 학습자가 실생활의 여러 말하기나 글쓰기 상황에서 ‘바꿔 말하기’ 또는 ‘고쳐 쓰기’와 같은 적절하고 다양한 전략을 활용하여 상황이나 목적에 맞게 효과적으로 말이나 대화를 하거나 문장이나 문단으로 쓸 수 있는 것을 의미한다."}, {"id": 819, "code": "[9영02-11]", "text": "상대방을 배려하는 태도로 말하거나 쓴다 .", "subject": "영어", "gradeGroup": "중1~3", "area": "말하기", "verb": "기타", "textLen": 23, "hasExp": true, "explanation": "성취기준의 경우 지필평가뿐만 아니라, 수행평가, 자기 평가, 동료 평가 등의 방법을 활용하여 평가할 수 있으며, 각 성취기준에 대한 도달 정도를 독립적으로 평가하기보다는 다른 성취기준과 연계하여 평가한다. 영어과 교육과정 24 3. 교수 ⋅학습 및 평가"}, {"id": 820, "code": "[4미01-01]", "text": "자연물과 인공물을 탐색하는 데 다양한 감각을 활용할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "체험", "verb": "능력", "textLen": 35, "hasExp": false}, {"id": 821, "code": "[4미01-02]", "text": "주변 대상을 체험하며 떠오른 느낌과 생각을 다양한 방법으로 나타낼 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "체험", "verb": "기타", "textLen": 43, "hasExp": false}, {"id": 822, "code": "[4미01-03]", "text": "미적 탐색에 호기심을 갖고 참여하며 자신의 감각으로 대상의 특징을 이해할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "체험", "verb": "능력", "textLen": 47, "hasExp": true, "explanation": "성취기준은 객관적 지식을 적용하거나 고정 관념에 따라 대상을 이해하는 방 식에서 벗어나 몸의 다양한 감각으로 직접 대상을 탐색하는 데 호기심을 갖고 참여하며 자신의 감각을 바탕으로 대상의 특징을 이해하는 데 중점을 둔다 . 같은 대상이라도 지각 하고 반응하는 방식은 학생마다 다를 수 있다 . 대상을 지각하며 자연스럽게 떠올린 자신 의 감정 , 느낌, 생각 등을 나타내고 친구들의 다양한 반응을 접하며 자신만의 고유한 감 각을 통해 대상이 지닌 다채로운 특징을 이해한다 ."}, {"id": 823, "code": "[4미01-04]", "text": "생활 속에서 활용되는 미술에 관심을 가지고 미술의 특징과 역할을 발견할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "체험", "verb": "능력", "textLen": 46, "hasExp": false}, {"id": 824, "code": "[4미02-01]", "text": "관찰과 상상으로 아이디어를 떠올려 표현 주제를 구체화할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "표현", "verb": "능력", "textLen": 37, "hasExp": false}, {"id": 825, "code": "[4미02-02]", "text": "기본적인 표현 재료와 용구의 특성을 이해하고 사용 방법을 익힐 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "표현", "verb": "기타", "textLen": 41, "hasExp": true, "explanation": "성취기준은 기본적인 표현 재료의 물성을 경험하고 표현 용구의 사용법을 충 분히 익히는 활동에 중점을 둔다 . 표현 재료와 용구는 단순히 표현 수단을 넘어 그 자체 로서 학생들에게 새로운 느낌과 생각을 가지게 한다 . 초등학교 3~4학년 수준에서 다룰 수 있는 기본적인 표현 재료에는 종이류 (도화지 , 색종이 , 한지 등 ), 드로잉 재료 (연필, 펜 등), 채색 재료 (크레파스 , 파스텔 , 수채화물감 , 아크릴물감 , 먹 등), 조소 재료 (찰흙, 종이 죽, 공예용 철사 등 )가 있으며 그 밖에 생활 속에서 익숙하게 다루고 있는 다양한 생활용 품 및 디지털 매체를 활용할 수 있다 ."}, {"id": 826, "code": "[4미02-03]", "text": "조형 요소의 특징을 자유롭게 탐색하며 주제 표현에 알맞게 활용할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "표현", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "성취기준은 미술 표현에 기초가 되는 조형 요소의 특징을 탐색하고 표현 주 제와 연결 지어 조형 요소를 활용하는 데 중점을 둔다 . 조형 요소에는 선 , 형과 형태 , 색, 질감, 양감 등이 있다 . 각 조형 요소를 탐색하여 시각적 특징을 발견하고 표현하고자 하는 주제와 어울리는 조형 요소를 찾아 주제 표현에 활용한다 ."}, {"id": 827, "code": "[4미02-04]", "text": "표현 의도를 가지고 작품을 제작하며 자기 작품을 소중히 여길 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "표현", "verb": "기타", "textLen": 40, "hasExp": true, "explanation": "성취기준은 작품 제작을 위한 계획 단계부터 작품을 완성한 후 발표 및 전 시에 이르기까지 학생들의 제작 의도와 작품을 대하는 태도에 중점을 둔다 . 작품 제작에 분명한 의도를 갖는 것은 주도적으로 작품을 제작하는 바탕이 되어 표현 재료와 용구 , 조형 미술과 교육과정 10요소의 특징을 탐색하여 작품에 활용하는 일련의 과정을 이끈다 . 또한, 자신의 의도에 따 라 주도적으로 제작한 작품에는 특별한 의미가 부여되어 작품을 소중히 여기는 태도로 이어질 수 있다 ."}, {"id": 828, "code": "[4미02-05]", "text": "미술과 타 교과를 관련지어 주제를 표현하는데 흥미를 가질 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "표현", "verb": "기타", "textLen": 38, "hasExp": false}, {"id": 829, "code": "[4미03-01]", "text": "미술 작품을 자세히 보고 작품과 미술가에 관해 질문할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "감상", "verb": "능력", "textLen": 36, "hasExp": true, "explanation": "성취기준은 작품에 대한 교사의 질문이나 조사에 의존하는 감상 방식에서 벗 어나 학생들이 작품을 충분히 보고 자신의 느낌과 생각을 바탕으로 질문을 만들어 상호 작용하는 데 중점을 둔다 . 질문하기를 통한 감상은 작품과 나누는 대화의 시작이다 . 작품 정보를 활용한 질문 , 작품의 내용이나 형식에 관한 질문 , 작가의 입장이 되어 던지는 질 문 등 다양한 질문을 통하여 학생들이 감상에 흥미를 느끼고 감상 관점을 기르도록 한다 ."}, {"id": 830, "code": "[4미03-02]", "text": "미술 작품의 특징과 작품에 관한 자신의 느낌과 생각을 설명할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "감상", "verb": "능력", "textLen": 40, "hasExp": false}, {"id": 831, "code": "[4미03-03]", "text": "미술 문화에 관심을 가지고 전시 및 행사에 참여할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "감상", "verb": "능력", "textLen": 34, "hasExp": false}, {"id": 832, "code": "[4미03-04]", "text": "작품 감상에 흥미를 가지고 참여하며 작품에 대한 자신의 감상 관점을 존중할 수 있다 .", "subject": "미술", "gradeGroup": "초3~4", "area": "감상", "verb": "능력", "textLen": 48, "hasExp": false}, {"id": 833, "code": "[6미01-01]", "text": "다양한 감각과 매체를 활용하여 자신과 대상을 탐색할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "체험", "verb": "능력", "textLen": 35, "hasExp": false}, {"id": 834, "code": "[6미01-02]", "text": "자신이나 주변 환경에서 찾은 감각적 특징 , 느낌, 생각 등을 관련지어 나타낼 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "체험", "verb": "기타", "textLen": 50, "hasExp": true, "explanation": "성취기준은 자신이나 대상 , 그리고 시시각각 변화하는 현상 등 주변 환경을 탐색하며 예민하게 찾은 감각적 특징과 체험 과정에서 떠오른 느낌과 생각을 관련지어 보는 경험에 중점을 둔다 . 미술의 특성상 시각적 특징을 우선 다루게 되지만 , 보이지 않 아도 느낄 수 있는 특징이나 느낌과 상상이 반영된 색 , 형, 이미지 , 문구, 소리, 움직임 등을 자유롭게 활용한다 . 이를 통해 감각이 사고에 미치는 영향뿐만 아니라 자신과 환경 사이의 관계를 이해한다 ."}, {"id": 835, "code": "[6미01-03]", "text": "주변 환경에 대한 민감한 태도로 대상과 상호 작용하며 새로운 의미를 발견할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "체험", "verb": "능력", "textLen": 48, "hasExp": true, "explanation": "성취기준은 주변 환경 속 대상과 민감하게 상호 작용하며 경험한 느낌과 생 각을 바탕으로 대상에 이름 붙이기 , 자신을 닮은 대상 찾기 , 대상을 연결하여 이야기 만 들기 등 대상에 의미를 부여하는 활동에 중점을 둔다 . 보는 사람 , 시간과 장소 , 분위기 등에 따라 대상과 다양하게 교감하며 그 과정에서 생성되는 의미를 성찰할 수 있도록 한다 . 이를 통해 예술적 사고를 이끄는 대상의 가치를 이해하고 자신과 환경과의 생태 전환 적 관계를 인식한다 ."}, {"id": 836, "code": "[6미01-04]", "text": "이미지가 나타내는 의미를 비판적으로 이해하고 느낌과 생각을 전달하는 데 활용할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "체험", "verb": "능력", "textLen": 50, "hasExp": false}, {"id": 837, "code": "[6미02-01]", "text": "다양한 방법으로 아이디어를 연결하여 확장된 표현 주제로 발전시킬 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "표현", "verb": "기타", "textLen": 42, "hasExp": false}, {"id": 838, "code": "[6미02-02]", "text": "디지털 매체 등 다양한 표현 재료와 용구를 탐색하여 작품 제작에 활용할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "표현", "verb": "능력", "textLen": 46, "hasExp": true, "explanation": "성취기준은 하나의 표현 주제에도 다양한 표현 방식이 있음을 이해하고 학생 들이 자신의 의도에 따라 표현 재료와 방법을 선택하여 작품을 제작하는 데 중점을 둔다 . 표현 주제에 적합한 표현 재료와 용구의 쓰임을 학생 스스로 탐색하고 습득하여 주제가 잘 드 러 날 수 있 도 록 적 용 하 게 한 다 . 특히, 디지털 매체는 신체적 감각과 지각을 확장하는 표현의 도구로써 디지털 매체의 특징과 사용법을 익혀 작품 제작에 효과적으로 활용하게 한다 . 미술과 교육과정 14"}, {"id": 839, "code": "[6미02-03]", "text": "조형 요소의 어울림을 통해 조형 원리를 이해하고 주제 표현에 연결할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "표현", "verb": "능력", "textLen": 44, "hasExp": false}, {"id": 840, "code": "[6미02-04]", "text": "주제 표현에 의지를 갖고 표현 과정을 돌아보며 작품을 발전시킬 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "표현", "verb": "기타", "textLen": 41, "hasExp": true, "explanation": "성취기준은 계획 단계를 비롯한 작품 완성의 전 과정에서 주제 표현에 의지를 갖고 표현 방법과 절차를 재고하는 성찰의 태도를 기르는 데 중점을 둔다 . 주제 표현의 의지를 갖는 것은 표현 주제를 나타내기 위해 다양한 표현 재료와 용구 , 조형 요소와 원 리를 작품에 활용하는 일련의 과정을 이끈다 . 또한 작품을 주도적으로 돌아보고 보완하며 발전시키는 경험을 통해 학생들은 작품 완성의 기준을 스스로 설정하고 창작에 대한 상위 인지를 활성화한다 ."}, {"id": 841, "code": "[6미02-05]", "text": "미술과 타 교과의 내용과 방법을 융합하는 활동을 자유롭게 시도할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "표현", "verb": "능력", "textLen": 42, "hasExp": false}, {"id": 842, "code": "[6미03-01]", "text": "미술 작품을 작품이 만들어진 시대적 , 지역적 배경 등과 연결하여 이해할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "감상", "verb": "능력", "textLen": 47, "hasExp": false}, {"id": 843, "code": "[6미03-02]", "text": "미술 작품의 내용 (소재, 주제 등 )과 형식 (재료와 용구 , 표현 방법 , 조형 요소와 원리 등 ) 을 분석하여 작품의 특징을 설명할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "감상", "verb": "능력", "textLen": 83, "hasExp": false}, {"id": 844, "code": "[6미03-03]", "text": "공동체의 미술 문화 활동에 관심을 가지고 참여하며 경험을 공유할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "감상", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "성취기준은 교실 수업이라는 시공간을 확장하여 전시 , 지역 축제 , 문화 행사 등 학생들이 살아가는 지역 사회의 미술 문화에 관심을 가지고 적극적으로 참여함으로써 문화를 향유하는 태도를 생활화하는 데 중점을 둔다 . 또한 그 경험을 공유하고 소통함으 로써 새로운 문화를 생성해가는 데까지 관심을 확장한다 ."}, {"id": 845, "code": "[6미03-04]", "text": "다양한 방법을 활용하여 작품을 감상하며 작품에 관한 서로 다른 관점을 존중할 수 있다 .", "subject": "미술", "gradeGroup": "초5~6", "area": "감상", "verb": "능력", "textLen": 49, "hasExp": false}, {"id": 846, "code": "[9미01-01]", "text": "감각을 활용하여 대상과 현상을 탐색하고 자신과 환경에 대한 감수성을 확장할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "체험", "verb": "능력", "textLen": 48, "hasExp": true, "explanation": "성취기준은 다양한 감각을 활용하여 주변의 대상과 현상을 탐색하고 자신과 자신을 둘러싼 환경에 대한 미적 인식을 통해 감수성을 일깨우는 데 중점을 둔다 . 감각을 활용하여 대상과 현상을 탐색하고 상호 작용하여 미적 인식에 이르는 경험을 통해 주변 환경을 포함하여 생태적 , 문화적 , 사회적 환경까지 새롭게 바라보고 의미를 부여하며 앎을 성찰할 수 있다 ."}, {"id": 847, "code": "[9미01-02]", "text": "시각 문화의 의미와 역할을 알고 이미지를 비판적으로 해석할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "체험", "verb": "능력", "textLen": 39, "hasExp": false}, {"id": 848, "code": "[9미01-03]", "text": "다양한 문화를 존중하며 이미지를 활용하여 소통할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "체험", "verb": "능력", "textLen": 33, "hasExp": false}, {"id": 849, "code": "[9미01-04]", "text": "삶과 미술의 관계를 이해하고 다양한 분야와의 연결 방안을 모색할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "체험", "verb": "능력", "textLen": 42, "hasExp": true, "explanation": "성취기준은 삶 속에서 미술이 어떻게 상호 작용하고 있는지 그 중요성을 인 식하는 것으로 출발한다 . 인문, 과학, 공학 등 타 분야와 사회 현상에 이르기까지 폭넓게 연결된 미술의 사례를 찾고 자신의 흥미에 맞는 진로나 직업 및 관심 분야와 관련하여 적용 방안을 탐색하는 데 중점을 둔다 . 미술과 관련된 직업과 진로를 적극적으로 탐색하고 , 자유학기제 진로 탐색 활동 , 진로연계교육 등과 연계할 수 있다 ."}, {"id": 850, "code": "[9미02-01]", "text": "주제를 탐구하고 의도를 반영하여 적합한 표현을 계획할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "표현", "verb": "능력", "textLen": 36, "hasExp": false}, {"id": 851, "code": "[9미02-02]", "text": "주도적이고 도전적인 태도로 다양한 미술 표현을 실험하고 작품에 적용할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "표현", "verb": "능력", "textLen": 45, "hasExp": true, "explanation": "성취기준은 주제를 효과적으로 시각화하는 방법을 찾기 위해 도전하고 실험 하는 태도를 기르는 데 중점을 둔다 . 실패를 두려워하거나 익숙한 표현 방법에 안주하지 않고 작품에 적합한 표현 방법과 매체를 주도적으로 탐색하고 활용할 수 있다 ."}, {"id": 852, "code": "[9미02-03]", "text": "조형 요소와 원리 , 표현 재료와 방법 , 디지털 매체를 포함한 다양한 매체를 활용하여 주제를 효과적으로 표현할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "표현", "verb": "능력", "textLen": 69, "hasExp": false}, {"id": 853, "code": "[9미02-04]", "text": "자신과 타인의 작품을 존중하며 , 다양한 방법으로 공유하고 소통할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "표현", "verb": "능력", "textLen": 43, "hasExp": true, "explanation": "성취기준은 자신의 작품을 소중히 여기고 타인의 작품을 존중하는 태도를 지 니며, 효과적인 방법으로 작품을 공유하고 소통하는 과정을 통해 표현의 가능성을 확장하는 데 중점을 둔다 . 미술 표현 과정과 결과물을 교실 , 복도, 지역 사회 공간 , 온라인 공간까지 확장하여 공유하고 발표하며 토론할 수 있다 ."}, {"id": 854, "code": "[9미02-05]", "text": "미술 표현 과정에서의 경험을 성찰하고 삶의 문제 해결에 활용할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "표현", "verb": "능력", "textLen": 41, "hasExp": true, "explanation": "성취기준은 미술 표현 과정에서 마주하는 크고 작은 질문과 답을 찾아 나가 는 과정이 가지는 가치를 알고 그 경험을 삶의 다양한 문제에 활용하는 데 중점을 둔다 . 표현 주제를 찾고 , 계획하고 , 실험하고 , 제작하고 , 타인과 상호 작용하는 전체 과정에서 경험한 지식 ⋅이해, 과정⋅기능, 가치⋅태도를 삶의 다양한 문제와 연결할 수 있다 ."}, {"id": 855, "code": "[9미03-01]", "text": "미술의 시대적 , 지역적 , 사회적 맥락을 이해하고 설명할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "감상", "verb": "능력", "textLen": 39, "hasExp": false}, {"id": 856, "code": "[9미03-02]", "text": "작품의 내용과 형식을 분석하고 미술 용어와 지식을 활용하여 설명할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "감상", "verb": "능력", "textLen": 43, "hasExp": false}, {"id": 857, "code": "[9미03-03]", "text": "다양한 감상 방법과 관점을 활용하여 작품을 해석할 수 있다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "감상", "verb": "능력", "textLen": 34, "hasExp": false}, {"id": 858, "code": "[9미03-04]", "text": "미술의 다원성에 대한 존중을 바탕으로 미술 감상 경험을 삶과 연결하고 공동체 문화에 기 여 할 수 있 다 .", "subject": "미술", "gradeGroup": "중1~3", "area": "감상", "verb": "기타", "textLen": 60, "hasExp": true, "explanation": "성취기준은 미술의 다원성을 존중하는 태도를 바탕으로 미술 감상 과정과 결 과에서 얻은 지식과 경험을 자신의 삶과 연결하여 통찰을 얻고 자신이 속한 공동체가 더 나은 문화를 만들어 나가도록 하는 데 중점을 둔다 . 미술 작품과 그에 얽힌 다양한 주제에 관해 의견을 나누는 가운데 미술의 가치와 역할을 인식하고 미술을 통해 나와 공동체의 문화를 새롭게 하는 데 기여할 수 있다 ."}];

